-- ----------------------------
-- Table structure for tcm_acupoints
-- ----------------------------
DROP TABLE IF EXISTS `tcm_acupoints`;
CREATE TABLE `tcm_acupoints`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `acupoint_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT ' 穴位名称',
  `meridian_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '所属经络名称',
  `location_description` longblob NULL COMMENT '穴位位置描述',
  `function_description` longblob NULL COMMENT '穴位功能描述',
  `common_usage` longblob NULL COMMENT '常见用途（如治疗病症等）',
  `picture_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '穴位相关图片的 URL',
  `acupuncture_depth` decimal(5, 2) NULL DEFAULT NULL COMMENT '针刺深度（单位：寸等，可根据实际调整）',
  `moxibustion_time` int(11) NULL DEFAULT NULL COMMENT '艾灸时间（分钟）',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '人体穴位表' ROW_FORMAT = Dynamic;

