-- ----------------------------
-- Table structure for tcm_case
-- ----------------------------
DROP TABLE IF EXISTS `tcm_case`;
CREATE TABLE `tcm_case`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `case_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '案例名称',
  `case_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '案例编号',
  `case_remark` longblob NULL COMMENT '案例描述',
