INSERT INTO `prescriptionofdrugs` VALUES (1, '九味羌活丸', NULL, '羌活、防风、苍术、细辛、川芎、白芷、黄芩、甘草、地黄', '疏风解表，散寒除湿', '用于外感风寒挟湿所致的感冒，症见恶寒、发热、无汗、头痛而重、肢体酸痛');
INSERT INTO `prescriptionofdrugs` VALUES (2, '感冒软胶囊', NULL, '麻黄、桂枝、羌活、防风、 荆芥穗、白芷、当归、川芎 、苦杏仁、桔梗、薄荷、石菖蒲、葛根、黄芩', '疏风散寒，解表清热', '用于外感风寒所致的感冒，症见发热头痛、恶寒无汗、鼻塞流涕 、骨节痛、咳嗽、咽痛');
INSERT INTO `prescriptionofdrugs` VALUES (3, '感冒清热颗粒', NULL, '荆芥穗、防风、紫苏叶、白芷、柴胡、薄荷、葛根、芦根、苦地丁、桔梗、苦杏仁', '疏风散寒，解表清热', '用于风寒感冒，头痛发热，恶寒 身痛，鼻流清涕，咳嗽，咽干');
INSERT INTO `prescriptionofdrugs` VALUES (4, '金花清感颗粒', NULL, '金银花、石膏、蜜麻黄、炒 苦杏仁、黄芩、连翘、渐贝 母、知母、牛蒡子、青蒿、薄荷、甘草', '疏风宣肺，清热解毒。', '用于单纯型流行性感冒轻症，中医辨证属风热犯肺证者，症见发热，头痛，全身酸痛，咽痛，咳嗽，恶风或恶寒，鼻塞流涕，舌质红，舌苔薄黄，脉数。在新型冠状病毒肺炎的常规治疗中，可用于轻型、普通型引起的发热、咳嗽、乏力');
INSERT INTO `prescriptionofdrugs` VALUES (5, '连花清瘟胶囊', NULL, '连翘、金银花、炙麻黄、炒苦杏仁、石膏、板蓝根、绵 马贯众、鱼腥草、广藿香、大黄、红景天、薄荷脑、甘草', '清瘟解毒，宣肺泄热。', '用于治疗流行性感冒属热毒袭肺证，症见发热，恶寒，肌肉酸痛，鼻塞流涕，咳嗽，头痛，咽干咽痛，舌偏红，苔黄或黄腻。在新型冠状病毒肺炎的常规治疗中，可用于轻型、普通型引起的 发热、咳嗽、乏力');
INSERT INTO `prescriptionofdrugs` VALUES (6, '羚翅解毒片', NULL, '羚羊角粉、金银花、连翘、 荆芥穗、薄荷、淡豆豉、淡竹叶、牛劳子（炒）、桔梗 、冰片、甘草', '疏风解表，清热解毒', '用于外感温邪或风热所致的感冒，症见恶风发热、四肢疫懒、头痛、鼻塞、咳嗽、咽痛');
INSERT INTO `prescriptionofdrugs` VALUES (7, '羚羊感冒胶囊', NULL, '金银花、连翘、羚羊角、牛蒡子、荆芥、淡豆豉、桔梗 、淡竹叶、薄荷素油、甘草', '清热解表', '用于流行性感冒，症见发热恶风 、头痛头晕、咳嗽、胸闷、咽喉肿痛');
INSERT INTO `prescriptionofdrugs` VALUES (8, '银趔解毒丸', NULL, '金银花、连翘、薄荷、荆芥、淡豆豉、牛蒡子（炒）、桔梗、淡竹叶、甘草', '疏风解表，清热解毒', '用于风热感冒，症见发热头痛、咳嗽口干、咽喉疼痛');
INSERT INTO `prescriptionofdrugs` VALUES (9, '桑菊感冒片', NULL, '桑叶、菊花、薄荷素油、苦 杏仁、桔梗、连翘、芦根、甘草', '疏风淸热，宜肺止咳', '用于风热感冒初起，头痛，咳嗽，口干，咽痛');
INSERT INTO `prescriptionofdrugs` VALUES (10, '桑菊银翘散', NULL, '桑叶、菊花、金银花、连翘、薄荷、荆芥、淡豆豉、牛蒡子、蝉蜕、僵蚕、绿豆、桔梗、苦杏仁、川贝母、淡竹叶', '疏风解表，清热解毒， 宣肺止咳', '用于风热感冒，症见发热恶风，头痛，咳嗽，咽喉肿痛');
INSERT INTO `prescriptionofdrugs` VALUES (11, '双黄连口服液（颗粒）', NULL, '金银花、黄芩、连翘', '疏风解表，清热解毒', '用于外感风热所致的感冒，症见发热、咳嗽、咽痈');
INSERT INTO `prescriptionofdrugs` VALUES (12, '痰热清胶囊', NULL, '金银花、黄芩、连翘、熊胆粉、山羊角。', '清热，化痰，解毒', '用于风温肺热病属风热袭肺证，症见发热，恶风，咳嗽，咯痰， 或咽痛，流涕，口干等');
INSERT INTO `prescriptionofdrugs` VALUES (13, '复方芩兰口服液', NULL, '金银花、黄芩、连翘、板蓝', '辛凉解表，清热解毒', '用于外感风热引起的发热、咳嗽 、咽痛');
INSERT INTO `prescriptionofdrugs` VALUES (14, '柴胡口服液', NULL, '柴胡', '解表退热', '用于外感发热，症见身热面赤、头痛身楚、口干而渴');
INSERT INTO `prescriptionofdrugs` VALUES (15, '柴石退热颗粒', NULL, '柴胡、黄芩、石膏、青蒿、板蓝根、金银花、大黄、蒲公英、知母、连翘', '清热解毒，解表清里', '用于风热感冒，症见：发热，头痛，或恶风，咽痛，口渴，便秘，尿黄');
INSERT INTO `prescriptionofdrugs` VALUES (16, '连花清咳片', NULL, '麻黄、石膏、连翘、黄芩、桑白皮、炒苦杏仁、前胡、清半夏、陈皮、浙贝母、牛蒡子、山银花、大黄、桔梗 、', '宣肺泄热，化痰止咳', '用于急性气管-支气管炎痰热壅肺 证引起的咳嗽，咳痰、痰白粘或色黄，伴咽干口渴，心胸烦闷，大便干，舌红，苔薄黄腻，脉滑数');
INSERT INTO `prescriptionofdrugs` VALUES (17, '疏风解毒胶囊', NULL, '虎杖、连翘、板蓝根、柴胡、败酱草、马鞭草、芦根、甘草', '疏风清热，解毒利咽', '用于急性上呼吸道感染属风热证，症见发热，恶风，咽痛，头痛，鼻塞，流浊涕，咳嗽等');
INSERT INTO `prescriptionofdrugs` VALUES (18, '射麻口服液', NULL, '麻黄、胆南星、石膏、桑白 皮（蜜炙）、射干、莱菔子（炒 黄）、苦杏仁、白前、黄芩、五味子（醋蒸）', '清肺化痰，止咳平喘', '适用于外邪犯肺、入里化热所致：咳嗽、痰多稠粘，胸闷憋气，气促作喘，喉中痰鸣，发热或不发热，舌苔黄或黄白，或舌 质红，脉弦滑或滑数等');
INSERT INTO `prescriptionofdrugs` VALUES (19, '感冒退热颗粒', NULL, '大青叶、板蓝根、连翘、拳参', '清热解毒，疏风解表', '用于上呼吸道感染、急性扁桃体炎、咽喉炎属外感风热、热毒壅盛证，症见发热、咽喉肿痛');
INSERT INTO `prescriptionofdrugs` VALUES (20, '藿香正气胶囊', NULL, '广藿香、紫苏叶、白芷、厚朴（姜制）、大腹皮、法半夏 、陈皮、白术（炒）、茯苓、桔梗、生姜、大枣、甘草', '解表化湿，理气和中', '用于外感风寒、内伤湿滞或夏伤暑湿所致的感冒，症见头痛昏重、胸膈痞闷、脘腹胀痛、呕吐泄泻：胃肠型感冒见上述证候者');
INSERT INTO `prescriptionofdrugs` VALUES (21, '小儿柴桂退热颗粒', NULL, '柴胡、桂枝、葛根、浮萍、黄芩、白芍、蝉蜕', '发汗解表，清里退热', '用于小儿外感发热。症见发热，头身痛，流涕，口渴，咽红，溲黄，便干');
INSERT INTO `prescriptionofdrugs` VALUES (22, '小儿金翘颗粒', NULL, '金银花、连翅、葛根、大青叶、山豆根、柴胡、甘草', '疏风清热，解毒利咽，消肿止痛', '用于风热袭肺所致乳蛾，症见恶 寒发热，咽部红肿疼痛，吞咽时加剧，咽干灼热，喉核红肿：小儿急性扁桃体炎见上述证候者');
INSERT INTO `prescriptionofdrugs` VALUES (23, '小儿热速清口服液', NULL, '柴胡、黄芩、板蓝根、葛根、金银花、水牛角、连翅、大黄', '清热解毒，泻火利咽', '用于小儿外感风热所致的感冒，症见高热、头痛、咽喉肿痛、鼻塞流涕、咳嗽、大便干结');
INSERT INTO `prescriptionofdrugs` VALUES (24, '小儿肺热咳喘颗粒', NULL, '麻黄、苦杏仁、石膏、甘草、金银花、连翘、知母、黄芩、板蓝根、麦冬、鱼腥草', '清热解毒，宣肺化痰', '用于热邪犯于肺卫所致发热、汗出、微恶风寒、咳嗽、痰黄，或兼喘息、口干而渴');
INSERT INTO `prescriptionofdrugs` VALUES (25, '小儿消积止咳口服液', NULL, '炒山楂、槟榔、枳实、蜜枇杷叶、瓜萎、炒莱菔子、炒葶苈子、桔梗、连翘、蝉蜕', '清热肃肺、消积止咳', '用于小儿饮食积滞、痰热蕴肺所致的咳嗽、夜重加重、喉间痰鸣、腹胀、口臭');
INSERT INTO `prescriptionofdrugs` VALUES (26, '小儿肺咳颗粒', NULL, '人参、茯苓、白术、陈皮、 鸡内金、酒大黄、鳖甲、地骨皮、北沙参、炙甘草、青蒿、麦冬、桂枝、干姜、淡 ', '健脾益肺，止咳平喘', '用于肺脾不足，痰湿内壅所致咳嗽或痰多稠黄，咳吐不爽，气短，喘促，动辄汗出，食少纳呆，周身乏力，舌红苔厚；小儿支气管炎见以上证候者');
INSERT INTO `prescriptionofdrugs` VALUES (27, '小儿清热感冒片', NULL, '羌活、荆芥、防风、苍术（炒）、白芷、葛根、川芎、苦杏仁（炒）、地黄、黄芩、甘草、人工牛黄', '发汗解肌，清热透表', '用于脏腑积热引起的发热怕冷，肌表无汗，头痛口渴，鼻塞咳嗽');
INSERT INTO `prescriptionofdrugs` VALUES (28, '小儿感冒颗粒', NULL, '广藿香、菊花、连翘、大青叶、板蓝根、地黄、地骨皮、白薇、薄荷、石膏。', '疏风解表，清热解毒', '用于小儿风热感冒，症见发热重 、头胀痛、咳嗽痰黏、咽喉肿痛；流感见上述证候者');
INSERT INTO `prescriptionofdrugs` VALUES (29, '小儿双清颗粒', NULL, '人工牛黄、羚羊角、水牛角浓缩粉、厚朴、板蓝根、连翘、拳参、石膏、莱菔子（炒）、荆芥穂、薄荷脑、冰片', '清热解毒，表里双解', '用于小儿外感属表里俱热证，见发热，流涕，咽红，口渴，便干，溲赤，舌红，苔黄者；急性上呼吸道感染见上述证候者');
INSERT INTO `prescriptionofdrugs` VALUES (30, '小儿热速清颗粒', NULL, '柴胡、黄芩、板蓝根、葛根、金银花、水牛角、连翘、大黄。', '清热解毒，泻火利咽', '用于小儿外感风热所致的感冒，症见高热、头痛、咽喉肿痛、鼻塞流涕、咳嗽、大便干结');
INSERT INTO `prescriptionofdrugs` VALUES (31, '小儿致翘清热颗粒', NULL, '连翘、淡豆豉、薄荷、荆芥、炒栀子、大黄、青蒿、赤芍、槟榔、厚朴、黄芩、半夏、柴胡、甘草。', '疏风解表，清热导滞', '用于小儿风热感冒夹滞证，症见 发热咳嗽，鼻塞流涕，咽红肿痛，纳呆口渴，脘腹胀满，便秘或大便酸臭，溲黄');
INSERT INTO `prescriptionofdrugs` VALUES (32, '儿童清肺口服液', NULL, '麻黄、炒苦杏仁、石膏、甘草、蜜桑白皮、瓜萎皮、黄芩、板蓝根、橘红、法半夏 、炒紫苏子、葶苈子、浙贝母', '清肺，解表，化痰，止嗽', '用于小儿风寒外束、肺经痰热所致的面赤身热、咳嗽气促、痰多粘稠、咽痛声哑');
INSERT INTO `prescriptionofdrugs` VALUES (33, '儿感退热宁颗粒', NULL, '青蒿、板蓝根、连翘、菊花 、苦杏仁、桔梗、薄荷、甘草', '解表清热，化痰止咳，解毒利咽', '用于小儿外感风热，内郁化火，发烧头痛，咳嗽，咽喉肿痛');
INSERT INTO `prescriptionofdrugs` VALUES (34, '芩香清解口服液', NULL, '黄芩、广藿香、蝉蜕、石膏 、葛根、大黄、赤芍、板蓝根、桔梗、玄参、山豆根、', '散风热，清泻里热，解毒利咽疏', '用于小儿上呼吸道感染表里俱热证，症见发热、鼻塞、流涕、咳嗽、咽红肿痛、便秘、口渇烦躁、舌红苔黄、脉滑数等者');
INSERT INTO `prescriptionofdrugs` VALUES (35, '正柴胡饮颗粒', NULL, '柴胡、陈皮、防风、赤芍、甘草、生姜', '表散风寒，解热止痛', '用于外感风寒初起：发热恶寒，无汗，头痛，鼻塞，喷嚏，咽痒咳噷，四肢酸痛。及流行性感冒初起、轻度上呼吸道感染见上述');
INSERT INTO `prescriptionofdrugs` VALUES (36, '小儿肺热清颗粒', NULL, '麻黄（蜜炙）、石膏、苦杏仁（炒）、桑白皮（蜜炙）、荸苈子（炒）、当归、丹参、地龙 、僵蚕（炒）、甘草', '清肺化痰，止咳平喘', '用于小儿急性支气管炎引起的肺热咳嗽，咳痰、痰多色黄，小便黄，大便于，舌红，苔黄或腻，脉滑数等症状');
