INSERT INTO `sys_oper_log` VALUES (130, '中药材', 1, 'com.ruoyi.web.controller.system.ChinesemedicineController.add()', 'POST', 1, 'admin', NULL, '/system/chinesemedicine', '127.0.0.1', '内网IP', '{\"chandi\":\"人工饲养，一年可繁殖3代。分布于全国各地，以长江以南为主。\",\"gongxiao\":\"祛风定惊、化痰散结。属平肝息风药下属分类的息风止痉药。\",\"huaxuezucheng\":\"僵蚕主要含蛋白质，脂肪。尚含多种氨基酸以及铁、锌、铜、锰、铬等微量元素。\",\"id\":29,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/140407/1-14040F93925436.jpg\",\"jinji\":\"心虚不宁、血虚生风者慎服。\",\"linchuangzuoyong\":\"用量5～9克，煎服或人丸、散。用治惊风抽搐、咽喉肿痛、皮肤瘙痒、颌下淋巴结炎、面神经麻痹。\",\"name\":\"僵蚕\",\"otherName\":\"天虫、僵虫、白僵蚕。\",\"params\":{},\"source\":\"蚕蛾科昆虫家蚕蛾Bombyx moriL.的幼虫感染白僵菌Beauveriabasiana (Bals.)Vaillant致死的干燥虫体。\",\"xingtai\":\"雌雄成虫全身皆密布白色鳞片。体长1.6～2.3厘米。翅展3.9～4.3厘米。头部较小。复眼l对。口器退化，下唇须细小。触角呈羽毛状。翅2对，前翅位于中胸部，呈三角形，较大；后翅生自后胸，较小；翅面有白色鳞片。雌性腹部肥硕，末端钝圆；雄性腹部狭窄，末端稍尖。幼虫体色灰白色至白色，胸部第2、3节稍见膨大，有皱纹。腹部第8节背面有l尾角。\",\"xingweiguijing\":\"性平，味咸、辛。归肝经、肺经、胃经。\",\"xingzhuang\":\"雌雄成虫全身皆密布白色鳞片。体长1.6～2.3厘米。翅展3.9～4.3厘米。头部较小。复眼l对。口器退化，下唇须细小。触角呈羽毛状。翅2对，前翅位于中胸部，呈三角形，较大；后翅生自后胸，较小；翅面有白色鳞片。雌性腹部肥硕，末端钝圆；雄性腹部狭窄，末端稍尖。幼虫体色灰白色至白色，胸部第2、3节稍见膨大，有皱纹。腹部第8节背面有l尾角。\",\"yaoliyanjiu\":\"具有镇静、抗惊厥作用;具有抗凝血、降血糖和明显抑制肉瘤S180的生长，及具有较弱的抑制细菌生长等作用。\",\"yaowupeifang\":\"①治风壅牙痛：僵蚕，藁本、白芷各等分。上为细末。每用少许揩牙痛处，用盐水灌漱。(《普济方&gt;僵蚕散)\\n\\n　　②治重舌、木舌：僵蚕3克，黄连(蜜炒)6克。为末，掺之，涎出为妙。(《积德堂经验方》)\\n\\n　　③治喉痹口疮，腮颊肿痛：白僵蚕(炒去丝、嘴)、牛蒡子(微炒)各等分。为细末，炼蜜为丸，每30克作1.5丸。每服1丸，含化，食后。(《杨氏家藏方》消毒丸)\\n\\n　　④治喉痹失音：瓜蒌皮(炒)、僵蚕(炒)、甘草(炒)各6克。共为末。每服9克，姜汤下。(《疑难杂症简方》)\\n\\n　　⑤治喘嗽，喉中如锯，不能睡卧：好末茶30克，白僵蚕30克。上为细末，放碗内，倾沸汤一小盏，用盏盖定，临卧，再添汤点服。(《瑞竹堂经验方》僵蚕汤)\\n\\n　　⑥治瘰疬：白僵蚕，研末，水服1.5克，日三服。(《千金要方》)\\n\\n　　⑦治遍身瘾疹，疼痛成疮：白僵蚕，焙令黄色，细研为末，酒服。(《圣惠方》)\\n\\n　　⑧治一切疥癣：白僵蚕24枚(炒去丝)，蝎梢5枚(去毒，微炒)，地龙3条。上件研令极细。分作二服，小儿作五服。温酒调下。服药，然后澡浴。(《杨氏家藏方》三神散)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-04-14 17:54:35');
INSERT INTO `sys_oper_log` VALUES (131, '中医房', 1, 'com.ruoyi.web.controller.system.TcmShopController.add()', 'POST', 1, 'admin', NULL, '/system/shop', '127.0.0.1', '内网IP', '{\"address\":\"安徽省蚌埠市龙子湖区群力街86号\",\"city\":\"蚌埠市\",\"coordinate\":\"117.379969,32.948383\",\"id\":3,\"introduce\":\"蚌埠市龙子湖区国医堂养生馆成立于2019年06月20日，位于安徽省蚌埠市龙子湖区金润名都第7栋1单元1层01011号，目前处于开业状态，经营范围包括理疗、养生服务（依法须经批准的项目，经相关部门批准后方可开展经营活动）等。\",\"name\":\"蚌埠国医堂(群力街店)\",\"params\":{}}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-12 09:24:23');
INSERT INTO `sys_oper_log` VALUES (132, '中医好文', 1, 'com.ruoyi.web.controller.system.TcmArticleController.add()', 'POST', 1, 'admin', NULL, '/system/article', '127.0.0.1', '内网IP', '{\"articleContent\":\"1.健脾滋胃方【处方】太子参18克,茯苓15克,淮山药15克,麦冬15克,石斛12克,白芍15克,生甘草6克,木瓜10克,丹参15克,生蒲黄15克,莪术10克,生谷芽15克。【主治】脘腹痛2.四逆梅瓜汤【处方】柴胡10克,枳壳10克,白芍15克,陈皮6克,青皮9克,苏叶6克,郁金10克,苍术12克,木瓜15克,乌梅10克,甘草6克【主治】糙皮病3.宫血灵【处方】益母草30克，贯众炭15克，茜草12克，生山楂15克，红花10克，旱莲草、生地榆、藕节各30克，三七粉3克(研服)。【用法】水煎服，每日1剂，日服2次。【功效】清热凉血，祛瘀止血。【主治】月经过多，经期延长，功血，子宫肌瘤，子宫内膜炎，放环后出血等。【加减】气虚不摄者，加党参、黄芪、白术、升麻；热象重者，加黑条芩、黑山栀、黄柏炭；偏寒者，加炮姜炭、艾叶；腹痛重者，加元胡、五灵脂；血虚重者，加白芍炭、熟地炭、阿胶；子宫内膜炎者，加二花炭、黄芩炭、败酱草、白芷。【方源】《中国中医秘方大全》4.香蔻汤【处方】煨肉蔻3g 丁香3g 草蔻6g 白蔻仁5g 茯苓15g 怀山药20g 木香10g 木瓜10g 乌贼骨20g 甘草10g【功效】温肾健脾 醒脾化湿 涩肠止泻【主治】睥肾阳虚之泄泻。症见腹泻、遇凉加重或夜间加重，伴脘腹胀满、肛门下坠、四肢不温、舌质淡红、舌苔薄白、脉弦细或细者，临床常用于肠易激综合征、功能性腹泻、慢性非特异性溃疡性结肠炎、直肠炎。【加减】脘腹胀满，加焦三仙、鸡内金、砂仁、焦白术、檀香、党参、苡仁以补气健脾、温中和胃消食。若泄泻次数较多或水样便，加赤石脂、芡实固涩止泻。肛门下坠者加枳壳以行气导滞。若久泄不止、中气下陷而致脱肛者，可合补中益气汤加减，以益气升清、健脾止泻。阴寒内盛、手足不温、腹中冷痛者，合用附子理中丸再加吴茱萸、肉桂温中散寒\",\"articleTitle\":\"压箱底干货：有价值的秘验方30首，可遇不可求！收藏备用吧（上）\",\"articleType\":\"中医药\",\"createTime\":\"2024-06-14T09:30:42.79+08:00\",\"id\":4,\"params\":{}}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-14 09:30:42');
INSERT INTO `sys_oper_log` VALUES (133, '中医好文', 1, 'com.ruoyi.web.controller.system.TcmArticleController.add()', 'POST', 1, 'admin', NULL, '/system/article', '127.0.0.1', '内网IP', '{\"articleContent\":\"以下方剂都是张仲景《伤寒论》的药方。正确使用的话，效果非常好。本文主要目的是希望能够让愿意相信中医的所有人，都能够以最简单的判断方法来自行治疗简易的感冒症状，因此以图表方式呈现，最终期盼能让完全不懂中医的人士，也能轻易看得懂。也因为必须尽量简化，因此较复杂的症状及用药方法无法一一详述于简表中，但大部分的感冒应该可以囊括。希望大家能对这三张图表提出各项建议（最终目的就是希望不论是否懂中医概念的人都能看懂且自行治疗感冒），集合大伙儿的智慧，或许可以改版得更简单易懂！※ 漏了一个大柴胡汤, 应用时机就是小柴胡汤的症状加上便秘。欢迎大家转载、下载，或有任何批评与建议皆可，希望最终能有更多人能因此免于西药的迫害！小病不求人，真的有需要再去看医生!一、桂枝汤：桂枝9g 芍药9g 炙甘草6g 生姜9g 大枣12枚(擘）五味药。用法：服桂枝汤约半小时后，须喝热稀粥1小碗，以助药力而使溱溱汗出。上五味，切碎三味。以水700毫升，微火煮取300毫升，去滓。适寒温，服100毫升。服已须臾，啜热稀粥适量，以助药力。温覆（盖被子）一时许，遍身微汗者为佳。若一服汗出病愈，停后服，不必尽剂，若不汗，更服，依前法，又不汗，后服小促其间，半日许，令三服尽。服一剂尽，病证犹在者，更作服，若汗不出者，乃服至二三剂。主治：外感风寒，发热恶风，头痛项强，身痛有汗，鼻呜干呕，苔白不渴，脉浮缓或浮弱。禁忌：服药期间，禁食生冷、粘滑、肉、面、五辛、酒酪、臭恶等物。表实无汗，表寒里热，及温病初起，见发热口渴者，均忌用。方论：桂枝汤方中桂枝为君，辛温通阳，解肌发表，散外感风寒之邪以调卫。芍药指白芍，作为臣药，酸苦微寒，益阴和里，敛固外泄之营阴以和营。桂芍等量相合，相须为用，一治卫强，一治营弱，散中有收，汗中寓补，使表邪得解，营卫调和。生姜助桂枝辛散表邪，又可温胃止呕；大枣助芍药益阴养血，姜枣相配，补脾和胃，调和营卫，共为佐药。甘草调和诸药，合桂枝辛甘化阳以实卫，合芍药酸甘化阴以和营，是为佐使药。有老中医在原方的基础上，加黄芪30g，糯稻根10g，治疗老年自汗，效果非常明显。加入黄芪补肺固卫以培本，糯稻根止汗以治标。\",\"articleTitle\":\"《伤寒论》治疗各种感冒发烧的特效药方\",\"articleType\":\"中药方\",\"createTime\":\"2024-06-14T09:47:22.468+08:00\",\"id\":5,\"params\":{}}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-14 09:47:22');
