INSERT INTO `sys_oper_log` VALUES (149, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"人工饲养，一年可繁殖3代。分布于全国各地，以长江以南为主。\",\"gongxiao\":\"祛风定惊、化痰散结。属平肝息风药下属分类的息风止痉药。\",\"huaxuezucheng\":\"僵蚕主要含蛋白质，脂肪。尚含多种氨基酸以及铁、锌、铜、锰、铬等微量元素。\",\"id\":30,\"imageurl\":\"https://bkimg.cdn.bcebos.com/pic/1ad5ad6eddc451da81cba0c590aa4566d016092494dc?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080\",\"jinji\":\"心虚不宁、血虚生风者慎服。\",\"linchuangzuoyong\":\"用量5～9克，煎服或人丸、散。用治惊风抽搐、咽喉肿痛、皮肤瘙痒、颌下淋巴结炎、面神经麻痹。\",\"name\":\"益母草\",\"otherName\":\"天虫、僵虫、白僵蚕。\",\"params\":{},\"source\":\"蚕蛾科昆虫家蚕蛾Bombyx moriL.的幼虫感染白僵菌Beauveriabasiana (Bals.)Vaillant致死的干燥虫体。\",\"xingtai\":\"雌雄成虫全身皆密布白色鳞片。体长1.6～2.3厘米。翅展3.9～4.3厘米。头部较小。复眼l对。口器退化，下唇须细小。触角呈羽毛状。翅2对，前翅位于中胸部，呈三角形，较大；后翅生自后胸，较小；翅面有白色鳞片。雌性腹部肥硕，末端钝圆；雄性腹部狭窄，末端稍尖。幼虫体色灰白色至白色，胸部第2、3节稍见膨大，有皱纹。腹部第8节背面有l尾角。\",\"xingweiguijing\":\"性平，味咸、辛。归肝经、肺经、胃经。\",\"xingzhuang\":\"雌雄成虫全身皆密布白色鳞片。体长1.6～2.3厘米。翅展3.9～4.3厘米。头部较小。复眼l对。口器退化，下唇须细小。触角呈羽毛状。翅2对，前翅位于中胸部，呈三角形，较大；后翅生自后胸，较小；翅面有白色鳞片。雌性腹部肥硕，末端钝圆；雄性腹部狭窄，末端稍尖。幼虫体色灰白色至白色，胸部第2、3节稍见膨大，有皱纹。腹部第8节背面有l尾角。\",\"yaoliyanjiu\":\"具有镇静、抗惊厥作用;具有抗凝血、降血糖和明显抑制肉瘤S180的生长，及具有较弱的抑制细菌生长等作用。\",\"yaowupeifang\":\"①治风壅牙痛：僵蚕，藁本、白芷各等分。上为细末。每用少许揩牙痛处，用盐水灌漱。(《普济方&gt;僵蚕散)\\n\\n　　②治重舌、木舌：僵蚕3克，黄连(蜜炒)6克。为末，掺之，涎出为妙。(《积德堂经验方》)\\n\\n　　③治喉痹口疮，腮颊肿痛：白僵蚕(炒去丝、嘴)、牛蒡子(微炒)各等分。为细末，炼蜜为丸，每30克作1.5丸。每服1丸，含化，食后。(《杨氏家藏方》消毒丸)\\n\\n　　④治喉痹失音：瓜蒌皮(炒)、僵蚕(炒)、甘草(炒)各6克。共为末。每服9克，姜汤下。(《疑难杂症简方》)\\n\\n　　⑤治喘嗽，喉中如锯，不能睡卧：好末茶30克，白僵蚕30克。上为细末，放碗内，倾沸汤一小盏，用盏盖定，临卧，再添汤点服。(《瑞竹堂经验方》僵蚕汤)\\n\\n　　⑥治瘰疬：白僵蚕，研末，水服1.5克，日三服。(《千金要方》)\\n\\n　　⑦治遍身瘾疹，疼痛成疮：白僵蚕，焙令黄色，细研为末，酒服。(《圣惠方》)\\n\\n　　⑧治一切疥癣：白僵蚕24枚(炒去丝)，蝎梢5枚(去毒，微炒)，地龙3条。上件研令极细。分作二服，小儿作五服。温酒调下。服药，然后澡浴。(《杨氏家藏方》三神散)\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ChinesemedicineMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ChinesemedicineMapper.updateChinesemedicine-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update chinesemedicine          SET name = ?,             imageURL = ?,             other_name = ?,             source = ?,             xingtai = ?,             chandi = ?,             xingzhuang = ?,             xingweiguijing = ?,             gongxiao = ?,             linchuangzuoyong = ?,             yaoliyanjiu = ?,             huaxuezucheng = ?,             jinji = ?,             yaowupeifang = ?          where id = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 18:44:14');
