INSERT INTO `sys_oper_log` VALUES (163, '中医房', 2, 'com.ruoyi.web.controller.system.TcmShopController.edit()', 'PUT', 1, 'admin', NULL, '/system/shop', '36.7.106.41', 'XX XX', '{\"address\":\"合肥市瑶海区襄水路马岗菜市南门西34间\",\"city\":\"合肥市\",\"coordinate\":\"117.370793,31.863905\",\"coverImage\":\"/profile/upload/2024/06/26/3_20240626213651A005.png\",\"id\":5,\"introduce\":\"电话:  13667693180\",\"name\":\"蔡贵中西药房\",\"params\":{}}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 21:55:42');
INSERT INTO `sys_oper_log` VALUES (164, '中医房', 1, 'com.ruoyi.web.controller.system.TcmShopController.add()', 'POST', 1, 'admin', NULL, '/system/shop', '36.7.106.41', 'XX XX', '{\"address\":\"青岛市城阳区流亭街道惠安路21号\",\"city\":\"青岛市\",\"coordinate\":\"120.337182,36.280374\",\"coverImage\":\"/profile/upload/2024/06/26/8_20240626220221A011.png\",\"introduce\":\"营业时间：08:00-18:00  简介：天成集团旗下有青岛百姓阳光大药房连锁有限公司、青岛悦康医药有限公司、青岛天成中药饮片有限公司、青岛天成阳光贸易有限公司四家独立法人公司。历经十余年拼搏发展,从青岛自选量贩式药店创始者,到现代医药物流实践者,再到农副产品和中药饮片生产开发者,天成集团已发展成为集医药生产、医药批发、医药零售连锁终端及农副产品、日用品批发零售为一体的多元化产业链式集团公司,年营业额达5亿余元。 青岛天成中药饮片有限公司成立于2013年8月,坐落于美丽的青岛白沙湾畔,是天成集团公司成员企业,拥有自己的产品品牌和加工工厂。天成饮片致力于中药饮片研发和生产,建立了标准化的质量管理体系,获得了药品生产许可证,并顺利通过国家GMP认证,建成了年产值5000吨的中药饮片生产线。 公司现有建筑面积3500平米,生产、检验、仓储、办公、生活设施配套齐全。生产车间包括口服净化车间、普通饮片车间、毒性饮片车间及小包装饮片包装车间、原料药仓库、成品药仓库,并按规范要求配备先进的设施设备。其中净化车间面积400平方米,能够达到直接口服饮片要求的D级净化级别。公司主要生产经营中药饮片以及小包装中药饮片,生产范围:中药饮片(含直接服用饮片、净制、切制、醋制、酒制、盐制、炒制、烫制、煅制、蒸制、煮制等),可生产各种规格中药饮片1000多种,能充分满足省内外中药制剂企业原料供应、医疗机构中药处方配方及各大药店中药饮片调剂销售的需求。 青岛天成中药饮片有限公司是天成集团从比较单一的医药销售向医药生产销售跨越的重要标志,是集团公司适应市场发展,引领医药领域发展新模式的重要步骤。公司所在的青岛空港工业园是青岛市重点工业和物流园区,毗邻青岛高新区、流亭国际机场、铁路青岛北站、青银高速、青兰高速,交通便利,区位发展优势十分明显。 伴随着人们健康理念的深化、中药文化的传播以及中医理论的全球化推广,以中医药为代表的天然药物的应用逐渐在世界范围内为人们所认可,中药饮片也逐渐被各国所接受,中药饮片行业的市场地位将持续提升,未来成长空间广阔。据世界卫生组织估计,中草药的开发利用在未来的10 年内将在世界范围全面兴起。 青岛天成中药饮片有限公司本着“立足青岛,面向山东,辐射全国,走向世界”的发展规划,坚持以质量为生命,以市场为导向,以专业为保障,努力打造产品和销售服务两个核心竞争力,通过科学有效的管理手段和品牌化运作,大力发扬“求真、务实、创新”的企业精神,共同实现多赢,为人类做出更好的服务和更大的贡献!\",\"name\":\"天成中药\",\"params\":{}}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'introduce\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/TcmShopMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.TcmShopMapper.insertTcmShop-Inline\r\n### The error occurred while setting parameters\r\n### SQL: insert into tcm_shop          ( name,             address,             coordinate,             introduce,             cover_image,             city )           values ( ?,             ?,             ?,             ?,             ?,             ? )\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'introduce\' at row 1\n; Data truncation: Data too long for column \'introduce\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'introduce\' at row 1', '2024-06-26 22:02:34');
