INSERT INTO `sys_oper_log` VALUES (177, '中医房', 2, 'com.ruoyi.web.controller.system.TcmShopController.edit()', 'PUT', 1, 'admin', NULL, '/system/shop', '36.7.106.41', 'XX XX', '{\"address\":\"青岛市即墨区崂山二路18号\",\"coordinate\":\"120.50542664206, 36.395562852109\",\"coverImage\":\"/profile/upload/2024/06/26/12_20240626221104A015.png\",\"id\":14,\"name\":\"青岛鸿德盛中药有限公司\",\"params\":{}}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:13:47');
INSERT INTO `sys_oper_log` VALUES (178, '中药材', 1, 'com.ruoyi.web.controller.system.ChinesemedicineController.add()', 'POST', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于草甸、向阳丘陵地。分布于黑龙江、吉林、辽宁、内蒙古、河北、河南、山西等地。\",\"gongxiao\":\"散结，杀虫。属杀虫止痒药。\",\"huaxuezucheng\":\"主要含羽扇豆醇、狼毒大戟素A、狼毒大戟素B等成分。\",\"id\":32,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/150707/1-150Q5110221T9.jpg\",\"jinji\":\"本品有毒，宜慎服，孕妇禁服。不宜与密陀僧同用。\",\"linchuangzuoyong\":\"外用：适量，研粉或制成软膏，搽、敷。内服：煎汤，炮制后用1～2.4克，或入丸、散。外用于淋巴结结核、皮癣，灭蛆。\",\"name\":\"狼毒\",\"otherName\":\"白狼毒、黄皮狼毒、猫眼睛\",\"params\":{},\"source\":\"大戟科植物狼毒大戟Euphorbia fischeriana Steud.或月腺大戟Euphorbia ebracteolata Hayata的干燥根\",\"xingtai\":\"多年生草本，高30～60厘米。植物体具白色乳汁。根肉质，长圆锥形，外皮红褐色或褐色。茎直立，单一，疏生白色柔毛，尤以节间较多。叶互生；近无柄；茎中部以上的叶3～5枚轮生；叶片长圆形。总花序多歧聚伞花序，顶生，通常具5伞梗，每伞梗又生出3小梗或再3、4小伞梗；杯状总苞外面有柔毛，内面近无毛，边缘有睫毛，腺体4个，肾形。总苞内有多数雄花，每花仅有l雄蕊；雌花1朵生于总苞中央，仅具l雌蕊，常伸出总苞而下垂，子房3室，花柱3，柱头2裂。蒴果密生短柔毛或无毛。花期5～6月，果期6～7月。\",\"xingweiguijing\":\"性平，味辛。归肝经、脾经。\",\"xingzhuang\":\"根为类圆形或长圆形块片，直径1.5～8厘米，厚0.3～4厘米。外皮棕黄色，切面纹理或环纹显黑褐色。水浸后有黏性，撕开可见黏丝。气微，味微辛。\",\"yaoliyanjiu\":\"具有抗肿瘤、杀蛆、灭孑孓等作用。\",\"yaowupeifang\":\"①治干湿疥疮：鲜狼毒捣烂，加生猪油和匀，布包搽患处。(《安徽中草药》)\\n\\n　　②治顽癣：狼毒研细末，棉子油或醋调搽患处。(《安徽中草药》)\\n\\n　　③治牛皮癣、神经性皮炎：将狼毒熬膏，每日隔日外搽1次。(《全国中草药汇编》)\\n\\n\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:28:03');
INSERT INTO `sys_oper_log` VALUES (179, '中药材', 1, 'com.ruoyi.web.controller.system.ChinesemedicineController.add()', 'POST', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于干燥的山坡、山脊或林中。分布于黑龙江、吉林、辽宁、内蒙古等地。\",\"gongxiao\":\"止咳、祛痰。属化痰止咳平喘药下属分类的止咳平喘药。\",\"huaxuezucheng\":\"叶含挥发油、黄酮类、内酯类、金丝桃苷、异金丝桃苷、杜鹃素、杜鹃黄素、棉花皮素、山柰酚、杨梅树皮素、槲皮素、石竹烯氧化物、木藜芦毒素Ⅰ等成分。\",\"id\":33,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/130911/1-130911164G0b2.jpg\",\"jinji\":\"可有口干、恶心、呕吐等神经系统症状，但程度轻微。部分病人可出现心率缓慢、血压下降等。肝病患者慎用。\",\"linchuangzuoyong\":\"用量9～15克，内服煎汤，鲜品加倍。治疗急、慢性支气管炎，咳嗽气喘痰多。\",\"name\":\"满山红\",\"otherName\":\"映山红、迎山红、金达来、东北满山红。\",\"params\":{},\"source\":\"兴安杜鹃的叶经水蒸气蒸馏得到的挥发油。\",\"xingtai\":\"半常绿灌木。叶互生，叶片革质，长圆形，两端钝，顶端有短尖头，上面有疏鳞片，下面有密鳞片，叶柄有微毛。花生于枝端，先叶开放，花冠宽漏斗状，5裂。蒴果。\",\"xingweiguijing\":\"性温，味辛、苦。归肺经。\",\"xingzhuang\":\"叶片干时卷曲，完整叶片椭圆形、长椭圆形或长倒卵形，先端钝或稍尖，常微缺，微缺处具钝的短尖，叶基近圆形或阔楔形。全缘，上表面暗绿色至褐绿色，下表面灰绿色，中脉隆起，侧脉不明显，叶柄表面凹，背面圆突。近革质。气特异芳香，味苦微辛。\",\"yaoliyanjiu\":\"对呼吸系统有镇咳、祛痰、平喘作用，体外试验，能抑制大鼠气管一肺组织呼吸，使耗氧量降低；可影响心血管系统，且具有一定的抗炎作用。灌服或腹腔注射乙醇或水提取液，对豚鼠、猫、小鼠均有止咳作用；醇浸水沉液、挥发油和水溶部分灌服对兔和小鼠酚红法均显示祛痰作用，杜鹃鸟素和去甲杜鹃素是祛痰主要成分。毒性：浸膏的生理盐水溶液给豚鼠静注，出现心率减慢，最后窦性停搏。\",\"yaowupeifang\":\"①治慢性支气管炎：满山红叶粗末60克， 白酒500毫升，浸7天过滤，每服15～20毫升，每日服3次。（《黑龙江常用中草药手册》）\\n\\n　　②治慢性支气管炎：满山红12～24克，三棵针、暴马丁香各9克。水煎，分2次服。[中国医学科学院药物研究所《满山红治疗慢性气管炎的临床和实验研究资料》1971，(11)；30]\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:31:19');
INSERT INTO `sys_oper_log` VALUES (180, '中药材', 1, 'com.ruoyi.web.controller.system.ChinesemedicineController.add()', 'POST', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于阴湿岩石壁或树干上，分布于云南、四川、贵州、广西、广东、福建、台湾、浙江、江西、湖南、湖北、陕西、安徽等省区。\",\"gongxiao\":\"化痰止咳，软坚散结。属化痰止咳平喘药下属分类的温化寒痰药。\",\"huaxuezucheng\":\"全草含石吊兰素，即内华达素(nevade-nsin)。还有黄酮类及挥发油类\",\"id\":34,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/140808/1-140PQ61Z4454.jpg\",\"jinji\":\"孕妇忌服。\",\"linchuangzuoyong\":\"内服：煎汤，9～15克，或浸酒服。外用：适量，捣敷，或煎水外洗。用治咳嗽痰多，瘰疬痰核。\",\"name\":\"石吊兰\",\"otherName\":\"黑乌骨、石豇豆、石泽兰、小泽兰、岩豇豆、岩石茶。\",\"params\":{},\"xingtai\":\"常绿附生半灌木。匍匐茎灰褐色，老枝黄棕色，长7～40厘米，不分枝或少分枝，幼枝常有短毛，皮微有皱纹。叶对生或三至数片轮生，革质，有短柄或近无柄，紫红绿色。叶片大小、形状变化较大。楔形、楔状条形，狭矩圆形，挟卵形，或倒卵形，长1.5～5.5厘米，宽3～16毫米，先端钝或短尖。基部楔形或钝圆，边缘在中部以上有牙齿，下部全缘或微波状，上面深绿色，有光泽，下面淡绿色，无毛。花序腋生，有花1～4朵，花序梗长1.5～3.5厘米，苞片小，早落，花萼5深裂至基部，裂片三角状条形。花冠白色至淡红色，常带紫色，管状，长3.5～4.5厘米，中部以上膨大，近二唇形，上唇2裂，下唇3裂，无毛，雄蕊4，能育雄蕊2，花药连着。花盘杯状，4裂，雌蕊单一，无毛。蒴果1～2个，条形，长7.5～10厘米，两端有毛。种子细小，顶端有长毛。花期5～7月，果期8～10月。\",\"xingweiguijing\":\"性温，味苦。归肺经。\",\"xingzhuang\":\"茎呈圆柱形，长25～60厘米，直径0.2～0.5厘米。表面淡棕色或灰褐色，有纵皱纹，节膨大，常有不定根；质脆，易折断，断面黄绿色或黄棕色，中心有空隙。叶轮生或对生，有短柄；叶多脱落，脱落后叶柄痕明显；叶片披针形至狭卵形，长1.5～6厘米，宽0.5～1.5厘米，边缘反卷，边缘上部有齿，两面灰绿色至灰棕色。气微，味苦。\",\"yaoliyanjiu\":\"有抗结核杆菌、抗炎、抗肝毒、止咳祛痰、平喘镇静、降血压、降血脂及抗动脉粥样硬化作用。\",\"yaowupeifang\":\"①治腰、四肢痛：石吊兰、杜仲各三钱。水煎服。（《湖南药物志》）\\n\\n　　②治热咳：岩豇豆、青鱼胆草、岩白菜各五钱。水煎服。（《贵阳民间药草》）\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:32:55');
INSERT INTO `sys_oper_log` VALUES (181, '中药材', 1, 'com.ruoyi.web.controller.system.ChinesemedicineController.add()', 'POST', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于山坡、丘陵地带的草丛及灌木林的边缘。分布于江苏、安徽南部、浙江等地。\",\"gongxiao\":\"利水消肿、祛风止痛。属祛风湿药下分类的祛风湿清热药。\",\"huaxuezucheng\":\"含多种生物碱，其中主要为粉防己碱、去甲基粉防己碱、较环藤酚碱、氧化防己碱、防己诺林碱等。可应用比色法及薄层色谱法进行总生物碱及粉防己碱、去甲基粉防己碱的含量测定。\",\"id\":35,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/130922/1-13092210362LW.jpg\",\"jinji\":\"脾胃虚弱及阴虚无湿热者禁服。\",\"linchuangzuoyong\":\"用量4.5～9克，煎汤内服，或入丸、散。用治水肿、小便不利、风湿痹痛、下肢湿热、疥癣疮肿等。\",\"name\":\"防己\",\"otherName\":\"汉防己、石蟾蜍、白木香、山乌龟。\",\"params\":{},\"source\":\"防己科植物粉防己Stephania tetrandraS.Moore的块根。\",\"xingtai\":\"多年生缠绕藤本。根圆柱状，有时呈块状，外皮淡棕色或棕褐色。茎柔韧，圆柱形，有时稍扭曲，具细条纹，枝光滑无毛，基部稍带红色。叶互生，质薄较柔，叶柄盾状着生，长与叶片相等；叶片外形近圆形，先端锐尖，基部截形或稍心形，全缘，两面均被短柔毛，上面绿色，下面灰绿色。花小，雌雄异株，为头状的聚伞花序；雄花花萼4，肉质，三角状，基部楔形，外面被毛，花瓣4，略呈半圆形，边缘微向内弯，具爪，雄蕊4花药近圆形；雌花的花萼、花瓣与雄花同数，无退化雄蕊，心皮1，花柱3枚。核果球形。花期5～6月，果期7～9月。\",\"xingweiguijing\":\"性寒，味苦。归膀胱经、肺经。\",\"xingzhuang\":\"不规则圆柱形、半圆柱形块状或块片状，常弯曲如结节状，长3～10厘米，直径1～6厘米。去栓皮的药材表面淡灰黄色，可见残留的黑褐色栓皮，弯曲处有深陷的横沟。体重，质坚实，断面平坦，灰白色至黄白色，富粉性，有排列稀疏的放射状纹理，纵剖面浅灰白色，维管束浅棕色，呈弯曲筋脉状纹理。气微、味苦。\",\"yaoliyanjiu\":\"有镇痛、抗炎、抗过敏、松弛横纹肌等药理作用，对心血管系统有降压、抗心肌正性肌力、抗心律失常、抗心肌缺血、抗心室肥厚等作用。\",\"yaowupeifang\":\"①治遗尿，小便涩：防己、葵子、防风各30克。上三味。以水五升，煮取二升半，分三股，散服亦佳。(《千金要方》)\\n\\n　　②治膀胱水蓄胀满，几成水肿：防己6克，车前子、韭菜子、泽泻各9克。水煎服。(《本草切要》)\\n\\n　　③治脚气肿痛：防己、木瓜、牛膝各9克，桂枝1.5克，枳壳3克。水煎服。(《本草切要》)\\n\\n　　④治水膨胀：防己30克、生姜15克。同炒，随入水煎服。半饥时饮之。(《本草汇言》)\\n\\n　　⑤治鼻衄：防己(生用)90克，捣罗为细散。每服6克，新汲水调下。老人小儿酒调3克服。更用热汤调少许、鼻中喘气，佳。(《圣济总录》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:34:32');
INSERT INTO `sys_oper_log` VALUES (182, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于海拔2000米以下的山坡阴湿处、林下或溪旁。分布于山东、安徽、浙江等地。\",\"gongxiao\":\"养阴生津、润肺清心。属补虚药下分类的补阴药。\",\"huaxuezucheng\":\"含多种甾体皂苷，其中麦冬皂苷A含量最高，麦冬皂苷B次之；此外含多种高异黄酮类化合物。从浙麦冬中还分离鉴定出5种黄酮类化合物。另还含麦冬黄酮A、鲁斯可皂昔元、薯蓣皂苷元、麦冬黄烷酮、α-广藿香烯、十六烷酸乙酯、齐墩果酸等。\",\"id\":1,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/130912/1-130912160A34G.jpg\",\"jinji\":\"虚寒泄泻、湿浊中阻、风寒或寒痰咳喘者禁用。\",\"linchuangzuoyong\":\"用量6～12克，煎汤内服；或入丸、散、膏。外用适量，研末调敷；煎汤涂；或鲜品捣汁搽。用治肺燥干咳、吐血、肺痈、虚劳烦热、消渴、热病津伤、咽干口燥、便秘等。\",\"name\":\"麦冬 \",\"otherName\":\"麦门冬、沿阶草、不死药、禹余粮\",\"params\":{},\"source\":\"百合科植物麦冬的块根\",\"xingtai\":\"多年生草本。地下具细长匍匐枝，节上被膜质苞片，须根常有部分膨大成肉质的块根。叶丛生，窄线形，先端钝或锐尖，基部狭窄，叶柄鞘状，两侧有薄膜。总状花序顶生；苞片膜质，每苞腋生1～3花；花淡紫色，偶为白色，形小，略下垂；花被6片，开展，卵圆形；雄蕊6.花丝不明显，较短于花药，花药先端尖；子房半下位，3室。浆果，球状，早期绿色，成熟时深绿色或蓝黑色。花期5～8月，果期7～9月。\",\"xingweiguijing\":\"性微寒，味甘、微苦。归心经、肺经、胃经。\",\"xingzhuang\":\"纺锤形或长圆形，两端略尖，中部充实或略收缩，长1.5～3厘米，直径3～6厘米。表面黄白色或淡黄色，有不规则的纵皱纹。未干透时，质较柔软，干后质硬脆，易折断；折断面黄白色，角质样，中央有细小中柱。气微香，味微甜。\",\"yaoliyanjiu\":\"有保护心血管系统的作用；增强耐缺氧，延长常压缺氧的存活时间；增强免疫功能；降血糖；延缓衰老；抑制胃肠推进作用；抗菌。麦冬为良好的养阴润肺药，近年来发现其在降低血糖的作用较好；临床应用强心作用稳定而效果佳。实验还证明，麦冬中的水溶性多糖有抗缺氧和免疫促进作用。\",\"yaowupeifang\":\"1.治肺燥咳嗽：麦冬15克，桑白皮15克。水煎服。(《新编常用中草药手册》)\\r\\n2.治肺热咳嗽：麦冬12克，北沙参12克，黄芩9克，桔梗9克，杏仁9克，甘草6克。水煎服。(《山东中草药手册》)\\r\\n3.治胃酸缺少：麦冬、石斛、牡荆各6克，糯稻根9克。水煎服。(《福建药物志》)\\r\\n4.治中耳炎：鲜麦冬块根捣烂取汁，滴耳。(《广西本草选编》)\\r\\n5.治小便闭淋：鲜麦冬90克(干品30克)。水煎成半杯，饮前服，2～3次。(《福建民间草药》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:40:18');
INSERT INTO `sys_oper_log` VALUES (183, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"黄精：生于山地林下、灌丛或山坡的半阴处。分布于东北、华北及陕西、宁夏、浙江等地。\\r\\n　　滇黄精：多生于阴湿的山坡林下或灌木丛中。分布云南等地。\\r\\n　　多花黄精：生于山坡林下、草地和灌木林中。分布于广东、江西、湖北、湖南、贵州等地。\",\"gongxiao\":\"补气养阴、健脾、润肺、益肾。属补虚药下分类的补阴药。\",\"huaxuezucheng\":\"黄精含甾体皂苷类成分，如薯蓣皂苷元、毛地黄糖苷、菝葜皂苷元等；黄酮类成分有芹菜黄素等。总糖含量为26.78%～46.40%，总蒽醌含量为0.0726%～0.128%。另含吖丁啶羧酸、天门冬氨酸、高丝氨酸牡荆素木糖苷、异甘草素玻、丁香脂素、14α-羟基西伯利亚蓼苷A、滇黄精苷A等。\",\"id\":2,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/131126/1-131126111426202.jpg\",\"jinji\":\"中寒泄泻，痰湿痞满气滞者忌服。\",\"linchuangzuoyong\":\"用量9～15克，煎服，鲜品30～60克；或入丸、散，熬膏。外用：适量，煎汤洗；熬膏涂；或浸酒搽。用治脾胃虚弱、体倦乏力、口干食少、肺虚燥咳、精血不足、内热消渴。\",\"name\":\"黄精\",\"otherName\":\"甜黄精、姜形黄精等\",\"params\":{},\"source\":\"百合科植物黄精的根茎\",\"xingtai\":\"黄精：多年生草本，高50～90厘米。根茎横走，圆柱状，结节膨大。叶轮生，无柄，每轮4～6片；叶片条状披针形，长8～15厘米，宽0.4～1.6厘米，先端卷曲。花腋生，2～4朵成伞形花丛，总花梗长1～2厘米；花被筒状，白色至淡黄色，全长0.9～1.3厘米，裂片6，披针形；雄蕊6枚，花丝短为子房长1.5～2倍。浆果球形，成熟时紫黑色。花期5～6月，果期7～9月。\\r\\n　　滇黄精：茎高1～3厘米，顶端常作缠绕状。叶轮生，每轮4～8枚，叶线形至线状披针形，长6～20厘米，宽0.3～3厘米，先端渐尖并拳卷。花梗2～3朵，不成伞形，花被粉红色，长1.8～2.5厘米。浆果成熟时红色。\\r\\n　　多花黄精：多年生草本。根茎肥厚，常结节成块；地上茎圆柱形，中空，不分枝。叶互生，椭圆形、卵状披针形至长圆状披针形，有叶脉5～7条，两面光滑无毛，无叶柄。花腋生，2～7朵排成伞形花序或单生；总花梗下垂；花被黄绿色，管状，裂片6；雄蕊6枚；花丝稍扁，具小乳突或细柔毛，上端稍膨大至囊状突起；子房上位，3室。浆果球形，成熟时蓝黑色。花期5～6月。\",\"xingweiguijing\":\"性平，味甘。归肺经、脾经、肾经\",\"xingzhuang\":\"鸡头黄精：呈结节状弯柱形，长3～10厘米，直径0.5～1.5厘米。结节长2～4厘米，略呈圆锥形，常有分枝；表面黄白色或灰黄色，半透明，有纵皱纹，茎痕圆形，直径5～8毫米。\\r\\n　　大黄精：根茎呈肥厚肉质的结节块状，结节长可达10厘米以上，宽3～6厘米，厚2～3厘米。表面淡黄色至黄棕色，具环节，有皱纹及须根痕，结节上侧茎痕呈圆盘状，周周凹入，中部突出。质硬而韧，不易折断，断面角质，淡黄色至黄棕色。气微，味甜，嚼之有黏性。\\r\\n　　姜形黄精：长条结节块状，长短不等，常数个块状结节相连。表面灰黄色或黄褐色，粗糙，结节上侧有突出的圆盘状茎痕，直径0.8～1.5厘米。味苦者不可药用。\",\"yaoliyanjiu\":\"黄精能增加冠脉流量、调血脂、降血糖、抗衰老和增强免疫。黄精粗多糖具免疫调节的功效与作用，对化学性肝损伤具保护作用，另具抗炎和抗病毒作用。此外，还具抑菌、抗病原微生物、降压、止血等作用。现代临床用治冠心病、高脂血症、糖尿病、白细胞减少症、肺结核、慢性肝炎、脑力及睡眠不足、头痛、阳痿及癣菌病等。\",\"yaowupeifang\":\"1.治足癣、体癣：黄精30克，丁香10克，百部10克。煎水外洗。(《新编常用中草药手册》)\\r\\n2.治神经性皮炎：黄精适量，切片，九蒸九晒。早晚嚼服，每次15～30克。(《湖北中草药志》)\\r\\n3.治病后体虚，面黄肌瘦，疲乏无力：黄精12克，党参、当归、枸杞子各9克。水煎服。(《宁夏中草药手册》)\\r\\n4.治神经衰弱，失眠：黄精15克，野蔷薇果9克，生甘草6克。水煎服。(《新疆中草药》)\\r\\n5.治阴血不足，大便秘结：黄精、火麻仁、玄参各15克，当归、肉苁蓉各9克，熟地黄12克。水煎服。(《湖北中草药志》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:43:15');
INSERT INTO `sys_oper_log` VALUES (184, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于山脚阳处、溪边、路旁及灌木丛中。分布于广东、贵州、广西、河南、江苏等地。\",\"gongxiao\":\"解毒、消痈、润肠通便。属泻下药下分类的润下药。\",\"huaxuezucheng\":\"何首乌含蒽醌类化合物，其中大黄素-8-0-B-D-葡萄糖苷是何首乌中促智的活性成分之一；醌类成分二苯乙烯苷2，3，5，4-四羟基二苯乙烯一2-0-B-D-葡萄糖苷具有广泛的心血管活性、免疫调节、保肝作用等，酰胺化合物有穆坪马兜酰胺、N-反式阿魏酰基-3-甲基多巴胺等；色原酮类有7一羟基.2，5.二甲基色原酮等；以二苯乙烯苷，为抗衰老、降血脂的活性成分。另含的2，3，5，4-四羟基二苯乙烯-2-0-(6”-O-a-D-吡喃葡萄糖)-B-D-葡萄糖苷具抑制血管平滑肌细胞增殖活性作用。另含芦荟大黄素、大黄酚、大黄酚葸酮、大黄素、大黄素甲醚、大黄酸、云杉新苷等。\",\"id\":3,\"imageurl\":\"https://upload.wikimedia.org/wikipedia/commons/thumb/d/d6/PolygonumMultiflorum.jpg/220px-PolygonumMultiflorum.jpg\",\"jinji\":\"大便清泄及有湿痰者不宜，忌铁器。\",\"linchuangzuoyong\":\"用量6～12克，煎服。用治瘰疬疮痈、风疹瘙痒、肠燥便秘、高血脂。\",\"name\":\"何首乌\",\"otherName\":\"首乌、赤首乌、夜交藤根、生何首乌、地精等\",\"params\":{},\"source\":\"蓼科植物何首乌的块根。\",\"xingtai\":\"多年生缠绕草本。块根肥大，外表红褐色至暗褐色。茎多分枝，下部稍木质化，上部较细，有时呈淡红色，具纵条纹，中空。叶互生，具长柄，卵状心形，先端渐尖，基部心形或近心形，全缘，两面较粗糙，无毛。托叶鞘状，膜质，无缘毛，常早落。花序圆锥状，顶生或腋生，开展；苞片卵形，中部绿色，边缘膜质透明，无毛；苞片内生白色小花2～4朵，花被片5，不等大，结果时外轮3片增大、肥厚，背部生宽翅，翅下延至花梗节处；雄蕊8枚，短于花被片；花柱3枚，柱头头状。瘦果三棱形，黑色，具光泽。花期10月，果期11月。\",\"xingweiguijing\":\"性温，味苦、甘、涩。归肝经、肾经、心经。\",\"xingzhuang\":\"何首乌呈团块状或不规则纺锤形。表面红棕色或红褐色，皱缩不平，有浅沟，并有横长皮孔及细根痕。体重，质坚实，不易折断，断面浅黄棕色或浅红棕色，显粉性，皮部有4～11个类圆形异型维管束环列，形成云锦状花纹，中央木部较大，有的呈木心。气微，味微苦而甘涩。\",\"yaoliyanjiu\":\"何首乌具抗衰老、增强免疫、促进肾上腺皮质的功效与作用。能促进血细胞新生和发育、调节血脂和抗动脉粥样硬化，并具保肝作用。抗动脉粥样硬化；延缓衰老；可增加离体兔心的冠脉血流量，可拮抗脑垂体后叶素引起的心率减慢，但对脑垂体后叶素引起的心律失常无拮抗作用；抗菌。\",\"yaowupeifang\":\"1.治疟疾：何首乌20克，甘草2克，小儿酌减。每日1剂，浓煎2小时，分3次食前服用，连用2天。[《广东医学·祖国医学版》1964，(4)：31]\\r\\n2.治遍身疮肿痒痛：防风、苦参、何首乌、薄荷各等分。上为粗末，每用药15克，水、酒各一半，共用一斗六升，煎十沸，热洗，于避风处睡一觉。(《外科精要》何首乌散)\\r\\n3.治大肠风毒，泻血不止：何首乌60克，捣细罗为散。每于食前，以温粥饮调下3克。(《圣惠方》)\\r\\n4.治自汗不止：何首乌末，津调，封脐中。(《濒湖集简方》)\\r\\n5.治破伤血出：何首乌末敷之即止。(《卫生杂志》)\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ChinesemedicineMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ChinesemedicineMapper.updateChinesemedicine-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update chinesemedicine          SET name = ?,             imageURL = ?,             other_name = ?,             source = ?,             xingtai = ?,             chandi = ?,             xingzhuang = ?,             xingweiguijing = ?,             gongxiao = ?,             linchuangzuoyong = ?,             yaoliyanjiu = ?,             huaxuezucheng = ?,             jinji = ?,             yaowupeifang = ?          where id = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 22:44:27');
INSERT INTO `sys_oper_log` VALUES (185, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于山脚阳处、溪边、路旁及灌木丛中。分布于广东、贵州、广西、河南、江苏等地。\",\"gongxiao\":\"解毒、消痈、润肠通便。属泻下药下分类的润下药。\",\"huaxuezucheng\":\"何首乌含蒽醌类化合物，其中大黄素-8-0-B-D-葡萄糖苷是何首乌中促智的活性成分之一；醌类成分二苯乙烯苷2，3，5，4-四羟基二苯乙烯一2-0-B-D-葡萄糖苷具有广泛的心血管活性、免疫调节、保肝作用等，酰胺化合物有穆坪马兜酰胺、N-反式阿魏酰基-3-甲基多巴胺等；色原酮类有7一羟基.2，5.二甲基色原酮等；以二苯乙烯苷，为抗衰老、降血脂的活性成分。另含的2，3，5，4-四羟基二苯乙烯-2-0-(6”-O-a-D-吡喃葡萄糖)-B-D-葡萄糖苷具抑制血管平滑肌细胞增殖活性作用。另含芦荟大黄素、大黄酚、大黄酚葸酮、大黄素、大黄素甲醚、大黄酸、云杉新苷等。\",\"id\":3,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/131112/1-131112152520391.jpg\",\"jinji\":\"大便清泄及有湿痰者不宜，忌铁器。\",\"linchuangzuoyong\":\"用量6～12克，煎服。用治瘰疬疮痈、风疹瘙痒、肠燥便秘、高血脂。\",\"name\":\"何首乌\",\"otherName\":\"首乌、赤首乌、夜交藤根、生何首乌、地精等\",\"params\":{},\"source\":\"蓼科植物何首乌的块根。\",\"xingtai\":\"多年生缠绕草本。块根肥大，外表红褐色至暗褐色。茎多分枝，下部稍木质化，上部较细，有时呈淡红色，具纵条纹，中空。叶互生，具长柄，卵状心形，先端渐尖，基部心形或近心形，全缘，两面较粗糙，无毛。托叶鞘状，膜质，无缘毛，常早落。花序圆锥状，顶生或腋生，开展；苞片卵形，中部绿色，边缘膜质透明，无毛；苞片内生白色小花2～4朵，花被片5，不等大，结果时外轮3片增大、肥厚，背部生宽翅，翅下延至花梗节处；雄蕊8枚，短于花被片；花柱3枚，柱头头状。瘦果三棱形，黑色，具光泽。花期10月，果期11月。\",\"xingweiguijing\":\"性温，味苦、甘、涩。归肝经、肾经、心经。\",\"xingzhuang\":\"何首乌呈团块状或不规则纺锤形。表面红棕色或红褐色，皱缩不平，有浅沟，并有横长皮孔及细根痕。体重，质坚实，不易折断，断面浅黄棕色或浅红棕色，显粉性，皮部有4～11个类圆形异型维管束环列，形成云锦状花纹，中央木部较大，有的呈木心。气微，味微苦而甘涩。\",\"yaoliyanjiu\":\"何首乌具抗衰老、增强免疫、促进肾上腺皮质的功效与作用。能促进血细胞新生和发育、调节血脂和抗动脉粥样硬化，并具保肝作用。抗动脉粥样硬化；延缓衰老；可增加离体兔心的冠脉血流量，可拮抗脑垂体后叶素引起的心率减慢，但对脑垂体后叶素引起的心律失常无拮抗作用；抗菌。\",\"yaowupeifang\":\"1.治疟疾：何首乌20克，甘草2克，小儿酌减。每日1剂，浓煎2小时，分3次食前服用，连用2天。[《广东医学·祖国医学版》1964，(4)：31]\\r\\n2.治遍身疮肿痒痛：防风、苦参、何首乌、薄荷各等分。上为粗末，每用药15克，水、酒各一半，共用一斗六升，煎十沸，热洗，于避风处睡一觉。(《外科精要》何首乌散)\\r\\n3.治大肠风毒，泻血不止：何首乌60克，捣细罗为散。每于食前，以温粥饮调下3克。(《圣惠方》)\\r\\n4.治自汗不止：何首乌末，津调，封脐中。(《濒湖集简方》)\\r\\n5.治破伤血出：何首乌末敷之即止。(《卫生杂志》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:45:20');
INSERT INTO `sys_oper_log` VALUES (186, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于海拔1800～2500米高寒阴湿地方。栽培于四川、云南、陕西、贵州，青海、宁夏也有。在甘肃深山老林中曾发现有野生的。\",\"gongxiao\":\"补血活血、调经止痛、润肠通便。属补虚药下属分类的补血药。\",\"huaxuezucheng\":\"当归挥发油中主要成分为藁本内酯、正丁烯基嗼内酯和当归酮等，尚含维生素B12和铁、锌等多种微量元素。另含阿魏酸、苯乙酮、菖蒲二烯、香荆芥酚、愈创木酚、茴香酸、当归内酯、藁本内酯二聚体等。\",\"id\":4,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/131228/1-13122P91A1S9.jpg\",\"jinji\":\"热盛出血患者禁服，湿盛中满及大便溏泄者慎服\",\"linchuangzuoyong\":\"用量6～12克，煎服。用治血虚萎黄、眩晕心悸、月经不调、经闭痛经、虚寒腹痛、肠燥便秘、风湿痹痛、跌扑损伤、痈疽疮疡。\",\"name\":\"当归\",\"otherName\":\"秦归、云归、西当归、干归、马尾归、岷当归。\",\"params\":{},\"source\":\"伞形科植物当归的根。\",\"xingtai\":\"多年生草本。茎直立，带紫色，有明显的纵直槽纹，无毛。叶为2～3回奇数羽状复叶，叶鞘膨大；叶片卵形，小叶3对，近顶端的一对无柄，呈1～2回分裂，裂片边缘有缺刻。复伞形花序，顶生，伞梗10～14，长短不等，基部有2个线形总苞片或缺；小总苞片2～4，线形；每一小伞形花序有花12～36朵，小伞梗密被细柔毛；萼齿5，细卵形；花瓣5，白色，长卵形，先端狭尖略向内折；雄蕊5枚，花丝内弯；子房下位，花柱基部圆锥形。双悬果椭圆形，分果有果棱5条，背棱线形隆起，侧棱发展成宽而薄的翅，翅边缘淡紫色，背部扁平。花期7月，果期8～9月。\",\"xingweiguijing\":\"性温，味甘、辛。归肝经、心经、脾经。\",\"xingzhuang\":\"略圆柱形，下部有支根3～5条或更多，长15～25厘米。表面黄棕色至棕褐色，具纵皱纹及横长皮孔。根头(归头)直径1.5～4厘米，具环纹，上端圆钝，有紫色或黄绿色的茎及叶鞘的残基；主根(归身)表面凹凸不平；支根(归尾)直径0.3～1厘米，上粗下细，多扭曲，有少数须根痕。质柔韧，断面黄白色或淡黄棕色，皮部厚，有裂隙及多数棕色点状分泌腔，木部色较淡，形成层环黄棕色。有浓郁的香气，味甘、辛、微苦。\",\"yaoliyanjiu\":\"当归有降低血小板聚集及抗血栓的功效与作用；促进造血系统功能；降血脂及抗动脉硬化；抗氧化和清除自由基；增强免疫系统功能；抑制I、Ⅱ、Ⅲ、Ⅳ型变态反应；对子宫具有兴奋及抑制的双向性作用；抑制前列腺增生；抗促性腺激素；抗辐射损伤；抗肿瘤；抗炎镇痛、抗损伤；保肝，利胆，促进消化，抑制胃肠的推动运动；具有抑制神经系统、松弛气管平滑肌、利尿、抑菌等作用。可抑制离体动物的子宫而兴奋整体动物的子宫。藁本内酯对实验动物有平喘作用，对其中枢神经系统有抑制作用。抗贫血作用可能与所含的维生素B12和铁、锌等微量元素有关。\",\"yaowupeifang\":\"1.治月经壅滞，脐腹疼痛：当归、玄胡索各等分。上为粗末。每服9克，加生姜三片，水煎稍热服。(《济阴纲目》玄归散)\\r\\n2.治妇人血崩：当归、白芍、干姜、棕榈，各烧存性，醋汤调，食前服。(《百一选方》)\\r\\n3.治大便不通：当归、白芷等分为末，每服6克，米汤下。(《圣济总录》)\\r\\n4.治产后自汗、盗汗：当归、黄芪各30克，麻黄根15克。上为末，每服9克，水煎服。(《济阴纲目》当归二黄汤)\\r\\n5.治脱骨疽：元参、金银花各90克，当归60克，甘草30克，水煎服。连服10剂。(《验方新编》四妙勇专汤)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:45:50');
INSERT INTO `sys_oper_log` VALUES (187, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"槟榔均为栽培。分布于广东、海南、福建、台湾、广西等地。\",\"gongxiao\":\"驱虫、消积、下气、行水。属驱虫药。\",\"huaxuezucheng\":\"槟榔种子含总生物碱0.3%～0.6%，主要为槟榔碱，及少量的槟榔次碱，去甲基槟榔碱，去甲基槟榔次碱，异去甲基槟榔次碱，槟榔副碱，高槟榔碱、硬脂酸、肉豆蔻酸、左旋表儿茶精、鞣质、原矢车菊素A-1等成分，大多与鞣酸结合形式存在。还含鞣质约15%，内有右旋儿茶精，左旋表儿茶精，原矢车菊素A-1，B-1和B-2以及称为槟榔鞣质A、B的两个系列化合物，这两个系列均系原矢车菊素的二聚体、三聚体、四聚体、五聚体。\",\"id\":5,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/130528/1-13052Q02QX08.jpg\",\"jinji\":\"气虚下陷者禁服。\",\"linchuangzuoyong\":\"槟榔用量3～9克，煎服。用治绦虫、蛔虫、姜片虫病；虫积腹痛、积滞泻痢、里急后重、水肿脚气、疟疾。驱绦虫、姜片虫：30～60克。\",\"name\":\"槟榔\",\"otherName\":\"槟榔子、大腹子、宾门、橄榄子、青仔、洗瘴丹、大腹槟榔、槟榔玉。\",\"params\":{},\"source\":\"棕榈科植物槟榔的成熟种子。\",\"xingtai\":\"常绿乔木。茎干直立，不分枝，叶丛生于茎顶端；羽状复叶，叶轴三菱形，具长叶鞘。花单性同株，肉穗花序生于最下部叶的叶鞘束下，多分枝，成圆锥状，苞片大，佛焰苞状，雄花小而多，无柄，生于分枝的上部，萼片3，极小，花瓣3；雄蕊6枚，退化雄蕊3枚；雌花较大而少，无柄，生于分枝的下部，萼片及花瓣各3，退化雄蕊6枚，子房上位，1室。坚果。\",\"xingweiguijing\":\"味苦、辛，性温。归胃经、大肠经。\",\"xingzhuang\":\"扁球形或圆锥形。表面淡黄棕色或淡红棕色，具稍凹的网状沟纹，底部中心有圆形凹陷的珠孔，其旁有一明显疤痕状种脐。质坚硬，断面可见棕色种皮与白色胚乳相间的大理石花纹。气微，味涩、微苦。\",\"yaoliyanjiu\":\"槟榔有驱虫、兴奋胆碱受体、抗病原微生物、抗高血压、抗癌的功效与作用。\",\"yaowupeifang\":\"1.治诸虫在脏，久不瘥者：槟榔(炮)15克为末。每服6克，以葱、蜜煎汤调服3克。(《圣惠方》)\\r\\n2.治蛔虫攻痛：槟榔60克。酒二盏，煎一盏，匀二次服。(《食物本草》)\\r\\n3.治食积满闷成痰涎呕吐：槟榔、半夏、砂仁、萝卜子、麦芽、干姜、白术各6克。水煎服。(《方脉正宗》)\\r\\n4.治心脾疼：高良姜、槟榔等分(各炒)。上为细末，米饮调下。(《百一选方》)\\r\\n5.治聤耳出脓：槟榔研末吹之。(《鲍氏小儿方》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:46:09');
INSERT INTO `sys_oper_log` VALUES (188, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生活于低潮线附近或浅海泥沙质海底及岩礁上，近江牡蛎及长牡蛎分布于全国沿海各地，大连湾牡蛎分布于辽宁、河北、山东沿海。\",\"gongxiao\":\"重镇安神，潜阳补阴，软坚散结，煅牡蛎收敛固涩。属平肝息风药下属分类的平抑肝阳药。\",\"huaxuezucheng\":\"牡蛎主含碳酸钙80%～95%、磷酸钙及硫酸钙。此外尚含镁、铁、铝、硅等多种无机元素及多种氨基酸，无机元素的种类和含量因品种与产地不同而异。\",\"id\":6,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/140320/1-140320194630206.jpg\",\"jinji\":\"不宜多服久服，以免引起便秘和消化不良。\",\"linchuangzuoyong\":\"9～30克，先煎，外用适量，研末撒或调敷。用治惊悸失眠，眩晕耳鸣、瘰蛎痰核、癥瘕痞块。煅牡蛎用治自汗盗汗、遗精崩带、胃痛泛酸。\",\"name\":\"牡蛎\",\"otherName\":\"左壳、蚝壳、海蛎子壳、蛎蛤、牡蛤、海砺子皮。\",\"params\":{},\"source\":\"牡蛎科动物长牡蛎的贝壳。\",\"xingtai\":\"贝壳左右2片，极不规则，厚而坚硬。左壳较大而凹，固着于海底岩石上；右壳较小而平坦，呈钙化质状。贝壳外表面有多层起伏的鳞片，灰白色、淡黄色、黄褐色至淡紫色，边缘极粗糙。内表面瓷白色，可见深色闭壳肌痕。肉质部可见鳃、心室、心耳及外套膜触手等。\",\"xingweiguijing\":\"性微寒，味咸。归肝经、胆经、肾经。\",\"xingzhuang\":\"牡蛎药材的外形不一，分左右两壳，一般左壳较大而厚。壳外面粗糙不平，内表面光滑、瓷白色。质硬脆，断面层状。味微咸。长牡蛎：呈长片状，背腹缘几乎平行。右壳较小，坚厚鳞片层状或层纹状排列，壳表面较平坦，淡紫色、灰白色或黄褐色。 大连湾牡蛎：呈类三角形，背腹缘呈“八”字形，左壳面鳞片坚厚，右壳面鳞片呈波状的同心性排列。近江牡蛎：多呈类圆形或三角状类圆形，右壳同心性排列的鳞片层层重叠，边缘有时带紫色。\",\"yaoliyanjiu\":\"牡蛎具有镇静、局部麻醉的功效与作用，并能抑制神经肌肉兴奋，抗实验性胃溃疡损伤，及增强免疫功能。\",\"yaowupeifang\":\"1.治风虚汗出，少气：牡蛎(烧为粉)30克，白术30克，防风(去芦头)30克。上件药，捣细罗散，每服不计时候，以温水调下6克。恶风倍防风，少气配白术，汗多出、面肿倍牡蛎。(《圣惠方》牡蛎散)\\r\\n2.治白带：牡蛎粉、艾叶、茴香各30克，糯米半合(炒熟)。上为末，滴水为丸，如梧桐子大。温米饮下，空心，每服五十丸。(《澹寮方》\\r\\n3.治温病下后，大便溏甚，脉仍数者：生牡蛎60克。研细，水八杯，煎服三杯，分温三服。(《温病条辨》一甲煎)\\r\\n4.治大病瘥后，鼻衄：牡蛎3克，石膏1.5克。捣末，酒服方寸匕，日三四。亦可蜜丸如梧桐子大，服之。(《肘后方》)\\r\\n5.治心痛气实者：用单味牡蛎煅为粉，酒调6克服之。(《丹溪心法》)\\r\\n6.治胃酸过多：牡蛎、海螵蛸各15克，浙贝母12克。共研细粉，每服9克，每日3次。(《山东中草药手册》)\\r\\n7.治紫癜风：牡蛎、胆矾各15克。上二味生用为散。用醋调摩患处。(《圣济总录》牡蛎散)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:46:29');
INSERT INTO `sys_oper_log` VALUES (189, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于海拔300～500米的山区。分布于广西、江西、广东等地。\",\"gongxiao\":\"清热润肺、滑肠通便。属清热药下属分类的清热解毒药。\",\"huaxuezucheng\":\"含罗汉果苷Ⅳ、罗汉果苷V、罗汉果苷Ⅶ，该苷甜度为蔗糖的300倍，苷元是葫芦素类化合物。尚含十多种氨基酸、黄酮、罗汉果苷元-3，24-二-氧-β-葡萄糖苷、D-甘露醇、罗汉果二醇苯甲酸酯、山柰酚和大量果糖。种仁含有油，其脂肪酸有癸酸、月桂酸、肉豆蔻酸、棕榈酸、硬脂酸、油酸及亚油酸等。\",\"id\":7,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/140122/1-14012210111b09.jpg\",\"jinji\":\"肺寒及脾胃虚寒者忌服。\",\"linchuangzuoyong\":\"用量9～15克，内服煎汤。用治伤风感冒咳嗽、咽痛失音、暑热口渴、肠燥便秘。\",\"name\":\"罗汉果\",\"otherName\":\"拉汗果、假苦瓜、光果木鳖、金不换。\",\"params\":{},\"source\":\"葫芦科植物罗汉果的成熟果实。\",\"xingtai\":\"多年生攀援草质藤本。长达5米。茎暗紫色，具纵棱，被白色或黄色柔毛及红色腺点；卷须2裂，几达中部。叶互生，叶片心状卵形，膜质，叶柄稍扭曲，被短柔毛。花单性，雌雄异株；雄花为腋生总状花序，被白色柔毛及红色腺毛，花萼漏斗状，5裂，被灰黄色柔毛，裂片先端呈线状长尾，花冠橙黄色，5全裂，先端渐尖，外被黑柔毛，雄蕊3枚，被白色腺毛，花药分离。雌花单生或3～5朵簇生于叶腋或呈短总状花序，子房下位，长卵形，被柔毛，花柱3，柱头2叉，具3个黄色或黑色退化雄蕊。果实圆球形或长圆球形或倒卵形，灰棕色，被柔毛，具10条纵线。种子扁长圆形，淡黄色，边缘具不规则齿状缺刻，中央稍凹入，边缘有放射状沟槽。花期6～8月，果期8～10月。\",\"xingweiguijing\":\"性凉，味甘。归肺经、大肠经\",\"xingzhuang\":\"罗汉果呈卵形、椭圆形或球形，长4.5～8.5厘米，直径3.5～6厘米。表面褐色、黄褐色或绿褐色，有深色斑块及黄色柔毛，有的有6~11条纵纹。顶端有花柱残痕，基部有果梗痕。体轻，质脆，果皮薄，易破。果瓤(中、内果皮)海绵状，浅棕色。种子扁圆形，多数，长约1.5厘米，宽约1.2厘米；浅红色至棕红色，两面中间微凹陷，四周有放射状沟纹，边缘有槽。气微，味甜。\",\"yaoliyanjiu\":\"罗汉果可增强机体的细胞免疫功能；大剂量的罗汉果可能提高脾特异性玫瑰花环形成细胞的比率。\",\"yaowupeifang\":\"1.治喉痛失音：罗汉果1个，切片，水煎，待冷后，频频饮服。(《食物中药与便方》)\\r\\n2.治肺燥咳嗽痰多，咽干口燥：罗汉果半个，陈皮6克，瘦猪肉100克。先将陈皮浸，刮去白，然后与罗汉果、瘦肉共煮汤，熟后去罗汉果、陈皮，饮汤食肉。(《新中医》1982，(11)：45)\\r\\n3.治急、慢性支气管炎，扁桃体炎，咽喉炎，便秘：罗汉果15～30克，开水泡，当茶饮。(《全国中草药汇编》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:46:53');
INSERT INTO `sys_oper_log` VALUES (190, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于沟谷或林下阴湿处。我国多栽培于疏林或阴棚下。原产于印度尼西亚。现我国海南有栽培。\",\"gongxiao\":\"化湿消痞、行气温中、开胃消食。属化湿药。\",\"huaxuezucheng\":\"豆蔻主含挥发油，另含桉油精、a-蒎烯、p-蒎烯、樟脑、月桂烯、丁香烯等。\",\"id\":8,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/131101/1-13110111221EJ.jpg\",\"jinji\":\"阴虚血燥者禁服。\",\"linchuangzuoyong\":\"用量3～6克，入煎剂宜后下；或入丸、散。用治湿浊中阻、不思饮食、湿温初起、胸闷不饥、寒湿呕逆、胸腹胀痛、食积不消。\",\"name\":\"豆蔻\",\"otherName\":\"白豆蔻、白蔻、圆豆蔻、白蔻仁、多骨、壳蔻、扣米。\",\"params\":{},\"source\":\"姜科植物白豆蔻的成熟果实。\",\"xingtai\":\"多年生丛生草本。根茎匍匐，粗壮。叶2列，叶鞘边缘纸质或膜质，无毛；叶舌先端圆形，无毛；几无叶柄；叶片披针形，先端尾尖，基部楔形，两面无毛。花序从根茎上抽出，常半掩于土中；花序倒卵形至倒锥形，土黄色，先端圆形至平截；苞片椭圆形，纸质，边缘较薄，有疏长柔毛，表面有内凹的纵细脉10～15条，先端钝；花着生于苞腋；小苞片白色，管状；萼管状，白色，外被微毛，先端3齿裂；花冠管较萼管略长，白色，狭椭圆形；唇瓣长圆形至倒卵形，白色，先端圆形或近平截，中肋略加厚，先端常呈橘黄色；侧生退化雄蕊，钻状；花丝宽而有沟，药隔附属物3裂；蜜腺2，半圆柱形；子房下位，被毛。蒴果土黄色或间有棕红色，近球形，有3棱，被柔毛，先端钝尖，花被宿存。种子多角形，棕红色，芳香。花期全年，盛花期4～6月，果期7～8月。\",\"xingweiguijing\":\"性温，味辛。归脾经、胃经。\",\"xingzhuang\":\"类球形。表面黄白色至淡黄棕色，有较深的纵向槽纹，顶端有突起的花柱基，基部有凹下的果柄痕，两端均具有浅棕色茸毛。果皮体轻，质脆，易纵向裂开。种子呈不规则多面体，背面略隆起，表面暗棕色，有皱纹，并被有残留的假种皮。气芳香，味辛凉略似樟脑。印尼白蔻个略小，表面黄白色，有的微显紫棕色，果皮较薄，种子瘦瘪，气味较弱。\",\"yaoliyanjiu\":\"豆蔻对豚鼠实验性结核能增强小剂量双氢链霉素的治疗作用。\",\"yaowupeifang\":\"1.治胃腹胀满，呕吐：白豆蔻3克，藿香6克，半夏、陈皮各4.5克，生姜6克。水煎服。(《全国中草药汇编》)\\r\\n2.治胃冷久呃：沉香、白豆蔻、苏叶各3克，上共为末。每服2.1克，柿蒂汤下。(《寿世秘典》)\\r\\n3.治妊娠呕吐：白豆蔻3克，竹茹9克，大枣3枚。将生姜捣碎取汁，取3药煎取1茶杯( 50～60毫升)，过滤，冲姜汁服。[《武汉医药卫生》1959，(3)：288]\\r\\n4.治产后呃逆：白豆蔻、丁香各15克。研细。桃仁汤服3克，少顷再服。(《乾坤秘韫》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:47:12');
INSERT INTO `sys_oper_log` VALUES (191, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"蒙古黄芪生于向阳草地及山坡；膜荚黄芪生于林缘、灌丛、林间草地及疏林下。分布于黑龙江、吉林、辽宁、河北、内蒙古等地。\",\"gongxiao\":\"补气升阳，固表止汗，利水消肿，生津养血，行滞通痹，托毒排脓，敛疮生肌。属补虚药下属分类的补气药。\",\"huaxuezucheng\":\"黄芪主要含黄芪甲苷、黄芪苷、毛蕊异黄酮葡萄糖苷、毛蕊异黄酮、异黄芪苷Ⅰ、异黄芪苷Ⅱ、三萜皂苷、黄酮及多糖等成分。\",\"id\":9,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/130717/1-130GG5220W54.jpg\",\"jinji\":\"表实邪盛、湿阻气滞、肠胃积滞、阴虚阳亢、痈疽初起或溃后热毒尚盛者，均禁服。\",\"linchuangzuoyong\":\"用量9～30克，煎汤内服；或入丸、散、膏剂。治疗气短心悸、乏力、虚脱、自汗、盗汗、体虚浮肿、慢性肾炎、久泻、脱肛、子宫脱垂、痈疽难溃、疮口久不愈合、小儿支气管哮喘、慢性乙型肝炎、慢性肾炎和病毒性心肌炎。补气宜炙用，止汗、利尿、托毒排脓生肌宜生用。\",\"name\":\"黄芪\",\"otherName\":\"黄耆、木耆、绵黄芪、王孙、箭芪、戴糁、戴椹、独椹、芰草、蜀脂、百本、百药绵、独根。\",\"params\":{},\"source\":\"豆科植物蒙古黄的根。\",\"xingtai\":\"蒙古黄芪：多年生草本。主根长而粗壮，条较顺直。奇数羽状复叶，小叶12～18对，小叶片下面被柔毛。总状花序腋生，花冠黄色至淡黄色，雄蕊10枚，二体。荚果膨胀，无毛。膜荚黄芪：形态上和上种极相似，主要区别为小叶6～13对，小叶片卵状披针形或椭圆形，长7～30毫米，宽4～10毫米；花冠淡黄色，长不及2厘米，子房被疏柔毛。荚果卵状长圆形，长2～2.5厘米，先端有喙，被黑色短毛。\",\"xingweiguijing\":\"性微温，味甘。归脾经、肺经。\",\"xingzhuang\":\"蒙古黄芪：表面灰黄色，栓皮不易脱落。质硬而韧，断面纤维性并显粉性。皮部黄白色，木部淡黄色。气微，味微甜，有豆腥味。膜荚黄芪：表面灰黄色、黄棕色，质硬，较难折断。\",\"yaoliyanjiu\":\"黄芪对核酸代谢有促进的功效与作用；增强造血功能；改善心肌功能，对抗心肌梗死；具有抗氧化、抗病毒、抗癌、改善肾功能和肾组织病理改变等。水煎剂具调节免疫、抗衰老和抗应激作用。毒性：煎剂LDso为(40±5)克/千克。\",\"yaowupeifang\":\"1.治表虚自汗：防风30克，黄芪(蜜炙)、白术各60克。每服9克，水一钟半，加大枣一枚，煎至七分，去滓，食后热服：(《医方类聚》引《究原方》玉屏风散)\\r\\n2.治气虚阳弱，虚汗不止，肢体倦怠：黄芪(去芦，蜜炙)、附子(炮，去皮、脐)各等分。每服12克，水二盏，生姜片、煎至八分，去滓，食前温服，不拘时候。(《严氏济生方》芪附汤)\\r\\n3.治吐血不止：黄芪7.5克，紫背浮萍15克。为末。每服3克，姜蜜水下。(《圣济总录》)\\r\\n4.治肠风泻血：黄芪、黄连等分。为末、面糊丸如绿豆大。每服三十丸，米饮下。(《传家秘宝》)\\r\\n5.治尿血、砂淋，痛不可忍：黄芪、人参等分。为末，以大萝卜一个，切一指厚大四五片，蜜60克，淹炙令尽，不令焦，点末。食无时，以盐汤下。(《永类钤方》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:47:37');
INSERT INTO `sys_oper_log` VALUES (192, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '36.7.106.41', 'XX XX', '{\"chandi\":\"生于平地、丘陵土岭的疏林酸性黄壤土或荒山中，有栽培。分布于广东、海南、广西、台湾等地。\",\"gongxiao\":\"行气止痛、温中止呕、纳气平喘。属理气药。\",\"huaxuezucheng\":\"沉香含挥发油及树脂。挥发油中主要成分为沉香螺醇、白木香酸、白木香醛、白木香醇、去氢白木香醇、白木香呋喃醛、白木香呋喃醇、α-沉香呋喃、β-沉香呋喃、茴香酸等成分；受曲霉菌感染的沉香挥发油中含沉香螺萜醇、沉香螺萜醛等。\",\"id\":10,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/130324/1-130324194102209.jpg\",\"jinji\":\"阴虚火旺或气虚下陷者慎用。\",\"linchuangzuoyong\":\"研末冲服，用量1.5～4.5克。亦可用原药磨汁服。入煎剂宜后下。用治胸腹胀闷疼痛、胃寒呕吐呃逆、肾虚气逆喘急。\",\"name\":\"沉香\",\"otherName\":\"白木香、土沉香、女儿香、蜜香、栈香、觉水香、奇南香、伽南香。\",\"params\":{},\"source\":\"瑞香科植物白木香含有树脂的木材。\",\"xingtai\":\"常绿大乔木，高达15米，有香气。树皮灰褐色，幼枝被柔毛。叶互生；叶片革质，长卵形、倒长卵形或椭圆形，先端渐尖，有光泽，基部楔形，全缘，下面及叶柄被伏贴茸毛，后渐无毛。伞形花序顶生和腋生，总花梗、小花梗均被灰白色茸毛；花黄绿色，被茸毛；花被钟形，花被管先端5裂，裂片长圆形，花被管喉部有鳞片10片，密被白色茸毛；雄蕊10枚，着生于花被管喉部，花丝极短或无；子房上位，卵形。蒴果木质，扁倒卵形，下垂，密被灰色毛，花被宿存。种子1粒，基部有角状附属体。花期3～5月，果期5～6月。\",\"xingweiguijing\":\"味辛、苦，性微温。归肾经、脾经、胃经。\",\"xingzhuang\":\"沉香药材呈不规则块、片状或盔帽状，有的为小碎块。表面凹凸不平，有刀痕，偶有孔洞，可见黑褐色树脂与黄白色木部相间的斑纹，孔洞及凹窝表面多呈朽木状。质较坚实，断面刺状。气芳香，味苦。\",\"yaoliyanjiu\":\"沉香可解除肠平滑肌痉挛，抑制中枢神经系统等。沉香水煎液对离体豚鼠回肠的自主收缩有抑制的功效与作用，并能对抗组胺、乙酰胆碱引起的痉挛性收缩。醇提物能促进离体豚鼠气管抗组胺作用，从而发挥止喘效果。此外，具解痉、镇静、镇痛、降压、抗菌的作用。\",\"yaowupeifang\":\"1.治腹胀气喘，坐卧不安：沉香、枳壳各15克，萝卜子炒30克，每服15克，姜三片，水煎服。(《赤水玄珠》沉香饮)\\r\\n2.治冷痰虚热，诸劳寒热：沉香、附子(炮)。上口咀，煎露一宿，空心服。(《澹寮集验方》冷香汤)\\r\\n3.治一切哮症：沉香60克，莱菔子(淘净，蒸熟，晒干)150克，上为细末，生姜汁为细丸。每服八分，白滚汤送下。(《丹台玉案》二仙丹)\\r\\n4.治胃冷久呃：沉香、紫苏、白豆蔻各3克。为末。每服1.5～2.1克，柿蒂汤下。(《活人心统》)\\r\\n5.治心神不定，恍惚不乐，火不下降，时有振跳，消阴养火，全心气：茯神(去皮)60克，沉香15克。并为细末，炼蜜丸如小豆大。每服三十丸，食后人参汤下，甚妙。(《百一选方》朱雀丸)\\r\\n6.治胞转不通，或过忍小便所致，当治其气则愈，非利药可通也：沉香、木香各6克为末。白汤空腹服之，以通为度。(《医垒元戎》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 22:48:33');
INSERT INTO `sys_oper_log` VALUES (193, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"人参生于山地的针、阔叶混交林或杂木林下。分布于长白山脉和小兴安岭东南部的山林地带，辽宁、吉林、黑龙江等地有大量栽培。\",\"gongxiao\":\"大补元气、复脉固脱、补脾益肺、生津安神。属补虚药下分类的补气药。\",\"huaxuezucheng\":\"含人参皂苷，其中达玛烷系三萜皂苷活性最显著，为评定人参质量的主要指标，其中主要有人参皂苷Rb₁、人参皂苷Re、人参皂苷Rf及人参皂苷Rg₁等。\",\"id\":11,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/131118/1-13111Q51I3F2.jpg\",\"jinji\":\"实热证、湿热证及正气不虚者禁服。不宜与茶同服。不宜与藜芦、五灵脂同用。\",\"linchuangzuoyong\":\"用量每天3～9克，另煎对入汤剂服；野山参若研粉吞服，一次2克，一天2次。治疗体虚欲脱、气短喘促、自汗肢冷、精神倦怠、食少吐泻、气虚作喘或久咳、津亏口渴、消渴、失眠多梦、惊悸健忘、阳痿、尿频、一切气血津液不足之症。\",\"name\":\"人参\",\"otherName\":\"神草、吉林参、棒槌、土精、黄参、血参、地精、金井玉阑、孩儿参。\",\"params\":{},\"source\":\"五加科植物人参的根。\",\"xingtai\":\"多年生草本。根茎短，直立，每年增生一节，通称“芦头”，有时其上生一至数条不定根(芋)。主根粗壮，肉质，圆柱形或纺锤形。掌状复叶轮生茎端，复叶有长柄，小叶片多为5枚，边缘有细锯齿，上面沿脉有稀疏刚毛。伞形花序顶生。核果。种子2粒。\",\"xingweiguijing\":\"性温，味甘、微苦。归心经、肺经、脾经、肾经。\",\"xingzhuang\":\"生晒参：主根呈纺锤形或圆柱形。表面灰黄色，上部或全体有疏浅断续的粗横纹及明显的纵皱，须根上常有不明显的细小疣状突起。根茎(芦头)具不定根(芋)和稀疏的凹窝状茎痕(芦碗)。质较硬，断面淡黄白色。香气特异，味微苦、甘。生晒山参：主根粗短，多具2个支根而呈人字形。表面灰黄色，上部有明显的细密螺旋纹，根茎具细密碗状茎痕，靠近主根的一段根茎较光滑无茎痕，称圆芦。支根上生有稀疏细长的须状根。上有明显疣状突起。\",\"yaoliyanjiu\":\"人参对中枢神经系统有双向调节、促智、镇痛、解热、抗惊和肌力减弱等功效与作用。对心血管系统有强心、抗缺血、扩张血管、降压等作用；对血液系统有保护和刺激造血功能，并抗凝血和抗血栓；对内分泌系统有促皮质激素样、促性激素样作用。提高机体免疫功能，强心、抗休克，保护和刺激骨髓的造血功能，增加肾上腺皮质激素分泌，调整血糖水平，显著抑制胆固醇的吸收，抗肿瘤，延缓衰老，加强机体的适应性，其提取物能明显促进大鼠器官核酸和蛋白质的合成。\",\"yaowupeifang\":\"1.大补气血，治一切虚烦：人参末、人乳粉等分。蜜丸，或化或吞俱可。(《冯氏锦囊》参乳丸)\\r\\n2.治脾胃肾气虚弱，呕吐不下食：人参、丁香各等分。捣罗为散，每服6克。空心热米饮调下。(《普济方》参散)\\r\\n3.治营卫气血不足：人参9～30克，黄芪(蜜酒炙)9～18克，炙甘草3克。水煎，空心服。(《张氏医通》保元汤)\\r\\n4.治虚劳白汗不止：人参45克，白术60克，桂心21克。每服15克，水煎服。阳虚甚者加附子。(《赤水玄珠》参术散)\\r\\n5.治小儿惊热盗汗：人参3克，黄芪6克，当归4.5克。加猪心一片。水煎服。(《婴童类萃》团参饮子)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:11:17');
INSERT INTO `sys_oper_log` VALUES (194, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"丁香原产于马来西亚、印度尼西亚及东非沿岸国家，现我国有栽培\",\"gongxiao\":\"温中降逆、补肾助阳。属温里药。\",\"huaxuezucheng\":\"含挥发油15%～20%，油中主成分为丁香油酚、β-丁香烯、乙酰基丁香油酚等。另含丁香酚、乙酰丁香酚、异槲皮素、山柰酚、槲皮素、石竹烯氧化物、齐墩果酸、α-衣兰油烯等成分。\",\"id\":12,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/130530/1-13053015424DE.jpg\",\"jinji\":\"热病及阴虚内热者忌服。\",\"linchuangzuoyong\":\"用量1～3克，煎服。用治脾胃虚寒、呃逆呕吐、食少吐泻、心腹冷痛、肾虚阳痿。\",\"name\":\"丁香\",\"otherName\":\"丁子香、公丁香、雄丁香、支解香、瘦香娇、如宇香、百里馨。\",\"params\":{},\"source\":\"桃金娘科植物丁香的花蕾。\",\"xingtai\":\"多年生常绿乔木，高12米。树皮灰白色而光滑。单叶对生，革质，卵状长椭圆形至披针形，先端尖，基部狭呈楔形，全缘，侧脉多，平行状，具多数透明小油点，叶柄明显。花顶生，3朵一组，集成聚伞形圆锥花序；花萼筒状，顶端4裂，裂片呈三角形，肉质肥厚，有油腺；花冠圆头状，花瓣4，白色而现微紫色；雄蕊多数，子房下位，柱头细小。浆果红色或深紫色，卵圆形，内有种子1粒，呈椭圆形。\",\"xingweiguijing\":\"味辛，性温。归胃经、脾经、肾经。\",\"xingzhuang\":\"略研棒状。花冠圆球形，花瓣4，覆瓦状抱合，棕褐色至黄褐色，花瓣内为雄蕊和花柱，搓碎后可见众多黄色细粒状的花药。萼筒圆柱状，略扁，有的稍弯曲，红棕色或棕褐色，上部有4枚三角状的萼片，“十”字形分开。质坚实，富油性。气芳香浓烈，味辛辣，有麻舌感。\",\"yaoliyanjiu\":\"丁香有抗胃溃疡，止泻，利胆，镇痛，抗缺氧，抗凝血，抗突变，抑菌杀虫的功效与作用。丁香还具健胃的功效与作用，浸出液具有明显的刺激胃液分泌作用，并能缓解腹胀、恶心、呕吐等。另外，丁香对多种致病性真菌、球菌、链球菌及肺炎、痢疾、大肠、伤寒等杆菌以及流感病毒有抑制作用。\",\"yaowupeifang\":\"1.治朝食暮吐：丁香十五个。研末。甘蔗汁、姜汁和丸莲子大。噙咽之。(《摘玄方》)\\r\\n2.治久心痛不止：丁香15克，桂心30克。捣细，罗为散，每于食前，以热酒调下3克。(《圣惠方》)\\r\\n3.治冷心疼，面青唇黑，手足厥冷：丁香、良姜、官桂各4.5克。水一碗煎七分，用胡椒二4.治妇人崩中，昼夜不止：丁香60克，酒二升，煎一升，分服。(《梅师方》)\\r\\n5.治乳头裂破：捣丁香末敷之。(《梅师方》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:11:39');
INSERT INTO `sys_oper_log` VALUES (195, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"生于山谷、疏林下阴湿地方，多为栽培。分布于福建、广东、四川，长江流域以南各地均有产。\",\"gongxiao\":\"清热解毒，凉血消肿。属清热药下属中的清热解毒药。\",\"huaxuezucheng\":\"南板蓝根全草含三萜类。靛玉红有抗癌活性-(3H)-喹唑酮有抗炎、抗高血压活性，根含吲哚苷、大黄酚及多种氨基酸。另含靛苷、靛玉红羽扇豆酮、羽扇豆醇、白桦脂醇、β-谷固醇等成分。\",\"id\":13,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/130323/1-130323152I4113.jpg\",\"jinji\":\"脾胃虚寒、无实火热毒者慎用。\",\"linchuangzuoyong\":\"9～15克，煎服。用治温病发斑、丹毒、流感、流脑，临床主要用治病毒性及细菌性疾病，如乙型肝炎、水痘、扁桃体炎、咽炎等。\",\"name\":\"南板蓝根\",\"otherName\":\"广东板蓝根、马蓝根、板蓝根、蓝靛根。\",\"params\":{},\"source\":\"爵床科植物马蓝的根茎及根\",\"xingtai\":\"多年生草本。茎基部稍木质化，多分枝，茎节明显，嫩枝被褐色细软毛。叶对生，叶片倒卵状长圆形至卵状长圆形，先端渐尖，基部渐窄，边缘浅锯齿，侧脉4～8对。穗状花序，着生枝顶；苞片叶状，早落；花萼裂片5，外被短柔毛；花冠筒状漏斗形，淡紫色，花冠筒近中部略向下弯曲，先端5裂；雄蕊4枚，2强；子房上位，花柱细长，被毛。蒴果。\",\"xingweiguijing\":\"味苦，性寒。归心经、胃经。\",\"xingzhuang\":\"南板蓝根的根茎类圆形，多弯曲，有分枝。表面灰棕色，具细纵纹；节膨大，节上长有细根或茎残基；外皮易剥落，呈蓝灰色。质硬而脆，易折断，断面不平坦，皮部蓝灰色，木部灰蓝色至淡黄褐色，中央有髓。根粗细不一，弯曲有分枝，细根细长柔韧。气微，味淡。\",\"yaoliyanjiu\":\"南板蓝根水煎剂具一定的抑菌的功效与作用，体外对病毒增殖有抑制作用，还具解热、抗炎作用。\",\"yaowupeifang\":\"1.治流行性腮腺炎：南板蓝根30克，或配金银花、蒲公英各15克，水煎服;外用鲜马蓝叶捣敷。(《浙南本革新编》)\\r\\n2.治喉痛：南板蓝根30克，开喉箭30克，山豆根30克，马勃9克。煎水服。(《重庆草药》)\\r\\n3.预防小儿喘憋性肺炎：南板蓝根、金银花、一枝黄花，4～7岁各用4.5克，3岁以下各用3克。水煎，每日分3～4次服。(《浙南本草新编》)\\r\\n4.治夏季微热，经久不退：南板蓝根30克，柴胡9克，体虚者加北沙参或孩儿参9克。水煎。每日1剂，连服7～10天。(《浙南本草新编》)\\r\\n5.治热毒疮：南板蓝根30克，银花藤30克，蒲公英30克，土茯苓15克。炖肉服。(《重庆草药》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:12:01');
INSERT INTO `sys_oper_log` VALUES (196, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"各地常见栽培。分布于四川、贵州、广西、广东等地。\",\"gongxiao\":\"平肝舒筋、和胃化湿。属祛风湿药下属分类的祛风湿强筋骨药。\",\"huaxuezucheng\":\"木瓜含苹果酸、酒石酸、柠檬酸、抗坏血酸、反丁烯二酸和皂苷;还含苹果酸钾盐及齐墩果酸、绿原受乙酯、咖啡酸、绿原酸、乌头酸、黄酮和鞣质等。\",\"id\":14,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/140126/1-140126111943O0.jpg\",\"jinji\":\"下部腰膝无力，由于精血虚、真阴不足者不宜用，湿热偏盛，小便淋闭者慎服。\",\"linchuangzuoyong\":\"用量6～9克，煎汤内服，用治湿痹拘挛、腰膝关节酸肿疼痛、吐泻转筋、脚气水肿。用木瓜片5片/次，3次/日治疗急性细菌性痢疾。木瓜冲剂治急性病毒性肝炎；木瓜胶代血浆治出血性休克，又可治风湿性关节炎、脚癣等。\",\"name\":\"木瓜\",\"otherName\":\"光皮木瓜、铁脚梨、秋木瓜、木瓜实、酸木瓜。\",\"params\":{},\"source\":\"蔷薇科植物木瓜的近成熟果实。\",\"xingtai\":\"小乔木或灌木。高可达10米，小枝圆柱形，无刺。单叶互生，叶片革质，椭圆状卵形或长椭圆形；叶柄稀被柔毛，有腺体；托叶膜质，卵状披针形，边缘具腺体。花单生于叶腋；萼钟状，萼片5，三角状披针形，边缘有腺齿，内面密被浅褐色茸毛，反折；花瓣5枚，倒卵形，淡粉红色，雄蕊多数，长不及花瓣之半；花柱3～5，基部合生，柱头头状，与雄蕊等长或稍长。果实长椭圆形，长10～15厘米，暗黄色，木质。花期4月，果期9~10月。\",\"xingweiguijing\":\"性温，味酸。归肝经、脾经。\",\"xingzhuang\":\"】木瓜果实长椭圆形或卵圆形，多纵剖为2～4瓣，长4～9厘米，宽3.5～4.5厘米。外表面红棕色或棕褐色，光滑无皱纹，或稍粗糙；剖面果肉粗糙，显颗粒性。种子多数，密集，每子房室内40～50粒，通常多数脱落。种子扁平三角形，气微，味微酸涩，嚼之有沙粒感。以质坚实、味酸者为佳。\",\"yaoliyanjiu\":\"木瓜有保肝、抗菌、抑制肿瘤的功效与作用。木瓜冲剂对由四氯化碳引起的大鼠急性肝损害有保护作用。体外试验，对多种肠道菌、葡萄球菌等有不同程度的抑制作用。水浸液对小鼠艾氏腹水癌有明显抑制作用，其抗癌有效成分是有机酸。\",\"yaowupeifang\":\"1.治脚气湿热：木瓜、薏苡仁各15克，白术、茯苓各9克，黄柏6克。水煎服。(《青岛中草药手册》)\\r\\n2.治脐下绞痛：木瓜一二片，桑叶七片，大枣三枚(碎之)。以水二升。煮取半升，顿服之。(《孟洗方》)\\r\\n3.治风湿麻木：木瓜泡酒服，每次一小盅，日服二次。(《天津中草药》)\\r\\n4.治泻不止：米豆子60克，木瓜、干姜、甘草各30克。为细末，每服6克，米饮调，不以时。(《鸡峰普济方》木瓜汤)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:12:28');
INSERT INTO `sys_oper_log` VALUES (197, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"全国各地广泛栽培。\",\"gongxiao\":\"解表散寒，行气和胃。属解表药下属分类的辛温解表药。\",\"huaxuezucheng\":\"紫苏叶含紫苏醛、紫苏酮，白苏酮、薄荷醇、高山黄芩苷、新西兰牡荆苷Ⅱ、鹭樱苷等成分。\",\"id\":15,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/160623/1-160H2212025957.jpg\",\"jinji\":\"阴虚、气虚及温病者慎服。\",\"linchuangzuoyong\":\"内服：煎汤，5～10克。外用：适量，捣敷、研末掺或煎汤洗。用于风寒感冒，咳嗽呕恶，妊娠呕吐，鱼蟹中毒。\",\"name\":\"紫苏叶\",\"otherName\":\"苏叶、紫菜、苏。\",\"params\":{},\"source\":\"唇形科植物紫苏的干燥叶(或带嫩枝)。\",\"xingtai\":\"】一年生草本，高30～200厘米。具有特殊芳香。茎直立，多分枝，紫色、绿紫色或绿色，钝四棱形，密被长柔毛。叶对生；叶柄长3～5厘米，紫红色或绿色，被长节毛；叶片阔卵形、卵状圆形或卵状三角形，长4～13厘米，宽2.5～10厘米，先端渐尖或突尖，有时呈短尾状，基部圆形或阔楔形，边缘具粗锯齿，有时锯齿较深或浅裂，两面紫色或仅下面紫色，上下两面均疏生柔毛，沿叶脉处较密，叶下面有细油腺点；侧脉7～8对，位于下部者稍靠近，斜上升。轮伞花序，由2花组成偏向一侧成假总状花序，顶生和腋生，花序密被长柔毛；苞片卵形、卵状三角形或披针形，全缘，具缘毛，外面有腺点，边缘膜质；花梗长1～1.5毫米，密被柔毛；花萼钟状，长约3毫米，10脉，外面下部密被长柔毛和有黄色腺点，顶端5齿，2唇，上唇宽大，有3齿，下唇有2齿，结果时增大，基部呈囊状；花冠唇形，长3～4毫米，白色或紫红色，花冠筒内有毛环，外面被柔毛，上唇微凹，下唇3裂，裂片近圆形，中裂片较大；雄蕊4，二强，着生于花冠筒内中部，几不伸出花冠外，花药2室；花盘在前边膨大；雌蕊1，子房4裂，花柱基底着生，柱头2裂；花盘在前边膨大；雌蕊1，子房4裂，花柱基底着生，柱头2裂。小坚果近球形，灰棕色或褐色，直径1～1.3毫米，有网纹，果萼长约10毫米。花期6～8月，果期7～9月。\",\"xingweiguijing\":\"性温，味辛。归肺经、脾经。\",\"xingzhuang\":\"紫苏叶多皱缩卷曲，破碎，完整叶片展平后呈卵圆形，长6～14厘米，宽3～11厘米。先端长尖或急尖，基部宽楔形，边缘具圆锯齿；两面均为暗绿色，被疏柔毛；叶柄长2.5～8厘米，密被白色毛茸。质脆，气清香，味微辛。\",\"yaoliyanjiu\":\"紫苏叶具有镇静及较弱的解热作用；可使兴奋性膜产生抑制作用；能促进消化液分泌，增强胃肠蠕动；对呼吸系统，可产生止咳祛痰平喘的功效与作用，对血液系统，具有止血和抗凝血双重作用；升高血糖；调节机体免疫功能，具有抗诱变能力；抗微生物，具有广谱的抗菌作用。对腺苷酸环化酶有轻度抑制作用，有很强的黄嘌呤氧化酶抑制作用；有显著抗氧化作用；尚有抗炎作用。\",\"yaowupeifang\":\"1.治伤风发热：紫苏叶、防风、川芎各4.5克，陈皮3克，甘草1.8克。加生姜二片煎服。(《不知医必要》苏叶汤)\\r\\n2.治伤寒不止：紫苏一把，水三升，煮取二升，稍稍饮。(《肘后方》)\\r\\n3.治乳痈肿痛：紫苏煎汤频服，并捣封之。(《海上名方》)\\r\\n4.治恶疮，疥癣：以大苏叶研细，外敷。(《普济方》)\\r\\n5.治跌扑伤损：紫苏捣敷之。疮口自合。(《谈野翁试验方》)\\r\\n6.治蛇虺伤人：紫苏捣汁饮之。(《千金要方》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:12:54');
INSERT INTO `sys_oper_log` VALUES (198, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"生于山坡杂木林下，常缠绕在其他植物上。分布于黑龙江、吉林、辽宁、河北、山西、内蒙古、陕西，主产于黑龙江、吉林、辽宁。\",\"gongxiao\":\"性温，味酸、甘。归肺经、心经、肾经。\",\"huaxuezucheng\":\"五味子有促进机体免疫功能与作用；抗氧化及抗衰老；护肝、诱导肝脏药物代谢酶；镇咳祛痰，抗肿瘤；降血糖；强心；增强机体适应能力；抗溃疡；抗肾病变；抗菌等作用。据报导，五味子煎剂静脉注射，对正常兔子都有呼吸兴奋作用，使吸收加深、加快，并能对抗吗啡的呼吸抑制作用，酊剂亦有同样效果。\",\"id\":16,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/140524/1-140524104ZA52.jpg\",\"jinji\":\"外有表邪，内有实热，或咳嗽初起、痧疹初发者忌服。\",\"linchuangzuoyong\":\"收敛固涩、益气生津、补肾宁心。属收涩药分类下的敛肺涩肠药。\",\"name\":\"五味子\",\"otherName\":\"北五味子、玄及、会及、五梅子、山花椒。\",\"params\":{},\"source\":\"为木兰科植物五味子的干燥成熟果实。\",\"xingtai\":\"落叶木质藤本。小枝褐色，有棱角，全株近无毛。单叶，互生，叶柄长2～4.5厘米，叶倒卵形、宽卵形或椭圆形，长5～10厘米，宽3～5厘米，先端急尖或渐尖，基部楔形，边缘有腺状细齿，上面光滑无毛，下面叶脉上嫩时有短柔毛。花单性，雌雄异株，花单生或簇生于叶腋，花梗细长而柔弱，花被6～9片，乳白色或粉红色，雄花有雄蕊5枚，雌花的雌蕊群椭圆形，有17～40个离生的心皮，覆瓦状排列在花托上。开花后期，花托逐渐延长，果熟时成穗状聚合果。浆果，肉质，直径约5毫米，紫红色。种子肾形，淡橙色，有光泽。花期5～6月，果期8～9月。\",\"xingweiguijing\":\"五味子呈不规则的球形或扁球形，直径5～8毫米。表面红色、紫红色或暗红色，皱缩，显油润；有的表面呈黑红色或出现“白霜”。果肉柔软，种子1～2，肾形，表面棕黄色，有光泽，种皮薄而脆。果肉气微，味酸，种子破碎后，有香气，味辛、微苦。\",\"xingzhuang\":\"秋季果实成熟时采摘，晒干或蒸后晒干，除去果梗和杂质。\",\"yaoliyanjiu\":\"用量2～6克，煎汤内服；研末，每次1～3克；熬膏；或入丸、散。外用：适量，研末掺；或煎水洗。用治久嗽虚喘，梦遗滑精，遗尿尿频，久泻不止，自汗盗汗，津伤口渴，内热消渴，心悸失眠。\",\"yaowupeifang\":\"1.治阳痿不起：五味子、菟丝子、蛇床子各等分。上三味末之，蜜丸如梧桐子。饮服三丸，日三。(《千金要方》)\\r\\n2.治滑泄：陈米、肉豆蔻(面裹煨)、五味子、赤石脂(研)各30克。上为末。每服6克，粟米汤饮调下，日进三服。(《世医得效方》豆蔻饮)\\r\\n3.治睡中盗汗：五味子30克，研末，以唾调作饼。敷脐上，以布扎定后睡，候天明取下，一二晚汗即上。(《医方一盘珠》)\\r\\n4.治肺经感寒，咳嗽不已：白茯苓120克，甘草90克，干姜90克，细辛90克，五味子75克。上为细末。每服6克，水一盏，煎至七分，去滓，温服，不以时。(《鸡峰普济方》五味细辛汤)\\r\\n5.治小儿暴嗽：五味子、桂(去粗皮)、干姜(炮)等分。上三味，粗捣筛。每服3克，水七分，煎至四分，去滓，量大小加减温服。(《圣济总录》五味子汤)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:13:53');
INSERT INTO `sys_oper_log` VALUES (199, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"华东、中南、西南及河北、陕西、台湾等地，均有栽培。\",\"gongxiao\":\"清热利湿，凉血解毒。属清热药下分类的清热凉血药。\",\"huaxuezucheng\":\"木槿花含叶黄素-5,6-环氧化物、隐黄质、菊黄素、花旗松素-3-O-β-D-吡喃葡萄糖苷、飞燕草素-3-O-葡萄糖苷等成分。\",\"id\":17,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/141218/1-150F1113K44J.jpg\",\"jinji\":\"尚不明确。\",\"linchuangzuoyong\":\"内服：煎汤，用量3～9克，鲜者30～60克。外用：适量，研末或鲜品捣烂调敷。主治肠风泻血，赤白下痢，痔疮出血，肺热咳嗽，咯血，白带，疮疖痈肿，烫伤。\",\"name\":\"木槿花\",\"otherName\":\"篱障花、碗盖花、木红花。\",\"params\":{},\"source\":\"锦葵科植物木槿的干燥花。\",\"xingtai\":\"落叶灌木，高3～4米。小枝密被黄色星状绒毛。叶互生，叶柄长5～25毫米，被星状柔毛；托叶线形，长约6毫米，疏被柔毛；叶片菱形至三角状卵形，长3～10厘米，宽2～4厘米，具深浅不同的3裂或不裂，先端钝，基部楔形，边缘具不整齐齿缺，下面沿叶脉微被毛或近无毛，花单生于枝端叶腋问，花梗长4～14毫米，被星状短绒毛；小苞片6～8，线形，长6～15毫米，宽1～2毫米，密被星状疏绒毛；花萼钟形，长14～20毫米，密被星状短绒毛，裂片5，三角形；花钟形，淡紫色，直径5～6厘米，花瓣倒卵形，长3.5～4.5厘米，外面疏被纤毛和星状长柔毛，雄蕊柱长约3厘米；花柱枝无毛。蒴果卵圆形，直径约12毫米，密被黄色星状绒毛。种子肾形，背部被黄色长柔毛。花期7～10月。\",\"xingweiguijing\":\"性凉，味甘、苦。归脾经、肺经、肝经\",\"xingzhuang\":\"本品多皱缩成团或不规则形，长2～4厘米，宽1～2厘米，全体被毛。花萼钟形，黄绿色或黄色，先端5裂，裂片三角形，萼筒外方有苞片6～7，条形，萼筒下常带花梗，长3～7毫米，花萼、苞片、花梗表面均密被细毛及星状毛；花瓣5片或重瓣，黄白色至黄棕色，基部与雄蕊合生，并密生白色长柔毛；雄蕊多数，花丝下部连合成筒状，包围花柱，柱头5分歧，伸出花丝筒外。质轻脆，气微香，味淡。\",\"yaoliyanjiu\":\"对致病大肠杆菌及痢疾杆菌均无明显作用；可以杀虫止痒，用其洗头洗脸，能够治疗头皮瘙痒；动物试验证明其花粉有致敏作用。\",\"yaowupeifang\":\"1.治下痢噤口：木槿花去蒂，阴干为末，先煎面饼二个，酿末食之。(《济急仙方》)\\r\\n2.治吐血，下血，赤白痢疾：木槿花9～13朵。酌加开水和冰糖炖半小时，饭前服，每日服2次。(《福建民间草药》)\\r\\n3.治咯血：鲜木槿花30克，冰糖15克。水煎服。(《福建药物志》)\\r\\n4.治痔疮出血：木槿花、槐花炭各15克，地榆炭9克。煎服。(《安徽中草药》)\\r\\n5.治妇人白带：木槿花6克(为末)。入人乳半钟，将花末拌于乳内，饭上蒸熟，食之效。(《滇南本草》)\\r\\n6.治湿热白带：木槿花30克，猪瘦肉120克。水炖，食肉喝汤。(《安徽中草药》)\\r\\n7.治白带：木槿花、败酱草、白鸡冠花各15克。每日1剂，水煎，分2次服。(《福建药物志》)\\r\\n8.治疮疖：鲜木槿花，捣烂外敷，干则更换。(《安徽中草药》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:14:19');
INSERT INTO `sys_oper_log` VALUES (200, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"我国中部、东南部至西南部各省广为栽培。\",\"gongxiao\":\"散寒解表，降逆止呕，化痰止咳，解鱼蟹毒。属解表药下属分类的辛温解表药。\",\"huaxuezucheng\":\"生姜含姜醇、α-姜烯、β-水芹烯、柠檬醛、芳香醇、甲基庚烯酮、壬醛、α-龙脑等，尚含辣味成分姜辣素。\",\"id\":19,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/150707/1-150FG5003UA.jpg\",\"jinji\":\"阴虚内热及实热证禁服。\",\"linchuangzuoyong\":\"内服：煎汤，用量3～10克，或捣汁冲服；外用：适量，捣敷，或炒热熨，或绞汁调搽。生姜用于风寒感冒，胃寒呕吐，寒痰咳嗽，鱼蟹中毒。\",\"name\":\"生姜\",\"otherName\":\"母姜、鲜生姜。\",\"params\":{},\"source\":\"姜科植物姜的新鲜根茎。\",\"xingtai\":\"多年生草本，高50～80厘米。根茎肥厚，断面黄白色，有浓厚的辛辣气味。叶互生，排成2列，无柄，几抱茎；叶舌长2～4毫米；叶片披针形至线状披针形， 长1 5～30厘米，宽1.5～2.2厘米，先端渐尖，基部狭，叶基鞘状抱茎，无毛。花葶自根茎中抽出，长15～25厘米；穗状花序椭圆形，长4～5厘米；苞片 卵形，长约2.5厘米，淡绿色，边缘淡黄色，先端有小尖头；花萼管长约1厘米，具3短尖齿；花冠黄绿色，管长2～2.5厘米，裂片3，披针形，长不及 2厘米，唇瓣的中间裂片长圆状倒卵形，较花冠裂片短，有紫色条纹和淡黄色斑点，两侧裂片卵形，黄绿色，具紫色边缘；雄蕊1，暗紫色，花药长约9厘米，药隔 附属体包裹住花柱；子房3室，无毛，花柱1，柱头近球形。蒴果。种子多数，黑色。花期8月。\",\"xingweiguijing\":\"性微温，味辛。归肺经、脾经、胃经。\",\"xingzhuang\":\"生姜根茎呈不规则块状，略扁，具指状分枝，长4～18厘米，厚1～3厘米。表面黄褐色或灰棕色，有环节，分枝顶端有茎痕或芽。质脆，易折断，断面浅黄色，内皮层环纹明显，维管束散在。气香，特异，味辛辣。延伸阅读：生姜的鉴别方法\",\"yaoliyanjiu\":\"生姜有镇静及抗惊厥作用；有解热、镇痛和抗炎作用；松弛胃肠道平滑肌；止吐和抗运动病；兴奋心脏，增强心房收缩力，保护胃黏膜；保肝利胆；抗血小板聚集；抗 5-羟色胺，抗氧化，抗微生物，中枢兴奋，促进体内活性物质释放，促进吸收，止咳，降血脂，抗过敏，诱变和抗诱变，抑制亚硝胺合成。生姜无明显毒性。\",\"yaowupeifang\":\"1.治感冒风寒：生姜5片，紫苏叶30克。水煎服。(《本草汇言》)\\r\\n2.治干呕哕，手足厥冷：橘皮120克，生姜240克。上二味，以水七升，煮取三升，分三服，不止，更合服之。(《千金要方》橘皮汤)\\r\\n3.治反胃，朝食暮吐，暮食朝吐，旋旋吐者：甘蔗汁7升，生姜汁1升。二味相合，分为三服。(《梅师集验方》)\\r\\n4.治霍乱欲吐不吐，欲泻不泻：盐30克，生姜15克，捣碎，同炒令色变。以水一碗，煎服，甚者加童便一盏。(《赤水玄珠》姜盐饮)\\r\\n5.治腰痛：生姜1斤，捣汁120克，水胶30克，同煎成膏。厚纸摊贴腰眼敷甚效。(《串雅内编》贴腰膏)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:27:00');
INSERT INTO `sys_oper_log` VALUES (201, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"性情温顺，以麦秸、谷草为食。我国北方地区均有饲养。\",\"gongxiao\":\"补血滋阴、润燥、止血。属补虚药下属分类的补血药。\",\"huaxuezucheng\":\"阿胶主含胶原蛋白，系多肽类物质，经水解后产生分子量不等的蛋白质，最终水解产物为氨基酸。尚含纤维粘连蛋白及糖胺多糖。\",\"id\":20,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/140321/1-140321221K04a.jpg\",\"jinji\":\"脾胃虚弱、消化不良者慎服。\",\"linchuangzuoyong\":\"用量3～9克，烊化兑服。阿胶用于血虚萎黄、眩晕心悸、肌痿无力、心烦不眠、虚风内动、肺燥咳嗽、劳嗽咯血、吐血尿血、便血崩漏、妊娠胎漏。延伸阅读：阿胶养生保健作用与方法\",\"name\":\"阿胶\",\"otherName\":\"盆覆胶、驴皮胶、傅致胶。\",\"params\":{},\"source\":\"马科动物驴的皮，经煎煮、浓缩制成的固体胶。\",\"xingtai\":\"我国北方地区主要役用家畜之一。体型比马小，体重一般200千克左右。头形较长，眼圆，其上生有l对显眼的长耳。颈部长而宽厚，颈背鬃毛短而稀少。躯体匀称，四肢短粗，蹄质坚硬，尾尖端处生有长毛。毛色主要有黑色、栗色、灰色3种。颈背有一条短的深色横沟，嘴部有白色嘴圈，腹部和四肢的内侧白色。\",\"xingweiguijing\":\"性平，味甘。归肺经、肝经、肾经。\",\"xingzhuang\":\"阿胶呈长方形或丁块状，长约8厘米，宽约4厘米，厚约0.7厘米。表面黑色或黑褐色，光滑，有油润光泽，对光照视呈半透明的棕红色。质坚脆，易碎。断面棕褐色，具玻璃样光泽。气微，味微甘。\",\"yaoliyanjiu\":\"实验表明，阿胶具有促进造血、增强免疫、抗辐射损伤和抗休克功能；能提高耐缺氧、耐寒冷、抗疲劳能力；促进凝血，增加钙的摄入量，对肌肉萎缩有预防和改善作用；有增加智力、加速生长发育、延缓衰老等作用。\",\"yaowupeifang\":\"1.治大人小儿吐血：阿胶(炒)、蛤粉各30克，辰砂少许。上为末，藕节捣汁，和蜜调下，食后服。(《赤水玄珠》辰砂散)\\r\\n2.治衄血：阿胶30克(杵碎，炒令黄燥)，贝母15克(煨令微黄)。上件药，捣筛为散。每服不计时候。以温水调下3克。(《圣惠方》)\\r\\n3.治伤寒热病七日以上，发汗不解及吐下后，诸热不除，遂至发斑：阿胶(炒令燥)30克。大青60克，甘草(炙)30克。上三味，粗捣筛。每服15克，水一盏半，豉百粒，煎至一盏。去滓温服。(《圣济总录》阿胶汤)\\r\\n4.治妊娠尿血：阿胶60克(捣碎。炒令黄燥)，熟干地黄60克。上件药，捣细罗为散。不计时候，以葱汤调下6克。(《圣惠方》)\\r\\n5.治产后虚赢，大便秘涩：阿胶(碎，炒)、枳壳(浸，去瓤，麸炒)各60克，滑石(研飞，为衣)15克。上为末，炼蜜丸如梧桐子大。每服二十丸，温水下，半日来未通再服。(《局方》阿胶枳壳丸)\\r\\n6.治老人虚人大便秘涩：阿胶(炒)6克，连根葱白三片，蜜二匙。新水煎，去葱。入阿胶、蜜溶开，食前温服。(《直指方》胶蜜汤)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:27:27');
INSERT INTO `sys_oper_log` VALUES (202, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"扶桑花多为栽培。分布于广东、广西、福建及西南各地。\",\"gongxiao\":\"清肺、化痰、凉血、解毒。属清热药下属分类的清热解毒药。\",\"huaxuezucheng\":\"扶桑花含槲皮素-3-二葡萄糖甙，槲皮素-3,7-二葡萄糖甙，矢车菊素-3,5-二葡萄糖甙，矢车菊素-3-槐糖甙-5-葡萄糖甙，山柰酚-3-木糖基葡萄糖甙，矢车菊双甙，槲皮素，矢车菊素，三十一烷，矢车菊素-3-槐糖甙，β-扶桑甾醇，及环肽生物碱。\",\"id\":21,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/2012/1-201216132425305.jpg\",\"jinji\":\"尚不明确。\",\"linchuangzuoyong\":\"用量15～30克，煎服。用治痰火咳嗽、鼻衄、痢疾、赤白浊。外用适量，捣烂敷患处，用治痈肿、毒疮、汗斑。\",\"name\":\"扶桑花\",\"otherName\":\"大红花、朱槿、吊丝红花、状元红、佛桑花等\",\"params\":{},\"source\":\"锦葵科植物朱槿的花。\",\"xingtai\":\"灌木或小乔木，高1～6米；小枝圆柱形，被星状柔毛。叶互生，宽卵形或狭卵形，先端突尖或渐尖，边缘有粗齿或缺刻，或除近先端外几乎全缘，秃净，或于背脉有少许疏毛。花大型，单生于上部叶腋，常下垂；小苞片6～7；花萼钟状，5裂，裂片卵形至披针形；花冠漏斗状，花瓣5，倒卵形，玫瑰红色、淡红色或淡黄色，有时重瓣；雄蕊多数，花丝结合成圆筒；子房上位，5室，花柱5裂，柱头头状，雄蕊筒与柱头甚长，超出花冠外。蒴果卵形，有喙，5瓣裂。花期全年。\",\"xingweiguijing\":\"性寒，味甘。归心经、肺经、肝经、脾经。\",\"xingzhuang\":\"扶桑花药材呈皱缩长条形，长5.5～7厘米。小苞片6～7，线形。花萼黄棕色，长约2.5厘米，有星状毛，5裂。花瓣5，有重瓣，紫色或淡棕红色，顶端圆或具粗圆齿。雄蕊柱长，突出于花冠外。子房5棱形，被毛，花柱5。体轻，气清香，味微苦。\",\"yaoliyanjiu\":\"动物实验表明，扶桑花提取物有降压作用，对平滑肌有致痉作用，还有抗生育作用。\",\"yaowupeifang\":\"治痈疽，腮肿：扶桑花或叶，同白芙蓉叶、牛蒡叶、白蜜研膏敷之。(《纲目》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:27:46');
INSERT INTO `sys_oper_log` VALUES (203, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"生于山坡草地、荒地、包谷地、田边、河边及疏林下。除内蒙古、新疆、西藏外，全国各地均有分布。\",\"gongxiao\":\"燥湿化痰、降逆止呕、消痞散结。属化痰止咳平喘药下属分类的温化寒痰药。\",\"huaxuezucheng\":\"含挥发油，内含3-乙酰氨基-5-甲基异唑等60多种成分及16种氨基酸和多种无机元素。其中，所含的草酸钙针晶为半夏的刺激性成分之一，经炮制后，晶形发生变化，含量急剧下降，刺激性明显减弱。另含琥珀酸、丁基乙烯基醚、苯甲醛、半夏蛋白、姜辣醇、胰蛋白酶抑制剂等。\",\"id\":22,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/131207/1-13120F9504V92.jpg\",\"jinji\":\"阴虚燥咳、津伤口渴、血证及燥痰者禁服，孕妇慎服。不宜与川乌、制川乌、草乌、制草乌、附子同用，生品内服宜慎。\",\"linchuangzuoyong\":\"内服用量3～9克；或入丸、散；外用研末调敷。用治湿痰冷饮、呕吐、反胃、咳喘痰多、胸膈胀满、痰厥头痛、头晕不眠等。\",\"name\":\"半夏\",\"otherName\":\"三叶半夏、三步跳、麻芋子、水芋、地巴豆。\",\"params\":{},\"source\":\"天南星科植物半夏Pinellia ternata (Thunb.) Breit.的块茎。\",\"xingtai\":\"多年生草本。块茎近球形。叶出自块茎顶端，在叶柄下部内侧生一白色珠芽；一年生的叶为单叶，卵状心形；2～3年后，叶为3小叶的复叶，小叶椭圆形至披针形，中间小叶较大，两侧的较小，先端锐尖，基部楔形，全缘，两面光滑无毛。肉穗花序顶生，花序梗常较叶柄长；佛焰苞绿色；花单性，无花被，雌雄同株；雄花着生在花序上部，白色，雄蕊密集成圆筒形，雌花着生于雄花的下部，绿色；花序中轴先端附属物延伸呈鼠尾状，直立伸出在佛焰苞外。浆果卵状椭圆形，绿色。花期5～7月，果期8～9月。\",\"xingweiguijing\":\"性温，味辛，有毒。归脾经、胃经、肺经。\",\"xingzhuang\":\"类球形，有的稍偏斜，直径0.8～1.5厘米。表面白色或浅黄色，顶端中心有凹陷的茎痕，周围密布棕色凹点状的根痕；下端钝圆，较光滑。质坚实，断面白色，富粉性。气微，味辛辣、麻舌而刺喉。\",\"yaoliyanjiu\":\"具有镇吐、催吐、镇咳、祛痰、抗癌、抗生育、抗早孕、抗心律失常、抗实验性溃疡、抗矽肺、促使外周淋巴细胞分裂等作用。\",\"yaowupeifang\":\"①治湿痰喘急，止心痛：半夏不拘多少，香油炒，为末，粥丸梧桐子大。每服三五十丸，姜汤下。(《丹溪心法》)\\r\\n\\r\\n　　②治诸呕吐，谷不得下者：半夏一升，生姜240克。上二味，以水七升，煮取一升半，分温再服。(《金匮要略》小半夏汤)\\r\\n\\r\\n　　③治头痛：半夏(汤洗七遍)、白僵蚕各15克，全蝎一个。上同为细末，以绿豆粉调贴于太阳穴上，干即易之。(《叶氏录验方》抽风膏)\\r\\n\\r\\n　　④下乳方：半夏(炮)三粒。为末，酒调服，即有乳。(《鲁府禁方》)\\r\\n\\r\\n　　⑤治蝎螫毒：用半夏、白矾等分为末，以醋和，敷伤处。(《景岳全书》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:28:15');
INSERT INTO `sys_oper_log` VALUES (204, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"生于半山腰荫蔽潮湿地带的杂木林中。主产于广东、广西、海南、湖南等地。\",\"gongxiao\":\"清热解毒，消肿止痛。属清热药下分类的清热解毒药。\",\"huaxuezucheng\":\"胆木茎中主要含生物碱类和生物碱苷类，其中生物碱有：乌檀费新碱，乌檀费丁碱，乌檀福林碱，1-乙酰基咔啉，乌檀费林碱和乌檀醛碱。生物碱苷有胆木碱庚，胆木碱辛和长春花苷内酰胺。另外含有奎诺酸，β-谷甾醇，香草酸。\",\"id\":23,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/2112/1-21121019112T27.jpg\",\"jinji\":\"尚不明确。\",\"linchuangzuoyong\":\"煎汤内服，用量15～30克。外用适量，煎水洗。用治乳蛾，痢疾，热淋，下肢溃疡，疖肿脓疡，湿疹。\",\"name\":\"胆木\",\"otherName\":\"胆木山熊胆、熊胆树、细叶黄棵木、黄羊木、药乌檀、黄胆木、黄心木、树黄柏。\",\"params\":{},\"source\":\"为茜草科植物胆木Nauclea officinalis Pierre. ex Pitard的枝、树皮。\",\"xingtai\":\"乔木，高4～12米，小枝纤细而光滑。叶纸质，对生，椭圆形，稀倒圆形，长7～11厘米，宽3.5～5厘米。顶端渐尖而略钝，基部楔形，侧脉每边5～7对，纤细，向上斜伸，近边缘处连结，在叶片两边略凸起；叶柄长10～15厘米，稍粗壮；托叶早落，倒卵形，长6～10厘米，顶端钝圆。头状花序顶生，单生；总花梗长1～3厘米，中部以下有早落的苞片。小坚果合成一球状体，成熟时黄褐色，直径9～15厘米，表面粗糙。种子椭圆形，长1厘米，腹面平坦，背面拱起，种皮黑色有光泽并有微小窝孔。果期夏季。\",\"xingweiguijing\":\"性寒，味苦。归肺经、大肠经。\",\"xingzhuang\":\"多劈成不规则的片、块，浅黄色或棕黄色，有的残留皮部，外皮灰绿色或者棕绿色，粗糙，具多数点状皮孔，较疏松，易剥离。横切面皮部棕褐色，木部黄色或棕黄色。质坚硬，气微，味苦。\",\"yaoliyanjiu\":\"从胆木茎中分离得到的乌檀醛碱经抑菌试验表明有抑菌作用，乌檀醛碱在100μg/ml以上对金黄色葡萄球菌、蜡样芽胞杆菌有明显抑制作用。胆木浸膏片对冰醋酸所致的小鼠腹部毛，细血管通透性增加和二甲苯所致的小鼠耳肿胀具有非常显著的抑制作用，并显著抑制大鼠蛋清性足跖肿胀形成和棉球性慢性肉芽组织增生，对伤寒V₁多糖菌苗所致的家兔双高峰体温升高有解热功效与作用。\",\"yaowupeifang\":\"1.治钩端螺旋体病：①胆木注射液(每1毫升含胆木的乙醇提取物3克)，每8小时肌内注射1次，每次2～3毫升，用至体温正常后2～3天。有出血倾向者加紫珠草30克，水煎，每日分3次服。②胆木、大青叶、地胆草、紫珠草各60～90克(小儿酌减)，加水3碗，煎成1碗，分3次口服。在口服合剂的同时可加用胆木注射液。(《全国中草药汇编》)\\r\\n\\r\\n　　2.上呼吸道感染：胆木注射液，每1毫升相当于生药1克，每次肌注2毫升，每日1次。(《全国中草药汇编》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:28:33');
INSERT INTO `sys_oper_log` VALUES (205, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"生于阔叶林下。分布于黑龙江、吉林、辽宁、山东等地。\",\"gongxiao\":\"祛风湿、消痈肿。属祛风湿药下分类的祛风湿强筋骨药。\",\"huaxuezucheng\":\"根茎含齐墩果酸，从中分离出10个皂苷和2个皂苷元：竹节香附皂苷R0、R1、R2、R3、R4、Rs、R6、R7、R8、R9 10个皂苷，齐墩果酸和薯蓣皂苷元，并含有毛茛苷和白头翁素。\",\"id\":25,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/140430/1-140430110225201.jpg\",\"jinji\":\"有毒，内服用量不宜过大、孕妇禁用。\",\"linchuangzuoyong\":\"用量1.5～3克，煎汤内服。外用：研末撒膏药上敷贴。治疗风寒湿痹、手足拘挛、骨节疼痛、痈疽肿痛。\",\"name\":\"两头尖\",\"otherName\":\"竹节香附、草乌喙。\",\"params\":{},\"source\":\"毛茛科植物多被银莲花Anemone raddeana Regel的根茎。\",\"xingtai\":\"多年生草本，高10～25厘米。根茎横走或斜生，呈细纺锤形，长1.5～3厘米，直径3～8毫米，暗褐色，顶端具数枚黄白色大型膜质鳞片。基生叶为3出复叶，通常1枚，小叶具柄，小叶片通常3深裂或近全裂，裂片倒卵形，3裂或缺刻状，先端钝，基部楔形，两面无毛或仅基部疏被长柔毛。花茎单一，直立，疏被长柔毛，较基生叶高，有叶状总苞片3枚，总苞片长圆形或狭倒卵形，具数个缺刻状圆齿，花单朵，顶生，萼片花瓣状，长圆形，10～15片，白色，外侧略带紫晕，两面无毛，雄蕊多数，雌蕊多数，离生，子房被长柔毛，花柱稍弯，无毛。瘦果，具细毛。\",\"xingweiguijing\":\"性热，味辛。归脾经。\",\"xingzhuang\":\"呈长纺锤形，两端尖细，略弯曲，长1～3厘米，直径2～7毫米。表面棕褐色至棕黑色，隐约可见数个环节，具多数细纵皱纹，有的一端具1至数个短的分枝或突起。质坚脆，断面较平坦，角质样，边缘棕黑色，中央淡灰白色至淡棕褐色;气微弱，味涩略麻竦。以质硬、断面类白色者为佳。\",\"yaoliyanjiu\":\"体外实验表明，竹节香附素A能显著抑制小鼠S180和腹水型肝癌细胞DNA、RNA及蛋白质的合成;银莲花素A能够明显抑制胸腺嘧啶苷、尿嘧啶苷和亮氨酸掺入S180和肝癌细胞;竹节香附皂苷Ri~ Rs均有溶血作用。\",\"yaowupeifang\":\"①治痈疽疮疡：两头尖3克，金银花30克，地丁30克。水煎服。(《山东中草药手册》)\\r\\n\\r\\n　　②治慢性关节疼痛：两头尖3克，防风9克，牛膝12克，威灵仙12克，松节6克，鸡血藤15克，水煎服。(《山东中草药手册》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:33:05');
INSERT INTO `sys_oper_log` VALUES (206, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"多产于山西、内蒙古、河北、河南、湖北、四川、陕西、甘肃等地。\",\"gongxiao\":\"镇心安神，平肝潜阳，固涩，收敛。属平肝息风药下分类的平抑肝阳药。\",\"huaxuezucheng\":\"主要成分为碳酸钙、磷酸钙等物质。\",\"id\":26,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/1901/1-1Z1251I421325.jpg\",\"jinji\":\"湿热积滞者慎服。\",\"linchuangzuoyong\":\"内服：煎汤，10～15克，打碎先煎；或入丸、散。外用：适量，研末撒；或调敷。安神、平肝宜生用，收涩、敛疮宜煅用。主治心悸怔忡，失眠健忘，惊痫癫狂，头晕目眩，自汗盗汗，遗精遗尿，崩漏带下，久泻久痢，溃疡久不收口及湿疮。\",\"name\":\"龙骨\",\"otherName\":\"五花龙骨。\",\"params\":{},\"source\":\"古代哺乳动物象类、犀类、三趾马、牛类、鹿类等的骨骼化石或象类门齿的化石。\",\"xingtai\":\"由磷灰石、方解石及少量黏土矿物组成。磷灰石为六方晶系隐晶质，依古代生物骨骼产出。疏松集合体中或有呈现晶体形小棒状的磷灰石 ，灰白色。略带油脂状，土状光泽或瓷状光泽。硬度大于指甲，小于小刀。方解石的晶体结构属三方晶系。晶体为菱面体，也有呈现柱状及板状者。常以钟乳状或致密粒状集体产出。断口贝壳状，硬度3，性脆。\",\"xingweiguijing\":\"性平，味涩、甘。归心经、肝经、肾经、大肠经。\",\"xingzhuang\":\"1.龙骨：又称白龙骨。呈骨骼状或不规则块状。表面白色、灰白色或黄白色至淡棕色，多较平滑，有的具纵纹裂隙或具棕色条纹与斑点。质硬，砸碎后，断面不平坦，色白或黄白，有的中空。关节处膨大，断面有蜂窝状小孔。吸湿力强，舔之吸舌。无臭，无味。以质硬、色白、吸湿力强者为佳。\\r\\n\\r\\n　　2.五花龙骨：又称五色龙骨。呈圆筒状或不规则块状。直径5～25厘米。淡灰白色、淡黄白色或淡黄棕色，夹有蓝灰色及红棕色深浅粗细不同的花纹，偶有不具花纹者。一般表面平滑，有时外层成片剥落，不平坦，有裂隙。质较酥脆，破碎后，断面粗糙，可见宽窄不一的同心环纹。吸湿力强，舔之吸舌。无臭，无味。以体较轻、质酥脆、分层、有花纹、吸湿力强者为佳。\",\"yaoliyanjiu\":\"有一定的镇静作用，增加戊巴比妥钠催眠率；还可缩短小鼠的凝血时间。\",\"yaowupeifang\":\"①治好忘：龙骨、虎骨、远志各等分。上三味治下筛。食后服2g，日二。久服聪明益智。(《千金要方》)\\r\\n\\r\\n　　②治虚劳梦泄：龙骨60克，韭子(微炒)60克。上件药捣罗为散，更研令细。每服6g，空心及晚食前以温酒调下。(《圣惠方》)\\r\\n\\r\\n　　③治遗溺淋沥：龙骨、桑螵蛸等分为末，每盐汤服6克。(《纲目》引《梅师经验方》)\\r\\n\\r\\n　　④治金疮出血：龙骨30克，诃子30克，白石脂15克，苎麻叶15克。上为细末，水调服之。(《普济方》神仙止血方)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:33:26');
INSERT INTO `sys_oper_log` VALUES (207, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"刺参：多栖息于水深3～15米的浅海中，喜波流静稳、海藻繁茂的岩礁底或细沙泥底。我国分布于辽宁、河北、山东沿岸浅海。现已人工繁殖进行放养。绿刺参：栖息于长有海藻的珊瑚砂上或珊瑚礁里边；或在被海水所冲刷的潟湖内。我国分布于海南南部及西沙群岛。花刺参：多栖息于潮间带珊瑚礁旁或岩石下，大形个体多在海水较深处。我国分布于海南及雷州半岛、西沙群岛等沿岸浅海。\",\"gongxiao\":\"补肾益精，养血润燥，止血。属补虚药下分类的补血药。\",\"huaxuezucheng\":\"刺参含有蛋白质、脂肪、碳水化合物，钙、磷、铁、镁、硒以及维生素B₁、B₂等。绿刺参含有18种氨基酸、牛璜酸、硫酸软骨素等成分。花刺参含有海参素、海参皂苷、酸性黏多糖、甾醇、本萜醇、β-胡萝卜素、海胆酮、虾青素、玉米黄质等成分。\",\"id\":27,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/1901/haishen.jpg\",\"jinji\":\"脾虚不运、外邪未尽者禁服。\",\"linchuangzuoyong\":\"内服：煎汤，煮食，用量15～30克；入丸、散，用量9～15克。外用：研末敷。主治精血亏损，虚弱劳怯，阳痿，梦遗，小便频数，肠燥便秘，肺虚咳嗽咯血，肠风便血，外伤出血。\",\"name\":\"海参\",\"otherName\":\"辽参，海男子。\",\"params\":{},\"source\":\"刺参科刺参属动物刺参Aposticopus japoniciLs Selenka、绿刺参Stichopus chloronotus Brandt、花刺参S. variegatus Sermper(去内脏)的全体。\",\"xingtai\":\"刺参：体呈圆柱状，一般长20～40厘米，宽3～6厘米，背面隆起，具4～6行圆锥形大小不等的肉刺，腹面管足较密，排成不规则的纵带。口在前端，后端为肛门。口偏于腹面，周围具蝰状触手20个。口背有一乳突，生殖孔即位于孔突处。皮内的骨片主要为桌形体，幼小个体的桌形体塔部细而高，底盘较大，周缘平滑，老年个体的桌形体塔部变低或消失，只剩下小形的穿孔盘。产卵季节在5月底至7月初。生活时体色通常为栗褐色，亦有绿色、黄褐色、灰白色等，随生境不同而异。\\r\\n\\r\\n　　绿刺参：体呈四方柱形，一般长达30厘米以上，沿身体的边棱，各有两行交互排列的圆锥形肉刺。腹面管足较多，排列成3纵带，中央带较宽。口稍偏于腹面，具触手20个。浅层皮内的骨片，主要是略成方形的桌形体，上方稍向外扩张，顶上有小齿8～12个，最多可达16个；下方底盘小，有穿孔4～8个。深层皮内的骨片为小形的C形体。生活时体色为深绿色或墨绿色，肉刺顶端为橙黄色或橙红色，触手基部为灰白色，管足为黑灰色。\\r\\n\\r\\n　　花刺参：体稍呈四方柱形，一般长30～40厘米，最长可达95厘米。背面散生多数圆锥形和排列不规则的肉刺。腹面管足排列成3纵带，中央带较宽。触手20个。皮的骨片：第一种为桌形体，塔部顶端具12个向外扩张的小齿，它的底盘小，略带方形，中央常有4个大孔，周围有4个或4个以上的小孔；底盘较大的桌形体，其周围小孔也较多。第二种骨片是大小不等的C形体。第三种似为数个C形体连接组成的花纹样体。生活时体色变异很大，多为橄榄绿灰色，并间有灰黄、浅褐及浓绿等色的斑点或斑纹，肉刺末端有的带红色。产卵季节在6月下旬。\",\"xingweiguijing\":\"性平，味甘、咸。归肾经、肺经。\",\"xingzhuang\":\"药材呈圆柱形、四方柱形，两端稍细。体分背腹两面。背面隆起，有4～6行圆锥状的肉刺。腹面较平坦，密集有小突起，末端有吸盘，口周围有20个触手。有的缺少，皱缩。肛门位于体后且稍偏于背面。体黑色、紫黑色、灰黑色、灰褐色、浅黄色或黄褐色。\",\"yaoliyanjiu\":\"1.刺参提取液对体外培养人胃癌MGC-B01、人肝癌BEL-7402、肺腺癌SPC-A均有抑制作用，但对正常细胞无明显影响。2.刺参提取液和刺参多糖均可明显延长凝血酶原时间，具有抗凝血作用。3.刺参提取液1毫升的镇痛作用约相当吗啡1毫克的镇痛效果。4.海参素对兔大动脉呈现依赖于浓度的持续性收缩作用。5.花刺参醇提取物体外对鼻咽癌(NPC)患者T调节细胞亚群的T4和T8细胞均有明显的诱导和激活作用。6.抗真菌作用：海参毒素对星状发癣菌、白念珠菌等真菌均有明显的抑制作用。7.抗放射性损伤：刺参酸性黏多糖有防治急性放射性损伤作用，并可明显促进实验动物造血功能的恢复。\",\"yaowupeifang\":\"①治体虚软，小便多：(海参)干品30克，水浸软，和猪瘦肉或鸡一起炖或煲汤服。(《广西药用动物》)\\r\\n\\r\\n　　②治糖尿病：海参3个，鸡蛋1个，猪胰1个，地肤子与向日葵杆芯各6克。把前', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:33:51');
INSERT INTO `sys_oper_log` VALUES (208, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"生于山坡或路旁。分布于黑龙江、吉林、辽宁、河北等地。\",\"gongxiao\":\"快气、和中、辟秽、祛湿。属理气药。\",\"huaxuezucheng\":\"含挥发油，主要成分为甲基胡椒酚，占80%以上。并含有茴香脑，茴香醛，柠檬烯，对甲氧基桂皮醛等。\",\"id\":28,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/1901/huoxiang.jpg\",\"jinji\":\"阴虚火旺，胃弱欲呕及胃热作呕，中焦火盛热极者禁服。不宜久煎。\",\"linchuangzuoyong\":\"用量5～9克，内服煎汤，或入丸散。治疗感冒暑湿、寒热、头痛、胸脘痞闷、呕吐泄泻、疟疾、痢疾、口臭。\",\"name\":\"藿香\",\"otherName\":\"土藿香、大叶薄荷、绿荷荷、川藿香、苏藿香、野藿香、排香草。\",\"params\":{},\"source\":\"唇形科植物藿香Agastache rugosa(Fisch.et Mey.)Q.Ktze.的全草或地上部分。\",\"xingtai\":\"一年生或多年生草本，高40～110厘米。茎直立，四棱形，略带红色，稀被微柔毛及腺体。叶对生，椭圆状卵形或卵形，先端锐尖或短渐尖，基部圆形或略带心形，边缘具不整齐的钝锯齿，齿圆形，上面无毛或近无毛，散生透明腺点，下面被短柔毛。轮伞花序聚成顶生的总状花序，苞片大，阔线形或披针形，被微柔毛，萼5裂，裂片三角形，具纵脉及腺点，花冠唇形，紫色或白色，上唇四方形或卵形，先端微凹，下唇3裂，两侧裂片短，中间裂片扇形，边缘有波状细齿，花冠外被细柔毛，雄蕊4枚，2强，伸出花冠管外，子房深4裂，花柱着生于子房底部中央，伸出花外，柱头2裂。小坚果倒卵状三棱形。\",\"xingweiguijing\":\"性微温，味辛。归肺经、脾经、胃经。\",\"xingzhuang\":\"茎呈四方柱形，四角有棱脊，直径3～10毫米，表面黄绿色或灰黄色，茸毛稀少，或近于无毛，质轻脆，断面中央有白色髓。老茎坚硬，木质化，断面中空。叶多已脱落，剩余叶灰绿色，皱缩或破碎，两面微具毛，薄而脆。有时枝端有圆柱形的花序，土棕色，小花具短柄，花冠多脱落，小坚果藏于萼内。气清香，味淡。\",\"yaoliyanjiu\":\"试管实验藿香煎剂对许兰氏毛癣菌等多种致病性真菌有抑制作用，乙醚浸出液及醇浸出液亦能抑制多种致病性真菌。水煎剂对钩端螺旋体有抑制作用，有效浓度是31毫克/毫升。藿香中的黄酮类物质具有抗病毒作用。\",\"yaowupeifang\":\"①预防伤暑：藿香、佩兰各等 分。煎水饮用。(《吉林中草药》)\\r\\n\\r\\n　　②治急性肠炎：藿香9～30克，水煎(不可久煎)，另用大蒜头4～6瓣，捣烂，和红糖15克拌匀，冲服，每日1～3次。(《浙江药用植物志》)\\r\\n\\r\\n　　③治胃腹冷痛：藿香6克，肉桂6克，共研细末，每次3克，白酒为饮，每日服2次。(《吉林中草药》)\\r\\n\\r\\n　　④治湿疹，皮肤瘙痒：用(藿香)茎、叶适量，水煎外洗。(《广西本草选编》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:34:08');
INSERT INTO `sys_oper_log` VALUES (209, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '61.190.13.218', 'XX XX', '{\"chandi\":\"人工饲养，一年可繁殖3代。分布于全国各地，以长江以南为主。\",\"gongxiao\":\"祛风定惊、化痰散结。属平肝息风药下属分类的息风止痉药。\",\"huaxuezucheng\":\"僵蚕主要含蛋白质，脂肪。尚含多种氨基酸以及铁、锌、铜、锰、铬等微量元素。\",\"id\":29,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/140407/1-14040F93925436.jpg\",\"jinji\":\"心虚不宁、血虚生风者慎服。\",\"linchuangzuoyong\":\"用量5～9克，煎服或人丸、散。用治惊风抽搐、咽喉肿痛、皮肤瘙痒、颌下淋巴结炎、面神经麻痹。\",\"name\":\"僵蚕\",\"otherName\":\"天虫、僵虫、白僵蚕。\",\"params\":{},\"source\":\"蚕蛾科昆虫家蚕蛾Bombyx moriL.的幼虫感染白僵菌Beauveriabasiana (Bals.)Vaillant致死的干燥虫体。\",\"xingtai\":\"雌雄成虫全身皆密布白色鳞片。体长1.6～2.3厘米。翅展3.9～4.3厘米。头部较小。复眼l对。口器退化，下唇须细小。触角呈羽毛状。翅2对，前翅位于中胸部，呈三角形，较大；后翅生自后胸，较小；翅面有白色鳞片。雌性腹部肥硕，末端钝圆；雄性腹部狭窄，末端稍尖。幼虫体色灰白色至白色，胸部第2、3节稍见膨大，有皱纹。腹部第8节背面有l尾角。\",\"xingweiguijing\":\"性平，味咸、辛。归肝经、肺经、胃经。\",\"xingzhuang\":\"雌雄成虫全身皆密布白色鳞片。体长1.6～2.3厘米。翅展3.9～4.3厘米。头部较小。复眼l对。口器退化，下唇须细小。触角呈羽毛状。翅2对，前翅位于中胸部，呈三角形，较大；后翅生自后胸，较小；翅面有白色鳞片。雌性腹部肥硕，末端钝圆；雄性腹部狭窄，末端稍尖。幼虫体色灰白色至白色，胸部第2、3节稍见膨大，有皱纹。腹部第8节背面有l尾角。\",\"yaoliyanjiu\":\"具有镇静、抗惊厥作用;具有抗凝血、降血糖和明显抑制肉瘤S180的生长，及具有较弱的抑制细菌生长等作用。\",\"yaowupeifang\":\"①治风壅牙痛：僵蚕，藁本、白芷各等分。上为细末。每用少许揩牙痛处，用盐水灌漱。(《普济方&gt;僵蚕散)\\n\\n　　②治重舌、木舌：僵蚕3克，黄连(蜜炒)6克。为末，掺之，涎出为妙。(《积德堂经验方》)\\n\\n　　③治喉痹口疮，腮颊肿痛：白僵蚕(炒去丝、嘴)、牛蒡子(微炒)各等分。为细末，炼蜜为丸，每30克作1.5丸。每服1丸，含化，食后。(《杨氏家藏方》消毒丸)\\n\\n　　④治喉痹失音：瓜蒌皮(炒)、僵蚕(炒)、甘草(炒)各6克。共为末。每服9克，姜汤下。(《疑难杂症简方》)\\n\\n　　⑤治喘嗽，喉中如锯，不能睡卧：好末茶30克，白僵蚕30克。上为细末，放碗内，倾沸汤一小盏，用盏盖定，临卧，再添汤点服。(《瑞竹堂经验方》僵蚕汤)\\n\\n　　⑥治瘰疬：白僵蚕，研末，水服1.5克，日三服。(《千金要方》)\\n\\n　　⑦治遍身瘾疹，疼痛成疮：白僵蚕，焙令黄色，细研为末，酒服。(《圣惠方》)\\n\\n　　⑧治一切疥癣：白僵蚕24枚(炒去丝)，蝎梢5枚(去毒，微炒)，地龙3条。上件研令极细。分作二服，小儿作五服。温酒调下。服药，然后澡浴。(《杨氏家藏方》三神散)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:34:29');
INSERT INTO `sys_oper_log` VALUES (210, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '61.190.13.218', 'XX XX', '{\"gongxiao\":\"健脾养胃、促进消化。适用于肠胃虚寒所致的腹部冷痛、呕吐或拉肚子等症。也可用于孕妇的早孕反应。\",\"imageurl\":\"https://i2.chuimg.com/6952b2048b2411e6b87c0242ac110003_1080w_1440h.jpg?imageView2/2/w/660/interlace/1/q/75\",\"jinji\":\"无\",\"name\":\"丁香炖鸡腿\",\"params\":{},\"shicai\":\"鸡腿2只，生姜3克，盐3克。\",\"shiyongfangfa\":\"佐餐食用，吃肉喝汤。\",\"yaocai\":\"丁香、陈皮各8克，党参、白术各10克。\",\"zuofa\":\"步骤1：以上药材、鸡腿分别洗净；陈皮清水泡发，鸡腿沸水汆烫备用。\\r\\n　　步骤2：药材放入砂锅，再放上鸡腿，加水盖过，放入姜片，保鲜膜密封，上锅隔水炖2小时，启封后放盐调味即可。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 23:47:10');
