INSERT INTO `sys_oper_log` VALUES (217, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '114.104.217.230', 'XX XX', '{\"gongxiao\":\"暖肾助阳、益精补髓。适用于虚损劳伤、肾阳虚衰所致的阳痿不举、早泄、身体衰弱等症。\",\"imageurl\":\"https://ts1.cn.mm.bing.net/th/id/R-C.a172792fd8746788ade5e3ab2c553e30?rik=pho%2fd9R2Nxunmw&riu=http%3a%2f%2fszyyj.gd.gov.cn%2fimg%2f0%2f751%2f751844%2f3804319.png&ehk=mje45qzkFNiiryRDXrm38a1OTJglJg4ELrDGmKe%2fvT0%3d&risl=&pid=ImgRaw&r=0\",\"jinji\":\"无\",\"name\":\"三物壮阳汤\",\"params\":{},\"shicai\":\"牛鞭80克，狗肾8克，羊肉80克，肥母鸡肉40克，花椒2克，老生姜、葱白各5克，绍酒15毫升，味精2克，盐5克，植物油10毫升。\",\"shiyongfangfa\":\"佐餐或单独食用。牛鞭狗鞭汤食材灵芝、枸杞各8克，肉苁蓉5克。\",\"yaocai\":\"枸杞、菟丝子8克，肉苁蓉5克。\",\"zuofa\":\"　步骤1：牛鞭入热水泡胀，剖开，刮洗干净，冷水浸泡30分钟，切段；狗肾油砂爆炒，温水浸泡40分钟，刷洗干净；羊肉洗净，沸水汆烫，凉水漂洗；菟丝子、肉苁蓉、枸杞洗净，装入纱布袋内，扎紧袋口。\\r\\n　　步骤2：砂锅内加水，放入牛鞭、狗肾和羊肉置于锅内，煮沸，撇去浮沫，加母鸡肉和花椒、老生姜、葱白、绍酒，大火煮沸，小火炖煮，隔30分钟翻动一次。至六成熟时，滤去花椒、生姜、葱白，放入药袋，继续煮沸，以牛鞭、狗肾酥烂为度。\\r\\n　　步骤3：捞去母鸡肉和药袋，加味精、盐和植物油调味。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 23:50:17');
INSERT INTO `sys_oper_log` VALUES (218, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '61.190.13.218', 'XX XX', '{\"gongxiao\":\"健脾养胃、促进消化。适用于肠胃虚寒所致的腹部冷痛、呕吐或拉肚子等症。也可用于孕妇的早孕反应。\",\"imageurl\":\"https://i2.chuimg.com/4cf944e8889911e6a9a10242ac110002_650w_650h.jpg?imageView2/1/w/640/h/520/q/75/format/jpg\",\"jinji\":\"无\",\"name\":\"丁香炖鸡腿\",\"params\":{},\"shicai\":\"鸡腿2只，生姜3克，盐3克。\",\"shiyongfangfa\":\"佐餐食用，吃肉喝汤。\",\"yaocai\":\"丁香、陈皮各8克，党参、白术各10克。\",\"zuofa\":\"步骤1：以上药材、鸡腿分别洗净；陈皮清水泡发，鸡腿沸水汆烫备用。\\r\\n　　步骤2：药材放入砂锅，再放上鸡腿，加水盖过，放入姜片，保鲜膜密封，上锅隔水炖2小时，启封后放盐调味即可。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 23:50:47');
INSERT INTO `sys_oper_log` VALUES (219, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '114.104.217.230', 'XX XX', '{\"gongxiao\":\"益心安神、补肺润肺。适用于肺热、肺燥、咳嗽、痰多等症。\",\"imageurl\":\"https://pic.rmb.bdstatic.com/6bc6ff4576ce0b70f189adea4bfcf214.jpeg\",\"jinji\":\"无\",\"name\":\"党参雪梨鸡\",\"params\":{},\"shicai\":\"乌鸡1只，红枣5枚，雪梨1个，盐3克，鸡精1克，植物油10毫升。\",\"shiyongfangfa\":\"佐餐食用。\",\"yaocai\":\"党参6克。\",\"zuofa\":\"步骤1：雪梨洗净，去核、皮，切成小块；红枣去核，洗净；党参洗净，浸泡，切片；乌鸡宰杀后，去毛、内脏、爪，切块，入沸水中汆烫去除血水，捞出备用。\\r\\n　　步骤2：炒锅置中火上，入油烧至九成热，放入鸡块爆炒10分钟，注入适量水，加入雪梨、红枣、党参，转小火煮约40分钟，加盐、鸡精调味即可。\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-26 23:51:46');
INSERT INTO `sys_oper_log` VALUES (220, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '114.104.217.230', 'XX XX', '{\"gongxiao\":\"温胃益肾、止腰痛。适宜妊娠期妇女及中老年人食用。\",\"imageurl\":\"https://bkimg.cdn.bcebos.com/pic/48540923dd54564e9258ad45bd978b82d158ccbfe13c?x-bce-process=image/format,f_auto/watermark,image_d2F0ZXIvYmFpa2UyNzI,g_7,xp_5,yp_5,P_20/resize,m_lfit,limit_1,h_1080\",\"jinji\":\"无\",\"name\":\"刀豆炒腰片\",\"params\":{},\"shicai\":\"猪腰2个，料酒5毫升，水淀粉10毫升，姜、盐各5克。\",\"shiyongfangfa\":\"佐餐食用。\",\"yaocai\":\"刀豆200克。\",\"zuofa\":\"　步骤1：猪腰撕去衣膜，剖开，入沸水焯烫、冲洗，切成薄片，加料酒、盐腌15分钟，加入水淀粉拌匀;刀豆洗净，切片;姜洗净，切片。\\r\\n　　步骤2：炒锅置大火上，入油烧至七成热，放姜片爆香，放入猪腰翻炒至熟，盛盘;锅中留少许油，烧至五成热，放入刀豆翻炒，加适量水，煮沸后，放盐调味，焖煮;分钟，下入药片，翻炒均匀，水淀粉勾芡即可。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 23:53:01');
INSERT INTO `sys_oper_log` VALUES (221, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '61.190.13.218', 'XX XX', '{\"gongxiao\":\"健脾养胃、促进消化。适用于肠胃虚寒所致的腹部冷痛、呕吐或拉肚子等症。也可用于孕妇的早孕反应。\",\"imageurl\":\"https://i2.chuimg.com/6952b2048b2411e6b87c0242ac110003_1080w_1440h.jpg?imageView2/2/w/660/interlace/1/q/75\",\"jinji\":\"无\",\"name\":\"丁香炖鸡腿\",\"params\":{},\"shicai\":\"鸡腿2只，生姜3克，盐3克。\",\"shiyongfangfa\":\"佐餐食用，吃肉喝汤。\",\"yaocai\":\"丁香、陈皮各8克，党参、白术各10克。\",\"zuofa\":\"步骤1：以上药材、鸡腿分别洗净；陈皮清水泡发，鸡腿沸水汆烫备用。\\r\\n　　步骤2：药材放入砂锅，再放上鸡腿，加水盖过，放入姜片，保鲜膜密封，上锅隔水炖2小时，启封后放盐调味即可。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 23:53:18');
INSERT INTO `sys_oper_log` VALUES (222, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '114.104.217.230', 'XX XX', '{\"gongxiao\":\"温胃益肾、止腰痛。适宜妊娠期妇女及中老年人食用。\",\"imageurl\":\"https://bkimg.cdn.bcebos.com/pic/1e30e924b899a901a8f659591f950a7b0308f59a?x-bce-process=image/format,f_auto/quality,Q_70/resize,m_lfit,limit_1,w_536\",\"jinji\":\"无\",\"name\":\"刀豆炒腰片\",\"params\":{},\"shicai\":\"猪腰2个，料酒5毫升，水淀粉10毫升，姜、盐各5克。\",\"shiyongfangfa\":\"佐餐食用。\",\"yaocai\":\"刀豆200克。\",\"zuofa\":\"　步骤1：猪腰撕去衣膜，剖开，入沸水焯烫、冲洗，切成薄片，加料酒、盐腌15分钟，加入水淀粉拌匀;刀豆洗净，切片;姜洗净，切片。\\r\\n　　步骤2：炒锅置大火上，入油烧至七成热，放姜片爆香，放入猪腰翻炒至熟，盛盘;锅中留少许油，烧至五成热，放入刀豆翻炒，加适量水，煮沸后，放盐调味，焖煮;分钟，下入药片，翻炒均匀，水淀粉勾芡即可。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 23:53:20');
INSERT INTO `sys_oper_log` VALUES (223, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '61.190.13.218', 'XX XX', '{\"gongxiao\":\"暖肾助阳、益精补髓。适用于虚损劳伤、肾阳虚衰所致的阳痿不举、早泄、身体衰弱等症。\",\"imageurl\":\"https://i2.chuimg.com/6952b2048b2411e6b87c0242ac110003_1080w_1440h.jpg?imageView2/2/w/660/interlace/1/q/75\",\"jinji\":\"无\",\"name\":\"三物壮阳汤\",\"params\":{},\"shicai\":\"牛鞭80克，狗肾8克，羊肉80克，肥母鸡肉40克，花椒2克，老生姜、葱白各5克，绍酒15毫升，味精2克，盐5克，植物油10毫升。\",\"shiyongfangfa\":\"佐餐或单独食用。牛鞭狗鞭汤食材灵芝、枸杞各8克，肉苁蓉5克。\",\"yaocai\":\"枸杞、菟丝子8克，肉苁蓉5克。\",\"zuofa\":\"　步骤1：牛鞭入热水泡胀，剖开，刮洗干净，冷水浸泡30分钟，切段；狗肾油砂爆炒，温水浸泡40分钟，刷洗干净；羊肉洗净，沸水汆烫，凉水漂洗；菟丝子、肉苁蓉、枸杞洗净，装入纱布袋内，扎紧袋口。\\r\\n　　步骤2：砂锅内加水，放入牛鞭、狗肾和羊肉置于锅内，煮沸，撇去浮沫，加母鸡肉和花椒、老生姜、葱白、绍酒，大火煮沸，小火炖煮，隔30分钟翻动一次。至六成熟时，滤去花椒、生姜、葱白，放入药袋，继续煮沸，以牛鞭、狗肾酥烂为度。\\r\\n　　步骤3：捞去母鸡肉和药袋，加味精、盐和植物油调味。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 23:53:25');
