INSERT INTO `sys_oper_log` VALUES (226, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '114.104.217.230', 'XX XX', '{\"gongxiao\":\"活血化瘀、补气散结。适用于子宫肌瘤，证属气虚血瘀者的辅助治疗。\",\"imageurl\":\"https://bkimg.cdn.bcebos.com/pic/730e0cf3d7ca7bcb6f523d8db0096b63f624a863?x-bce-process=image/format,f_auto/quality,Q_70/resize,m_lfit,limit_1,w_536\",\"jinji\":\"无\",\"name\":\"川芎山楂牛肉汤\",\"params\":{},\"shicai\":\"牛肉350克，姜、葱各5克，料酒5毫升，植物油10毫升，盐3克，鸡精2克。\",\"shiyongfangfa\":\"食肉喝汤，分次食用。\",\"yaocai\":\"川芎10克，山楂15克。\",\"zuofa\":\"步骤1：牛肉洗净，切片；川芎洗净，润透；姜洗净，切片；葱洗净，切段；山楂去核，洗净。\\r\\n　　步骤2：炒锅置火上，入油烧热，下姜片、葱段爆香，放入牛肉片炒至变色，烹入料酒，加入川芎炒匀，注入清水适量，大火煮沸后，转小火炖1小时，加入盐、鸡精调味，即可饮用。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-26 23:54:24');
INSERT INTO `sys_oper_log` VALUES (227, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '61.190.13.218', 'XX XX', '{\"gongxiao\":\"健脾养胃、促进消化。适用于肠胃虚寒所致的腹部冷痛、呕吐或拉肚子等症。也可用于孕妇的早孕反应。\",\"imageurl\":\"https://cdn.jsdelivr.net/gh/bfs1201/images/202403241911660.pnghttps://cdn.jsdelivr.net/gh/bfs1201/images/202403241911660.pnghttps://cdn.jsdelivr.net/gh/bfs1201/images/202403241911660.png\",\"jinji\":\"无\",\"name\":\"丁香炖鸡腿\",\"params\":{},\"shicai\":\"鸡腿2只，生姜3克，盐3克。\",\"shiyongfangfa\":\"佐餐食用，吃肉喝汤。\",\"yaocai\":\"丁香、陈皮各8克，党参、白术各10克。\",\"zuofa\":\"步骤1：以上药材、鸡腿分别洗净；陈皮清水泡发，鸡腿沸水汆烫备用。\\r\\n　　步骤2：药材放入砂锅，再放上鸡腿，加水盖过，放入姜片，保鲜膜密封，上锅隔水炖2小时，启封后放盐调味即可。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-27 00:10:28');
