INSERT INTO `sys_oper_log` VALUES (229, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '114.104.217.230', 'XX XX', '{\"gongxiao\":\"活血化瘀、补气散结。适用于子宫肌瘤，证属气虚血瘀者的辅助治疗。\",\"imageurl\":\"https://img0.baidu.com/it/u=3140793530,3725997330&fm=253&fmt=auto&app=138&f=JPEG?w=750&h=478\",\"jinji\":\"无\",\"name\":\"川芎山楂牛肉汤\",\"params\":{},\"shicai\":\"牛肉350克，姜、葱各5克，料酒5毫升，植物油10毫升，盐3克，鸡精2克。\",\"shiyongfangfa\":\"食肉喝汤，分次食用。\",\"yaocai\":\"川芎10克，山楂15克。\",\"zuofa\":\"步骤1：牛肉洗净，切片；川芎洗净，润透；姜洗净，切片；葱洗净，切段；山楂去核，洗净。\\r\\n　　步骤2：炒锅置火上，入油烧热，下姜片、葱段爆香，放入牛肉片炒至变色，烹入料酒，加入川芎炒匀，注入清水适量，大火煮沸后，转小火炖1小时，加入盐、鸡精调味，即可饮用。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-27 00:11:44');
INSERT INTO `sys_oper_log` VALUES (230, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '114.104.217.230', 'XX XX', '{\"gongxiao\":\"健脾固肾、补肺化痰。适用于痰饮喘咳、肺结核低热、慢性支气管炎、泄泻等症。\",\"imageurl\":\"https://img1.baidu.com/it/u=3448598459,872429828&fm=253&fmt=auto&app=138&f=JPEG?w=450&h=300\",\"jinji\":\"无\",\"name\":\"桂花山药羹\",\"params\":{},\"shicai\":\"冰糖适量。\",\"shiyongfangfa\":\"随时食用。\",\"yaocai\":\"山药150克，鲜桂花5克(干品1克)。\",\"zuofa\":\"　步骤1：将去皮洗净切成小丁的山药放入锅中，加水适量开始煮。\\r\\n　　步骤2：待山药煮至七八成熟时，放入桂花、冰糖，煮至山药糯软、汤汁浓稠，即可食用。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-27 00:12:16');
INSERT INTO `sys_oper_log` VALUES (231, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '114.104.217.230', 'XX XX', '{\"gongxiao\":\"健脾固肾、补肺化痰。适用于痰饮喘咳、肺结核低热、慢性支气管炎、泄泻等症。\",\"imageurl\":\"https://gimg2.baidu.com/image_search/src=http%3A%2F%2Fsafe-img.xhscdn.com%2Fbw1%2F137bb7c0-9cba-4f26-b2f0-ae3134384442%3FimageView2%2F2%2Fw%2F1080%2Fformat%2Fjpg&refer=http%3A%2F%2Fsafe-img.xhscdn.com&app=2002&size=f9999,10000&q=a80&n=0&g=0n&fmt=auto?sec=1722010576&t=91fc32e4ef19d32a5a0dbb6ac4665571\",\"jinji\":\"无\",\"name\":\"桂花山药羹\",\"params\":{},\"shicai\":\"冰糖适量。\",\"shiyongfangfa\":\"随时食用。\",\"yaocai\":\"山药150克，鲜桂花5克(干品1克)。\",\"zuofa\":\"　步骤1：将去皮洗净切成小丁的山药放入锅中，加水适量开始煮。\\r\\n　　步骤2：待山药煮至七八成熟时，放入桂花、冰糖，煮至山药糯软、汤汁浓稠，即可食用。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-27 00:16:33');
INSERT INTO `sys_oper_log` VALUES (232, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '114.104.217.230', 'XX XX', '{\"chandi\":\"仙人掌生于沿海沙滩的空旷处，向阳干燥的山坡、石上、路旁或村庄。分布于我国西南、华南以及浙江、福建、江西等地。\",\"gongxiao\":\"行气活血、凉血止血、解毒消肿。属清热药下属分类的清热解毒药。\",\"huaxuezucheng\":\"绿仙人掌生药浆分析含果胶多糖和胶渗出物。全草含无羁萜酮、无羁萜-3α-醇、蒲公英赛酮和蒲公英赛醇等成分。\",\"id\":18,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/131224/1-131224101A1I5.jpg\",\"jinji\":\"虚寒者忌用，《岭南杂记》：其汁入目，使人失明。\",\"linchuangzuoyong\":\"用量10～30克，煎服；或3～6克，焙干研末；或捣汁。仙人掌外用鲜品适量捣敷。主治胃痛、痞块、痢疾、喉痛、肺热咳嗽、肺痨咯血、吐血、痔血、疮疡、乳痈、痄腮、癣疾、蛇虫咬伤、烫伤和冻伤。\",\"name\":\"仙人掌\",\"otherName\":\"龙舌、火掌、仙巴掌、凤尾簕、平虑草、老鸦舌、神仙掌、观音掌、观音刺、霸王树、刺巴掌、番花、麒麟花、佛手刺、避火簪。\",\"params\":{},\"source\":\"仙人掌科植物仙人掌的地上部分或全株。\",\"xingtai\":\"多年生肉质植物，常丛生，灌木状。茎下部稍木质，近圆柱形，上部有分枝，具节；茎节扁平，倒卵形至长圆形，幼时鲜绿色，老时变蓝绿色，有时被白粉，其上散生小瘤体，每一瘤体上簇生数条针刺和多数倒生短刺毛，针刺黄色，杂以黄褐色斑纹。叶退化成钻状，早落。花单生或数朵聚生于茎节顶部边缘，鲜黄色；花被片多数，外部的带绿色，向内渐变为花瓣状，广倒卵形；雄蕊多数，排成数轮，花药2室；子房下位，1室，花柱粗壮，柱头白色。浆果多汁，倒卵形或梨形，紫红色。种子多数。花期5～6月。\",\"xingweiguijing\":\"性寒，味苦。归胃经、肺经、大肠经。\",\"xingzhuang\":\"仙人掌以全株入药(刺除外)。近基部老茎呈圆柱形，其余均呈掌状，扁平，每节呈倒卵形至椭圆形，每节长 6～25厘米或更长，直径 4～15厘米，厚 0.2～0.6厘米，表面灰绿色至黄棕色，具多数因削除小瘤体上的利刺和刺毛而残留的痕迹。质松脆，易折断，断面略呈粉性，灰绿色、黄绿色至黄棕色。气微，味酸。\",\"yaoliyanjiu\":\"仙人掌具降血糖、抗胃溃疡、抗炎、镇痛、抗应激、抑菌等作用。此外，还能延缓衰老。\",\"yaowupeifang\":\"1.治头痛：仙人掌去刺，剖成两爿，剖面撒食盐，合拢，湿草纸包，细铁线绑扡固定，火煨八成熟。将剖面贴额颞部，胶布固定，每次贴4小时，可连续使用。(《福建药物志》)\\r\\n2.治痔疮出血：仙人掌30克，炖牛肉250克，顿服。(《草木便方今释》)\\r\\n3.治颈淋巴结核：仙人掌茎剖开两爿，剖面撒上煅牡蛎粉，合紧烤热后，取含牡蛎粉剖面敷患处，胶布固定。(《福建药物志》)\\r\\n4.治小儿头上秃疮：仙人掌焙干为末，有汗干掺，无汗油调。(《普济方》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:19:33');
INSERT INTO `sys_oper_log` VALUES (233, '中药材', 2, 'com.ruoyi.web.controller.system.ChinesemedicineController.edit()', 'PUT', 1, 'admin', NULL, '/system/chinesemedicine', '114.104.217.230', 'XX XX', '{\"chandi\":\"生于低海拔到海拔3500米左右的山野草地及丛林边。分布于陕西及长江流域以南各地。\",\"gongxiao\":\"祛风除湿，散寒止痛，化痰止咳。属祛风湿药下分类的祛风湿散寒药。\",\"huaxuezucheng\":\"滇白珠叶含挥发油0.5%～0.8%。其中主要成分是水杨酸甲酯。根中含木脂素苷成分：白株木苷、C、D，(—)-异落叶松树脂醇-2a-O-β-D-吡喃木糖苷，(+)-南烛木树脂酚-2a-O-β-L-吡喃阿糖苷又名滇白珠苷A，(—)-5\'-甲氧基异落叶松树脂醇-2a-O-β-D-吡喃木糖苷，(+)-南烛木树脂酚-2a-O-β-D-吡喃葡萄糖苷，南烛木树脂酚，(—)-5\'-甲氧基异落叶松树脂醇。根中含二萜成分，三萜成分，黄酮成分，有机酸成分，甾体类，又含东莨菪素。\",\"id\":24,\"imageurl\":\"http://www.zhongyoo.com/uploads/allimg/1906/1-1Z619160519316.jpg\",\"jinji\":\"孕妇禁服。忌酸冷、鱼腥、荞面。\",\"linchuangzuoyong\":\"内服；煎汤，9～15克，鲜品30克；或浸酒。外用：煎水洗；或浸酒擦；或捣敷。主治风湿痹痛，胃寒疼痛，跌打损伤，咳嗽多痰。\",\"name\":\"透骨香\",\"otherName\":\"透骨草，满山香，搜山虎，煤炭子，煤炭果，万里香，九里香、芳香草、满天香，透骨消，小透骨草。\",\"params\":{},\"source\":\"为杜鹃花科白珠树属植物滇白珠Gaultheria yunnanenszs(Franch.)Rehd. 的全株或根。\",\"xingtai\":\"常绿灌木，高1～3米。树皮灰黑色，枝条细长，左右曲折，具纵纹，带红色或红绿色，无毛。单叶互生；叶柄短，粗壮；叶片革质，卵状长圆形，长卵形，有香气，长7～9厘米，宽2.5～3.5厘米，尾状渐尖，基部钝圆或心形，边缘具齿，表面绿色，有光泽，背面较淡，密被褐色斑点。总状花序腋生，有花10～15朵，疏生；苞片卵形，凸尖，被白色缘毛；小苞片2，对生或近对生，着生于花梗上部近萼处，披针状三角形；花萼裂片5，卵状三角形，钝头；花冠白绿色，钟形，口部分裂；雄蕊10枚，花丝短而粗，花药2室，每室先端具2芒；子房球形，被毛，短于花冠。浆果状蒴果，球形，黑色，5裂。种子多数，细小，淡黄色。花期5～6月，果期7～11月。\",\"xingweiguijing\":\"性温，味辛。归肾经，肺经，肝经。\",\"xingzhuang\":\"茎圆柱形，多分枝，表面淡红棕色至棕红色，有明显的纵纹，皮孔横生，突起。叶痕类圆形或类三角形，质硬脆，易折断，断面不整齐，木质部淡棕色至类白色，髓淡黄棕色。叶革质，多脱落，表面淡绿色至棕红色，先端尖尾状，基部心形，叶缘有细锯齿。有的可见花序或果序，总状，腋生，小花白色，蒴果球形，其外有紫黑色萼片，种子多而小，淡黄色。气香，味甘、辛。根弯曲有分枝，颇长，粗者直径可达2厘米，外表赤褐色，深色之栓皮极易剥落，内部色较淡；散生细根，粗约1毫米。质硬而脆，易折断；断面灰黄色，射线明显，木质致密。气芳香。\",\"yaoliyanjiu\":\"1.抗炎作用 ：透骨香中含有已知具有解热、抗风湿作用的水杨酸甲酯，水杨酸甲酯的药理实验证明，内服后有明显的抗炎作用。对巴豆油引起的小鼠耳郭肿胀抑制率为32.9%；小鼠腹腔毛细血管通透性试验，染料渗出抑制率为32.2%；此外，能减轻大鼠角叉菜胶足肿胀，致炎后30分钟及1小时作用明显，肿胀抑制率为41%。2.镇痛作用：对透骨香根茎的水提醇沉浸膏进行了镇痛药理研究，扭体法试验表明，透骨香浸膏镇痛百分率为58.8%；电刺激法，痛阈提高率为120.8%；热板法，痛阈提高率为54.4%。\",\"yaowupeifang\":\"①治风湿关节疼痛：透骨香根30克，小血藤15克，白龙须3克，牛膝15克。泡酒1000毫升。每服约30毫升，并用透骨香茎叶、生姜、葱煎水外洗。(《贵阳民间药草》)\\r\\n\\r\\n　　②治水臌：透骨香15克，车前草9克。水煎服。(《贵州草药》)\\r\\n\\r\\n　　③治跌打损伤：白珠树根30克，八棱麻18克。水、酒各半，煎服。(《草药手册》)\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:21:49');
INSERT INTO `sys_oper_log` VALUES (234, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '114.104.217.230', 'XX XX', '{\"gongxiao\":\"健脾固肾、补肺化痰。适用于痰饮喘咳、肺结核低热、慢性支气管炎、泄泻等症。\",\"imageurl\":\"https://st-cn.meishij.net/rs/150/151/14787900/n14787900_160482572569763.jpg\",\"jinji\":\"无\",\"name\":\"桂花山药羹\",\"params\":{},\"shicai\":\"冰糖适量。\",\"shiyongfangfa\":\"随时食用。\",\"yaocai\":\"山药150克，鲜桂花5克(干品1克)。\",\"zuofa\":\"　步骤1：将去皮洗净切成小丁的山药放入锅中，加水适量开始煮。\\r\\n　　步骤2：待山药煮至七八成熟时，放入桂花、冰糖，煮至山药糯软、汤汁浓稠，即可食用。\"}', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\r\n### The error may exist in URL [jar:file:/C:/Users/Administrator/Desktop/sjds/20240609/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.3.jar!/mapper/system/ZhonogyaoshipuMapper.xml]\r\n### The error may involve com.ruoyi.system.mapper.ZhonogyaoshipuMapper.updateZhonogyaoshipu-Inline\r\n### The error occurred while setting parameters\r\n### SQL: update zhonogyaoshipu          SET imageURL = ?,             yaocai = ?,             shicai = ?,             zuofa = ?,             gongxiao = ?,             shiyongfangfa = ?,             jinji = ?          where name = ?\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1\n; Data truncation: Data too long for column \'imageURL\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'imageURL\' at row 1', '2024-06-27 00:24:52');
INSERT INTO `sys_oper_log` VALUES (235, '中医好文', 1, 'com.ruoyi.web.controller.system.TcmArticleController.add()', 'POST', 1, 'admin', NULL, '/system/article', '61.190.13.218', 'XX XX', '{\"articleContent\":\"阴阳学说是在气一元论的基础上建立起来的中国古代的朴素的对立统一理论，属于中国古代唯物论和辩证法范畴，体现出中华民族辩证思维的特殊精神。其哲理玄奥，反映着宇宙的图式。其影响且远且大，成为人们行为义理的准则。如当今博得世界赞叹的《孙子兵法》是中国古代兵家理论和实战经验的总结，其将阴阳义理在军事行为中运用至极，已达到出神人化的境界。&lt;a href=http://zhongyi.lishichunqiu.com/ target=_blank class=infotextkey&gt;中医&lt;/a&gt;阴阳学说　　阴阳学说认为：世界是物质性的整体，宇宙间一切事物不仅其内部存在着阴阳的对立统一，而且其发生、发展和变化都是阴阳二气对立统一的结果。　　　　中医学把阴阳学说应用于医学，形成了中医学的阴阳学说，促进了中医学理论体系的形成和发展，中医学的阴阳学说是中医学理论体系的基础之一和重要组成部分，是理解和掌握中医学理论体系的一把钥匙。“明于阴阳，如惑之解，如醉之醒”（《灵枢·病传》），“设能明彻阴阳，则医理虽玄，思过半矣”（《景岳全书·传忠录·阴阳篇》）。　　　　中医学用阴阳学说阐明生命的起源和本质，人体的生理功能、病理变化，疾病的诊断和防治的根本规律，贯穿于中医的理、法、方、药，长期以来，一直有效地指导着实践。　　　　一、阴阳的基本概念　　　　（一）阴阳的含义　　　　1．阴阳的哲学含义：阴阳是中国古代哲学的基本范畴。气一物两体，分为阴阳。阴阳是气本身所具有的对立统一属性，含有对立统一的意思，所谓“阴阳者，一分为二也”（《类经·阴阳类》）。阴和阳之间有着既对立又统一的辩证关系。阴阳的对立统一是宇宙的总规律：阴阳不仅贯穿于中国古代哲学，而且与天文、历算、医学＼农学等具体学科相结合，—并成为各门具体学科的理论基础，促进了各门具体学科的发展。阴阳的对立、互根、消长和转化构成了阴阳的矛盾运动，成为阴阳学说的基本内容。　　　　阴阳与矛盾的区别：阴阳虽然含有对立统一的意思，但是它与唯物辩证法的矛盾范畴有着根本的区别。这种区别表现为：　　　　（1）阴阳范畴的局限性：唯物辩证法认为，一切事物内部所包含的对立都是矛盾。矛盾范畴，对于各对立面的性质，除了指出其对立统一外，不加任何其他限定。对立统一是宇宙中最普遍的现象。因此，矛盾范畴适用于一切领域，是事物和现象最抽象最一般的概括。而阴阳范畴不仅具有对立统一的属性，而且又有另外一些特殊的规定，属于一类具体的矛盾。阴阳是标志事物一定的趋向和性态特征的关系范畴。所以，阴阳尽管包罗万象，具有普遍性，但在无限的宇宙中，阴阳毕竟是一种有限的具体的矛盾形式，其内涵和外延比矛盾范围小很多，其适用范围有；定的限度，仅能对宇宙的事物和现象作一定程度的说明和概括，更不能用以说明社会现象。另外对于唯物辩证法来说，具体矛盾的双方，如有主有从，何者为主，何者为从，则视具体情况而定。但阴阳学说认为，在相互依存的阴阳矛盾中，一般情况下阳为主导而阴为从属，即阳主阴从。在人体内部阴阳之中，强调以阳为本，阳气既固，阴必从之。“凡阴阳之要，阳密乃固……阳强不能密，阴气乃绝”，“阳气者，若天与日，失其所则折寿而不彰，故天运当以日光明”（《素问·生气通天论》）。阳气是生命的主导，若失常不固，人就折寿夭亡。因此，在治疗疾病时，主张、“血气俱要，而补气在补血之先；阴阳并需，而养阳在滋阴乏上”（《医宗必读·水火阴阳论》）。总之，阴阳学说对矛盾双方的性态作了具体限定，一方属阴，一方属阳，阳为主，阴为从。一般说来，这种主从关系是固定的，这也表现出阴阳学说的特殊性和局限性。　　　　（2）阴阳范畴的直观性：唯物辩证法的矛盾范畴是建立在高度科学抽象的基础之上的，是宇宙的根本规律。而阴阳范畴，由于当时的科学发展水平的限制，使阴阳范畴还不可能超出直观的观察的广度和深度，不可能具有严格科学的表现形式，往往有一定的推测的成分。　　　　2．阴阳的医学含义　　　　阴阳范畴引入医学领域，成为中医学理论体系的基石，成为基本的医学概念。在中医学中，阴阳是自然界的根本规律，是标示事物内在本质属性和性态特征的范踌，既标示两种对立特定的属性，如明与暗、表与里、寒与热等等，又标示两种对立的特定的运动趋向或状态，如动与静、上与下、内与外、迟与数等等。　　　　总之，事物和现象相互对立方面的阴阳属性，是相比较而言的，是由其性质、位置、趋势等方面所决定的。阴阳是抽象的属性概念而不是具体事物的实体概念，也是一对关系范畴，它表示各种物质特性之间的对立统一关系。所以说：“阴阳者，有名而无形”（《灵枢·阴阳系日月》）。\",\"articleTitle\":\"中医学的阴阳学说\",\"articleType\":\"中医药\",\"createTime\":\"2024-06-27T0', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:33:29');
INSERT INTO `sys_oper_log` VALUES (236, '中医好文', 2, 'com.ruoyi.web.controller.system.TcmArticleController.edit()', 'PUT', 1, 'admin', NULL, '/system/article', '61.190.13.218', 'XX XX', '{\"articleContent\":\"\\t\\t阴阳学说是在气一元论的基础上建立起来的中国古代的朴素的对立统一理论，属于中国古代唯物论和辩证法范畴，体现出中华民族辩证思维的特殊精神。其哲理玄奥，反映着宇宙的图式。其影响且远且大，成为人们行为义理的准则。如当今博得世界赞叹的《孙子兵法》是中国古代兵家理论和实战经验的总结，其将阴阳义理在军事行为中运用至极，已达到出神人化的境界。\\t\\t阴阳学说认为：世界是物质性的整体，宇宙间一切事物不仅其内部存在着阴阳的对立统一，而且其发生、发展和变化都是阴阳二气对立统一的结果。　　　　中医学把阴阳学说应用于医学，形成了中医学的阴阳学说，促进了中医学理论体系的形成和发展，中医学的阴阳学说是中医学理论体系的基础之一和重要组成部分，是理解和掌握中医学理论体系的一把钥匙。“明于阴阳，如惑之解，如醉之醒”（《灵枢·病传》），“设能明彻阴阳，则医理虽玄，思过半矣”（《景岳全书·传忠录·阴阳篇》）。　　　　中医学用阴阳学说阐明生命的起源和本质，人体的生理功能、病理变化，疾病的诊断和防治的根本规律，贯穿于中医的理、法、方、药，长期以来，一直有效地指导着实践。&lt;img src=\\\"http://www.lishichunqiu.com/d/file/zhongyi/zyzs/zyll/5bce77f2abc819d67237a752b2aaaec6.jpg\\\" alt=\\\"<a href=\\\"http://zhongyi.lishichunqiu.com/\\\" target=\\\"_blank\\\">中医</a>阴阳学说\\\"&gt;　　　　一、阴阳的基本概念　　　　（一）阴阳的含义　　　　1．阴阳的哲学含义：阴阳是中国古代哲学的基本范畴。气一物两体，分为阴阳。阴阳是气本身所具有的对立统一属性，含有对立统一的意思，所谓“阴阳者，一分为二也”（《类经·阴阳类》）。阴和阳之间有着既对立又统一的辩证关系。阴阳的对立统一是宇宙的总规律：阴阳不仅贯穿于中国古代哲学，而且与天文、历算、医学＼农学等具体学科相结合，—并成为各门具体学科的理论基础，促进了各门具体学科的发展。阴阳的对立、互根、消长和转化构成了阴阳的矛盾运动，成为阴阳学说的基本内容。　　　　阴阳与矛盾的区别：阴阳虽然含有对立统一的意思，但是它与唯物辩证法的矛盾范畴有着根本的区别。这种区别表现为：　　　　（1）阴阳范畴的局限性：唯物辩证法认为，一切事物内部所包含的对立都是矛盾。矛盾范畴，对于各对立面的性质，除了指出其对立统一外，不加任何其他限定。对立统一是宇宙中最普遍的现象。因此，矛盾范畴适用于一切领域，是事物和现象最抽象最一般的概括。而阴阳范畴不仅具有对立统一的属性，而且又有另外一些特殊的规定，属于一类具体的矛盾。阴阳是标志事物一定的趋向和性态特征的关系范畴。所以，阴阳尽管包罗万象，具有普遍性，但在无限的宇宙中，阴阳毕竟是一种有限的具体的矛盾形式，其内涵和外延比矛盾范围小很多，其适用范围有；定的限度，仅能对宇宙的事物和现象作一定程度的说明和概括，更不能用以说明社会现象。另外对于唯物辩证法来说，具体矛盾的双方，如有主有从，何者为主，何者为从，则视具体情况而定。但阴阳学说认为，在相互依存的阴阳矛盾中，一般情况下阳为主导而阴为从属，即阳主阴从。在人体内部阴阳之中，强调以阳为本，阳气既固，阴必从之。“凡阴阳之要，阳密乃固……阳强不能密，阴气乃绝”，“阳气者，若天与日，失其所则折寿而不彰，故天运当以日光明”（《素问·生气通天论》）。阳气是生命的主导，若失常不固，人就折寿夭亡。因此，在治疗疾病时，主张、“血气俱要，而补气在补血之先；阴阳并需，而养阳在滋阴乏上”（《医宗必读·水火阴阳论》）。总之，阴阳学说对矛盾双方的性态作了具体限定，一方属阴，一方属阳，阳为主，阴为从。一般说来，这种主从关系是固定的，这也表现出阴阳学说的特殊性和局限性。　　　　（2）阴阳范畴的直观性：唯物辩证法的矛盾范畴是建立在高度科学抽象的基础之上的，是宇宙的根本规律。而阴阳范畴，由于当时的科学发展水平的限制，使阴阳范畴还不可能超出直观的观察的广度和深度，不可能具有严格科学的表现形式，往往有一定的推测的成分。　　　　2．阴阳的医学含义　　　　阴阳范畴引入医学领域，成为中医学理论体系的基石，成为基本的医学概念。在中医学中，阴阳是自然界的根本规律，是标示事物内在本质属性和性态特征的范踌，既标示两种对立特定的属性，如明与暗、表与里、寒与热等等，又标示两种对立的特定的运动趋向或状态，如动与静、上与下、内与外、迟与数等等。　　　　总之，事物和现象相互对立方面的阴阳属性，是相比较而言的，是由其性质、位置、趋势等方面所决定的。阴阳是抽象的属性概念而不是具体事物的实体概念，也是一对关系范畴，它表示各种物质特性之间的对立统一关系。', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:34:32');
INSERT INTO `sys_oper_log` VALUES (237, '中医好文', 2, 'com.ruoyi.web.controller.system.TcmArticleController.edit()', 'PUT', 1, 'admin', NULL, '/system/article', '61.190.13.218', 'XX XX', '{\"articleContent\":\"\\t\\t阴阳学说是在气一元论的基础上建立起来的中国古代的朴素的对立统一理论，属于中国古代唯物论和辩证法范畴，体现出中华民族辩证思维的特殊精神。其哲理玄奥，反映着宇宙的图式。其影响且远且大，成为人们行为义理的准则。如当今博得世界赞叹的《孙子兵法》是中国古代兵家理论和实战经验的总结，其将阴阳义理在军事行为中运用至极，已达到出神人化的境界。\\t\\t阴阳学说认为：世界是物质性的整体，宇宙间一切事物不仅其内部存在着阴阳的对立统一，而且其发生、发展和变化都是阴阳二气对立统一的结果。　　　　中医学把阴阳学说应用于医学，形成了中医学的阴阳学说，促进了中医学理论体系的形成和发展，中医学的阴阳学说是中医学理论体系的基础之一和重要组成部分，是理解和掌握中医学理论体系的一把钥匙。“明于阴阳，如惑之解，如醉之醒”（《灵枢·病传》），“设能明彻阴阳，则医理虽玄，思过半矣”（《景岳全书·传忠录·阴阳篇》）。　　　　中医学用阴阳学说阐明生命的起源和本质，人体的生理功能、病理变化，疾病的诊断和防治的根本规律，贯穿于中医的理、法、方、药，长期以来，一直有效地指导着实践。　　　　一、阴阳的基本概念　　　　（一）阴阳的含义　　　　1．阴阳的哲学含义：阴阳是中国古代哲学的基本范畴。气一物两体，分为阴阳。阴阳是气本身所具有的对立统一属性，含有对立统一的意思，所谓“阴阳者，一分为二也”（《类经·阴阳类》）。阴和阳之间有着既对立又统一的辩证关系。阴阳的对立统一是宇宙的总规律：阴阳不仅贯穿于中国古代哲学，而且与天文、历算、医学＼农学等具体学科相结合，—并成为各门具体学科的理论基础，促进了各门具体学科的发展。阴阳的对立、互根、消长和转化构成了阴阳的矛盾运动，成为阴阳学说的基本内容。　　　　阴阳与矛盾的区别：阴阳虽然含有对立统一的意思，但是它与唯物辩证法的矛盾范畴有着根本的区别。这种区别表现为：　　　　（1）阴阳范畴的局限性：唯物辩证法认为，一切事物内部所包含的对立都是矛盾。矛盾范畴，对于各对立面的性质，除了指出其对立统一外，不加任何其他限定。对立统一是宇宙中最普遍的现象。因此，矛盾范畴适用于一切领域，是事物和现象最抽象最一般的概括。而阴阳范畴不仅具有对立统一的属性，而且又有另外一些特殊的规定，属于一类具体的矛盾。阴阳是标志事物一定的趋向和性态特征的关系范畴。所以，阴阳尽管包罗万象，具有普遍性，但在无限的宇宙中，阴阳毕竟是一种有限的具体的矛盾形式，其内涵和外延比矛盾范围小很多，其适用范围有；定的限度，仅能对宇宙的事物和现象作一定程度的说明和概括，更不能用以说明社会现象。另外对于唯物辩证法来说，具体矛盾的双方，如有主有从，何者为主，何者为从，则视具体情况而定。但阴阳学说认为，在相互依存的阴阳矛盾中，一般情况下阳为主导而阴为从属，即阳主阴从。在人体内部阴阳之中，强调以阳为本，阳气既固，阴必从之。“凡阴阳之要，阳密乃固……阳强不能密，阴气乃绝”，“阳气者，若天与日，失其所则折寿而不彰，故天运当以日光明”（《素问·生气通天论》）。阳气是生命的主导，若失常不固，人就折寿夭亡。因此，在治疗疾病时，主张、“血气俱要，而补气在补血之先；阴阳并需，而养阳在滋阴乏上”（《医宗必读·水火阴阳论》）。总之，阴阳学说对矛盾双方的性态作了具体限定，一方属阴，一方属阳，阳为主，阴为从。一般说来，这种主从关系是固定的，这也表现出阴阳学说的特殊性和局限性。　　　　（2）阴阳范畴的直观性：唯物辩证法的矛盾范畴是建立在高度科学抽象的基础之上的，是宇宙的根本规律。而阴阳范畴，由于当时的科学发展水平的限制，使阴阳范畴还不可能超出直观的观察的广度和深度，不可能具有严格科学的表现形式，往往有一定的推测的成分。　　　　2．阴阳的医学含义　　　　\\t\\t阴阳范畴引入医学领域，成为中医学理论体系的基石，成为基本的医学概念。在中医学中，阴阳是自然界的根本规律，是标示事物内在本质属性和性态特征的范踌，既标示两种对立特定的属性，如明与暗、表与里、寒与热等等，又标示两种对立的特定的运动趋向或状态，如动与静、上与下、内与外、迟与数等等。　　　　\\t\\t总之，事物和现象相互对立方面的阴阳属性，是相比较而言的，是由其性质、位置、趋势等方面所决定的。阴阳是抽象的属性概念而不是具体事物的实体概念，也是一对关系范畴，它表示各种物质特性之间的对立统一关系。所以说：“阴阳者，有名而无形”（《灵枢·阴阳系日月》）。\",\"articleTitle\":\"中医学的阴阳学说\",\"articleType\":\"中医药\",\"createBy\":\"\",\"createTime\":\"2024-06-27 00:33:30\",\"id\":6,\"params\":{},\"updateBy\":\"\",\"updateTime\":\"2024-06-27T', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:40:04');
INSERT INTO `sys_oper_log` VALUES (238, '中医好文', 1, 'com.ruoyi.web.controller.system.TcmArticleController.add()', 'POST', 1, 'admin', NULL, '/system/article', '61.190.13.218', 'XX XX', '{\"articleContent\":\" 　　哲学是人们对于整个世界（自然、社会和思维）的根本观点和体系，即研究世界观的学问，是对自然知识和社会知识的概括和总结。科学是自然、社会和思维的知识体系。科学离不开理论思维，离不开世界观的指导。所以，哲学和科学之间存在着相互依赖、相互影响的密切关系。医学是研究人类生命过程以及同疾病作斗争的一门科学体系，属于自然科学范畴。自然科学与哲学的关系是特殊和普通的辩证关系。医学研究生命运动的特殊规律，而哲学则研究自然、社会和思维发展的普通规律。要探索生命的奥秘和健康与疾病的运动规律，医学就必须以先进的哲学思想为建构自己理论体系的世界观和方法论。中医学属于中国古代自然科学范畴，以中国古代朴素的唯物论和自发的辩证法思想即气一元论、阴阳学说和五行学说为哲学基础，来建构理论体系，并使之成为中医学理论体系的重要组成部分。　　　　气是中国古代哲学范畴系统中一个最重要的最基本的范畴，是中华民族独有的普遍的范畴。气一元论，又称元气论，对中国传统文化具有极其深刻的影响，成为中国古人认识世界的自然观。　　　　阴阳学说是在气一元论基础上建立起来的，是中国古代关于对立统一规律的认识，气是阴阳对立的统一体，物质世界在阴阳二气的相互作用下，不断地运动变化。　　　　五行学说是中国古代朴素的普通系统论，和阴阳学说一样，着眼于事物的矛盾作用，着眼于事物的运动和变化，从事物的结构关系及其行为方式，探索自然界物质运动动态平衡的中国古代哲学认为：气是天地万物统一的基础，是世界的本原。它以气为最高哲学范按着气——阴阳——五行的逻辑系统，揭示了世界万物包括生命的本质，阐明了世界运动变化。　　　　中医学继承和发展了中国古代哲学的气一元论、阴阳学说和五行学说，用以阐明人类生命活动和外界环境的关系，疾病发生、发展及其防治规律，以及增进健康、延年益寿和提高劳动能力的措施等，建立了中医学的气一元论、阴阳学说和五行学说。　　　　中医学是中国古代的一门比较系统的学科，在探索人体生命运动规律时，把当时先进的哲学理论和医学理论熔铸成为一个不可分割的整体，属于自然哲学形态。但中医学是在古代医学中远较古希腊古罗马医学理论完善且医术高超的自然哲学，它以气一元论、阴阳学说和五行学说为自己的哲学基础，运用综合思维方式分析和解决医学理论和医疗实践，体现出中国传统文化的特点。时至今日，还无法用分析手段使其脱离自然哲学而成为独立存在的实证医学。因此，要学习和研究中医学，就必须弄懂中医学中所包含的哲学内容。做到这一点，才能深刻理解中医学理论的本质和特点。\",\"articleTitle\":\"中医学的哲学基础\",\"articleType\":\"中医知识\",\"createTime\":\"2024-06-27T00:41:09.545+08:00\",\"id\":7,\"params\":{}}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:41:09');
INSERT INTO `sys_oper_log` VALUES (239, '中医好文', 2, 'com.ruoyi.web.controller.system.TcmArticleController.edit()', 'PUT', 1, 'admin', NULL, '/system/article', '61.190.13.218', 'XX XX', '{\"articleContent\":\"\\t\\t阴阳学说是在气一元论的基础上建立起来的中国古代的朴素的对立统一理论，属于中国古代唯物论和辩证法范畴，体现出中华民族辩证思维的特殊精神。其哲理玄奥，反映着宇宙的图式。其影响且远且大，成为人们行为义理的准则。如当今博得世界赞叹的《孙子兵法》是中国古代兵家理论和实战经验的总结，其将阴阳义理在军事行为中运用至极，已达到出神人化的境界。\\t\\t阴阳学说认为：世界是物质性的整体，宇宙间一切事物不仅其内部存在着阴阳的对立统一，而且其发生、发展和变化都是阴阳二气对立统一的结果。　　　　中医学把阴阳学说应用于医学，形成了中医学的阴阳学说，促进了中医学理论体系的形成和发展，中医学的阴阳学说是中医学理论体系的基础之一和重要组成部分，是理解和掌握中医学理论体系的一把钥匙。“明于阴阳，如惑之解，如醉之醒”（《灵枢·病传》），“设能明彻阴阳，则医理虽玄，思过半矣”（《景岳全书·传忠录·阴阳篇》）。　　　　中医学用阴阳学说阐明生命的起源和本质，人体的生理功能、病理变化，疾病的诊断和防治的根本规律，贯穿于中医的理、法、方、药，长期以来，一直有效地指导着实践。　　　　一、阴阳的基本概念　　　　（一）阴阳的含义　　　　1．阴阳的哲学含义：阴阳是中国古代哲学的基本范畴。气一物两体，分为阴阳。阴阳是气本身所具有的对立统一属性，含有对立统一的意思，所谓“阴阳者，一分为二也”（《类经·阴阳类》）。阴和阳之间有着既对立又统一的辩证关系。阴阳的对立统一是宇宙的总规律：阴阳不仅贯穿于中国古代哲学，而且与天文、历算、医学＼农学等具体学科相结合，—并成为各门具体学科的理论基础，促进了各门具体学科的发展。阴阳的对立、互根、消长和转化构成了阴阳的矛盾运动，成为阴阳学说的基本内容。　　　　阴阳与矛盾的区别：阴阳虽然含有对立统一的意思，但是它与唯物辩证法的矛盾范畴有着根本的区别。这种区别表现为：　　　　（1）阴阳范畴的局限性：唯物辩证法认为，一切事物内部所包含的对立都是矛盾。矛盾范畴，对于各对立面的性质，除了指出其对立统一外，不加任何其他限定。对立统一是宇宙中最普遍的现象。因此，矛盾范畴适用于一切领域，是事物和现象最抽象最一般的概括。而阴阳范畴不仅具有对立统一的属性，而且又有另外一些特殊的规定，属于一类具体的矛盾。阴阳是标志事物一定的趋向和性态特征的关系范畴。所以，阴阳尽管包罗万象，具有普遍性，但在无限的宇宙中，阴阳毕竟是一种有限的具体的矛盾形式，其内涵和外延比矛盾范围小很多，其适用范围有；定的限度，仅能对宇宙的事物和现象作一定程度的说明和概括，更不能用以说明社会现象。另外对于唯物辩证法来说，具体矛盾的双方，如有主有从，何者为主，何者为从，则视具体情况而定。但阴阳学说认为，在相互依存的阴阳矛盾中，一般情况下阳为主导而阴为从属，即阳主阴从。在人体内部阴阳之中，强调以阳为本，阳气既固，阴必从之。“凡阴阳之要，阳密乃固……阳强不能密，阴气乃绝”，“阳气者，若天与日，失其所则折寿而不彰，故天运当以日光明”（《素问·生气通天论》）。阳气是生命的主导，若失常不固，人就折寿夭亡。因此，在治疗疾病时，主张、“血气俱要，而补气在补血之先；阴阳并需，而养阳在滋阴乏上”（《医宗必读·水火阴阳论》）。总之，阴阳学说对矛盾双方的性态作了具体限定，一方属阴，一方属阳，阳为主，阴为从。一般说来，这种主从关系是固定的，这也表现出阴阳学说的特殊性和局限性。　　　　（2）阴阳范畴的直观性：唯物辩证法的矛盾范畴是建立在高度科学抽象的基础之上的，是宇宙的根本规律。而阴阳范畴，由于当时的科学发展水平的限制，使阴阳范畴还不可能超出直观的观察的广度和深度，不可能具有严格科学的表现形式，往往有一定的推测的成分。　　　　2．阴阳的医学含义　　　　\\t\\t阴阳范畴引入医学领域，成为中医学理论体系的基石，成为基本的医学概念。在中医学中，阴阳是自然界的根本规律，是标示事物内在本质属性和性态特征的范踌，既标示两种对立特定的属性，如明与暗、表与里、寒与热等等，又标示两种对立的特定的运动趋向或状态，如动与静、上与下、内与外、迟与数等等。　　　　\\t\\t总之，事物和现象相互对立方面的阴阳属性，是相比较而言的，是由其性质、位置、趋势等方面所决定的。阴阳是抽象的属性概念而不是具体事物的实体概念，也是一对关系范畴，它表示各种物质特性之间的对立统一关系。所以说：“阴阳者，有名而无形”（《灵枢·阴阳系日月》）。\",\"articleTitle\":\"中医学的阴阳学说\",\"articleType\":\"中医知识\",\"createBy\":\"\",\"createTime\":\"2024-06-27 00:33:30\",\"id\":6,\"params\":{},\"updateBy\":\"\",\"updateTime\":\"2024-06-27', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:41:32');
INSERT INTO `sys_oper_log` VALUES (240, '中医好文', 2, 'com.ruoyi.web.controller.system.TcmArticleController.edit()', 'PUT', 1, 'admin', NULL, '/system/article', '61.190.13.218', 'XX XX', '{\"articleContent\":\" \\t\\t哲学是人们对于整个世界（自然、社会和思维）的根本观点和体系，即研究世界观的学问，是对自然知识和社会知识的概括和总结。科学是自然、社会和思维的知识体系。科学离不开理论思维，离不开世界观的指导。所以，哲学和科学之间存在着相互依赖、相互影响的密切关系。医学是研究人类生命过程以及同疾病作斗争的一门科学体系，属于自然科学范畴。自然科学与哲学的关系是特殊和普通的辩证关系。医学研究生命运动的特殊规律，而哲学则研究自然、社会和思维发展的普通规律。要探索生命的奥秘和健康与疾病的运动规律，医学就必须以先进的哲学思想为建构自己理论体系的世界观和方法论。中医学属于中国古代自然科学范畴，以中国古代朴素的唯物论和自发的辩证法思想即气一元论、阴阳学说和五行学说为哲学基础，来建构理论体系，并使之成为中医学理论体系的重要组成部分。　　　　气是中国古代哲学范畴系统中一个最重要的最基本的范畴，是中华民族独有的普遍的范畴。气一元论，又称元气论，对中国传统文化具有极其深刻的影响，成为中国古人认识世界的自然观。　　　　\\t\\t阴阳学说是在气一元论基础上建立起来的，是中国古代关于对立统一规律的认识，气是阴阳对立的统一体，物质世界在阴阳二气的相互作用下，不断地运动变化。　　　　五行学说是中国古代朴素的普通系统论，和阴阳学说一样，着眼于事物的矛盾作用，着眼于事物的运动和变化，从事物的结构关系及其行为方式，探索自然界物质运动动态平衡的中国古代哲学认为：气是天地万物统一的基础，是世界的本原。它以气为最高哲学范按着气——阴阳——五行的逻辑系统，揭示了世界万物包括生命的本质，阐明了世界运动变化。　　　　\\t\\t中医学继承和发展了中国古代哲学的气一元论、阴阳学说和五行学说，用以阐明人类生命活动和外界环境的关系，疾病发生、发展及其防治规律，以及增进健康、延年益寿和提高劳动能力的措施等，建立了中医学的气一元论、阴阳学说和五行学说。　　　　\\t\\t中医学是中国古代的一门比较系统的学科，在探索人体生命运动规律时，把当时先进的哲学理论和医学理论熔铸成为一个不可分割的整体，属于自然哲学形态。但中医学是在古代医学中远较古希腊古罗马医学理论完善且医术高超的自然哲学，它以气一元论、阴阳学说和五行学说为自己的哲学基础，运用综合思维方式分析和解决医学理论和医疗实践，体现出中国传统文化的特点。时至今日，还无法用分析手段使其脱离自然哲学而成为独立存在的实证医学。因此，要学习和研究中医学，就必须弄懂中医学中所包含的哲学内容。做到这一点，才能深刻理解中医学理论的本质和特点。\",\"articleTitle\":\"中医学的哲学基础\",\"articleType\":\"中医知识\",\"createBy\":\"\",\"createTime\":\"2024-06-27 00:41:10\",\"id\":7,\"params\":{},\"updateBy\":\"\",\"updateTime\":\"2024-06-27T00:41:54.219+08:00\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:41:54');
INSERT INTO `sys_oper_log` VALUES (241, '中医好文', 1, 'com.ruoyi.web.controller.system.TcmArticleController.add()', 'POST', 1, 'admin', NULL, '/system/article', '61.190.13.218', 'XX XX', '{\"articleContent\":\" 　　一、气、阴阳、五行的关系　　　　气、阴阳、五行都是中国传统哲学的重要范畴。气在与阴阳、五行的纵横联结中，构成厂气——阴阳——五行的逻辑结构系统，形成了中国传统哲学自身的特点。　　　　（一）气与阴阳　　　　气是物质实体，是构成宇宙天体以及天地万物的最基本元素，是世界的本原。气范畴肯定了物质世界的统一性。阴阳是气的两种固有属性。按阴阳分，则世界上的气可分为阴气和阳气两类。阴阳又是气本身内在的矛盾要素。阴气和阳气又各具阴阳对立要素，相互渗透，相互作用，构成了气的矛盾统一体。一气分为阴阳，阴阳统一于气。“气有阴阳”（《正蒙·神化》），“一物两体，气也”（《正蒙·参两》），“气有阴阳，屈伸相感之无穷，故神之应也无穷”（《正蒙·乾称》）。气是一，万物本原为一气，但一气分阴阳，气有阴阳为两，两存在于一之中，表现为对立的两个方面，“一”指对立双方的统一。作为宇宙本原的气是阴阳对立的统一物，物质世界在阴阳二气的相互作用下，不断地运动变化。“两不立则一不可见，一不可见则两之用息。两体者，虚实也，动静也，聚散也，清浊也，其究一而已”（《横渠易说·说卦》）。虚实、动静、聚散、清浊等是对立两方面的具体表现，也是一气之阴阳的具体内涵。这种阴阳对立的双方，共同组成气的统一体，它们是一切运动变化的根源，从而建立起对立统一的气一元的物质概念。　　　　（二）气与五行　　　　气是世界的本原，“天地间一气耳。气之清而强者为火，清而弱者为水；浊而沉者为土，浊而浮者为木，浊而实者为金，皆一气之清浊而流派为五也。一气分五行，而五行又各有五行’’，“五可还一，一可摄五，譬之一树……各不同形，实总一根菱”（《百子全书·叔苴子内篇·卷一》）。五行同一气，一气合五行。《云笈七笺》吸收了阴阳五行思想，根据“元气本一，化生有万”的理论，阐述了气与五行的关系，谓：“一含五气，为水、为火、为木、为金、为土”，“元气分而为五行，五行归于一气”。《白虎通·卷二》曰：“五行者……金木水火土也。言行者，欲言为天行气之义也”，意即金木水火土五种物质元素是由气的运动变化而成的。如是，将五行多元物质结构概念统一于气一元论的单一的物质概念之中。　　　　（三）阴阳与五行　　　　中国古代哲学认为：“天降阳，地出阴，阴阳合而生五行”（《李觏《删定易图序论一》》。即五行本原于阴阳之气，阴阳二气相互作用而产生五行。“阴变阳合而生水、火、木、金、土。五气顺布，四时行焉”，“五行一阴阳也，阴阳一太极也，太极本无极也。五行之生也，各一其性”（《御纂性理精义·卷一》）。“阴阳之为五行，有分而言之者，如木火阳而金水阴也；有合而言之者，如木之甲，火之丙，土之戊，金之庚，水之壬皆阳，而乙丁己辛癸皆阴也。以此推之健顺，五常之理可见”（《御纂情理精义·卷十》）。即太极生阴阳，阴阳化五行。就五行之阴阳言，木火属阳而金水土属阴，而五行之中又各具阴阳，木之甲、火之丙、土之戊、金之庚、水之壬为阳，而木之乙、火之丁、土之己、金之辛、水之癸为阴。　　　　世界本原一气，气之动静而为阴阳，气为阴阳之体，阴阳为气之用。阴阳合和化生五行。所谓“有太极则一动一静而两仪分，有阴阳则一变一合而五行具”（《御纂性理精义·卷一》）。总之，“本是一气，分而言之曰阴阳，又就阴阳中细分之则为五行。五气即二气，二气即一气”（吴澄《吴文正公集·答人问性理》）。一气分阴阳，阴阳生五行，阴阳五行均为气之消息变化。　　　　二、气一元论、阴阳学说、五行学说的关系　　　　气、阴阳和五行，均为中国古代唯物主义哲学关于世界的物质构成的哲学范畴，属于世界本原的物质概念。气一元论、阴阳学说和五行学说，是中国朴素的唯物论和辩证法，是中国传统文化认识世界的根本观点和方法，体现了中华民族特有的智慧和才能。　　　　气一元论、阴阳五行学说渗透到医学领域后，促进了中医学理论体系的形成和发展，并贯彻中医学理论体系的各个方面。其中，气一元论作为一种自然观，奠定了中医学理论体系的基石，如果说中医学理论体系的全部学说都是建立在气一元论基础之上的，也并不为过。而阴阳学说和五行学说作为方法论，则构筑了中医学理论体系的基本框架。气一元论、阴阳学说和五行学说，既各有所指和特点，又相互关联。　　　　（一）气一元论　　　　气一元论认为，气是不断地运动着的物质实体，是世界万事万物的本原（或本体），为宇宙天体和天地万物统一的物质基础。运动是气的根本特性，阴阳是气的固有属性，气是阴阳的矛盾统一体，气的胜复作用即阴阳的矛盾运动是物质世界运动变化的根源，气聚而成形，散而为气，形（有形）与气（无形）及其相互转化是物质世界存在和运动的基本形式。物质世界是一个不断地发生着气的升降出入的气化运动的世界。气分而为阴阳，阴阳合而生五行，而五行之中复有阴阳。就世界的本原而言，作为一种自然观，气一元论', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:43:24');
INSERT INTO `sys_oper_log` VALUES (242, '中医好文', 1, 'com.ruoyi.web.controller.system.TcmArticleController.add()', 'POST', 1, 'admin', NULL, '/system/article', '61.190.13.218', 'XX XX', '{\"articleContent\":\" 　　伤寒学派：创立于东汉之际。汉代医家张仲景将理论与方药熔于一炉，著《伤寒杂病论》，奠定了中医学辨证论治的基础，专门探讨伤寒杂病的诊疗规律。其书被奉为经典，其人被尊为医圣。从晋唐至宋元明清，研究者如云，历代不衰，各展所长，形成了时间最长，医家众多，影响最大，学术昌盛的伤寒学派。　　　　寒凉学派：又称河间派，金元大家刘完素主攻火热病机，提出“六气皆从火化”之说，创“火热论”，疗疾多用寒凉药物。他不仅对中医病机理论的提高有很大贡献，并对后世创立温病学说大有启迪。因刘氏家住河间，又称河间学派。　　　　易水学派：金代医家张元素，河北易水人，在《内经》、《中藏经》的启示下，以脏腑标本虚实寒热的论点来分析疾病的发生与演变，归纳用药，执简驭繁，创立了“脏腑病机学说”，对后世医家颇有影响。　　　　攻邪学派：金元大家张从正，强调“病由邪生，攻邪已（治愈）病”，主张治疗应以驱邪主，善用吐汗下三法，偏重攻法，反对滥用补法。从一个侧面深化了中医治则理论，并丰富了临床经验。　　　　补土学派：又称温补学派，金元大家李杲认为“人以胃气为本”，独重后天脾胃，创立“脾胃论”，长于温补之法。　　　　滋阴学派：金元大家朱丹溪受到刘完素“火热论”的影响，又接受李杲“内伤论”的观点，提出“阳常有余，阴常不足”的新论，治病多用滋阴降火之法。　　　　温补学派：明代薛已、张介宾、赵献可、孙一奎、李中梓诸医家重视命门水火的研究。探讨脏腑病机逐渐侧重于虚损病证，形成了善用温补的特点。充实发展了命门学说，使中医理论有所突破。　　　　温病学派：明代末年，温疫流行，用伤寒治法无效，以明代吴又可为开创，清代叶天士、吴瑭为中坚，对外感热病的治疗规律进行了大胆探索，提出了温疫病机和温病学说，取得了很大的成就。　　　　这七大医学流派，成为祖国医学发展进程中的主要链条与脉络，清晰地向我们展示了中医发展、演变、日臻完善的轨迹。至于历史上的众多医家，其中包括那些名垂青史的历代名医，技艺高超，著述颇丰，但未有明显的学派倾向，亦不失为医界星空的一颗颗璀璨明星。　　　　中医流派是历史的产物，是宝贵的遗产，值得我们医界后人万分珍视。半个多世纪以来，学院教育以规范化、标准化的模式，基本上取代了沿袭数千年的师徒授受，而成为培养当代中医人才的主要途径，数以万计的学院派，成了中医界的主力军，这是中医事业和教育的一大飞跃。但是中医最重要的还是要靠临床实践与经验的积累，要靠医生的医疗水平与能力。因此，在培养共性的同时，要更注重培养和发展医者的个性。对不同流派的继承和实践，是造就特色中医的重要方式，也是繁荣中医学术，倡导百家争鸣，丰富中医内涵，呈现中医生机的有力保障。\",\"articleTitle\":\"中医发展中的七大流派\",\"articleType\":\"中医知识\",\"createTime\":\"2024-06-27T00:44:09.028+08:00\",\"id\":9,\"params\":{}}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:44:09');
INSERT INTO `sys_oper_log` VALUES (243, '中医好文', 1, 'com.ruoyi.web.controller.system.TcmArticleController.add()', 'POST', 1, 'admin', NULL, '/system/article', '61.190.13.218', 'XX XX', '{\"articleContent\":\" 　　中医认为，正常的出汗，可以调节体温，排除体内的废物，调节人体阴阳的平衡。而当人体阴阳失衡、脏腑功能失调时则会出现异常的出汗，所以，中医常常根据出汗的时间、部位、多少和特点来判断身体的状况。　　　　首先要排除是否疾病所致。一般情况下，糖尿病、甲亢、高血压、充血性心衰、偏瘫脊柱外伤、肿瘤、结核等都会导致异常出汗，并伴随明显的相应症状。这种情况下，必须及时控制病情，而后多汗情况就能解决。当然，更多的情况是没有明显疾病症状的异常出汗，概括起来有以下几种。　　　　按出汗时间分：一种是白天出汗过多。无论冬夏，在白天不活动或轻微活动的情况下，常汗出不止。这些人常有身体虚弱、说话语声较低、食欲差、易感冒等特点，中医认为是气虚的表现。这类人饮食上可选择山药、豆浆、牛羊肉等，也可用党参或黄芪炖鸡或腔骨，以补益机体，缓解气虚。还可通过动作舒缓、动静结合的运动增强体质，如练习太极拳、八段锦等。　　　　另一种是晚上出汗。睡着出汗，醒来汗止，中医称为\\\"盗汗\\\"。这些人常有手脚心热、心烦、面部发红发热、口咽干燥等特点，中医认为是阴虚表现。这类人饮食上可选择百合、雪梨等滋阴之品，少吃羊肉、洋葱、葱、姜、蒜等热性食物，也可用沙参、麦冬、五味子或西洋参等泡水饮用。　　　　按出汗部位分：一为头汗过多，若暴饮暴食后出现头面部多汗，同时觉得上腹胀满、口渴、不想吃饭，多为积食，可通过减少进食量、吃清淡饮食缓解，也可吃点消化药;若伴随肢体沉重无力，胃胀不适，想呕吐，身体发热，舌苔厚而黄腻，是脾胃有湿热的表现，应注意清淡饮食。孩子睡眠时出现轻微头汗属正常现象;但若伴有睡眠不实、烦躁不安、易惊吓、头发稀少等表现，要及时诊治。此外，老人和产后身体虚弱的女性，也会有头汗过多的情况，多属于气虚。　　　　二为手足心多汗，如果手足心多汗伴有手脚心热、口咽干燥等，多属于阴虚有热;若手足心多汗伴随腹部胀满疼痛，大便不通，多属于肠道内有积粪的热证，可服用通便药;若有手足心多汗伴随口干、牙龈肿痛等，多属于胃热，可服用清胃热的中药，如牛黄清胃丸、清胃黄连丸等。　　　　三为心窝、胸口多汗，多见于一些脑力工作者，这些人常伴有精神倦怠、食欲不振、睡眠差，多梦的表现，属于思虑过度，导致心脾虚，可通过适当的运动，如慢跑、太极拳、八段锦等，缓解压力，调节心身。　　　　按气味辨别：正常的汗没有明显的腥臭味，如果汗味腥臭，多与热证或湿热证有关，属肝热，这种情况可通过清淡饮食，或用中药菊花、茵陈等泡水饮用;若腥臭明显，应找大夫诊治。此外，若在夏季闷热的环境中，出现大量出汗、口渴、头昏、胸闷、恶心、心慌、四肢无力、耳鸣、注意力不集中，体温升高的情况，一般属于中暑先兆，应及时转移到阴凉通风的地方，补充一些淡盐水，短时间内可恢复正常，症状不能恢复或严重者，要及时就医。　　　　除上述情况，还有一些出汗表现，如汗液颜色的改变，有黄汗、红汗、黑汗等，这种情况需由医生综合判断后诊治。如果重病的病人突然大汗淋漓、四肢厥冷、呼吸微弱或大汗、呼吸急促等，则预示着病情的凶险。　　　　总之，一旦异常出汗的情况严重或伴随其他严重表现，应及时就诊。\",\"articleTitle\":\"中医“辨汗”识病\",\"articleType\":\"诊断\",\"createTime\":\"2024-06-27T00:46:32.899+08:00\",\"id\":10,\"params\":{}}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 00:46:32');
INSERT INTO `sys_oper_log` VALUES (244, '中医药视频', 1, 'com.ruoyi.web.controller.system.TcmVideoController.add()', 'POST', 1, 'admin', NULL, '/system/video', '127.0.0.1', '内网IP', '{\"category\":\"123\",\"count\":123,\"coverImage\":\"/profile/upload/2024/06/27/bj_20240627092256A002.png\",\"createTime\":\"2024-06-27T09:22:58.106+08:00\",\"id\":7,\"introduce\":\"123\",\"name\":\"123\",\"params\":{},\"path\":\"/profile/upload/2024/06/27/案例演示_20240627092235A001.mp4\",\"remark\":\"123\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 09:22:58');
INSERT INTO `sys_oper_log` VALUES (245, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '36.60.90.92', 'XX XX', '{\"gongxiao\":\"健脾养胃、促进消化。适用于肠胃虚寒所致的腹部冷痛、呕吐或拉肚子等症。也可用于孕妇的早孕反应。\",\"imageurl\":\"https://ts2.cn.mm.bing.net/th?id=OSK.7c80640c7d9e3012d50ae54281c729a7&w=300&h=200&c=7&rs=1&qlt=80&o=6&cdv=1&dpr=1.5&pid=16.1\",\"jinji\":\"无\",\"name\":\"丁香炖鸡腿\",\"params\":{},\"shicai\":\"鸡腿2只，生姜3克，盐3克。\",\"shiyongfangfa\":\"佐餐食用，吃肉喝汤。\",\"yaocai\":\"丁香、陈皮各8克，党参、白术各10克。\",\"zuofa\":\"步骤1：以上药材、鸡腿分别洗净；陈皮清水泡发，鸡腿沸水汆烫备用。\\r\\n　　步骤2：药材放入砂锅，再放上鸡腿，加水盖过，放入姜片，保鲜膜密封，上锅隔水炖2小时，启封后放盐调味即可。\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 09:44:55');
INSERT INTO `sys_oper_log` VALUES (246, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '36.60.90.92', 'XX XX', '{\"gongxiao\":\"暖肾助阳、益精补髓。适用于虚损劳伤、肾阳虚衰所致的阳痿不举、早泄、身体衰弱等症。\",\"imageurl\":\"https://pic.baike.soso.com/ugc/baikepic2/7279/20220420193625-699343303_jpeg_375_300_30393.jpg/0\",\"jinji\":\"无\",\"name\":\"三物壮阳汤\",\"params\":{},\"shicai\":\"牛鞭80克，狗肾8克，羊肉80克，肥母鸡肉40克，花椒2克，老生姜、葱白各5克，绍酒15毫升，味精2克，盐5克，植物油10毫升。\",\"shiyongfangfa\":\"佐餐或单独食用。牛鞭狗鞭汤食材灵芝、枸杞各8克，肉苁蓉5克。\",\"yaocai\":\"枸杞、菟丝子8克，肉苁蓉5克。\",\"zuofa\":\"　步骤1：牛鞭入热水泡胀，剖开，刮洗干净，冷水浸泡30分钟，切段；狗肾油砂爆炒，温水浸泡40分钟，刷洗干净；羊肉洗净，沸水汆烫，凉水漂洗；菟丝子、肉苁蓉、枸杞洗净，装入纱布袋内，扎紧袋口。\\r\\n　　步骤2：砂锅内加水，放入牛鞭、狗肾和羊肉置于锅内，煮沸，撇去浮沫，加母鸡肉和花椒、老生姜、葱白、绍酒，大火煮沸，小火炖煮，隔30分钟翻动一次。至六成熟时，滤去花椒、生姜、葱白，放入药袋，继续煮沸，以牛鞭、狗肾酥烂为度。\\r\\n　　步骤3：捞去母鸡肉和药袋，加味精、盐和植物油调味。\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 09:45:20');
INSERT INTO `sys_oper_log` VALUES (247, '中药食谱', 2, 'com.ruoyi.web.controller.system.ZhonogyaoshipuController.edit()', 'PUT', 1, 'admin', NULL, '/system/zhonogyaoshipu', '36.60.90.92', 'XX XX', '{\"gongxiao\":\"健脾养心，益气补血。适宜气血双亏、心脾两虚者食用。\",\"imageurl\":\"https://ts3.cn.mm.bing.net/th?id=OSK.4bed88f9494d01f21746d49f75c0e59d&w=328&h=440&c=7&rs=1&qlt=80&o=6&cdv=1&dpr=1.5&pid=16.1\",\"jinji\":\"无\",\"name\":\"健脾麦片粥\",\"params\":{},\"shicai\":\"麦片60克。佳圆肉20克，红枣5枚。\",\"shiyongfangfa\":\"宜早、晚空腹食用。\",\"yaocai\":\"党参、黄芪各10克，当归、酸枣仁、甘草各8克，丹参8克，桂枝3克。\",\"zuofa\":\"步骤1：所有药材清水洗净，放入纱布袋中，扎口；红枣泡透，去核，洗净；桂圆肉洗净。\\r\\n　　步骤2：砂锅量小火上，入水适量，放入纱布袋煎煮1小时，捞去药袋，下入麦片、桂圆肉、红枣，大火煮沸后转小火熬煮至粥黏稠，即可食用。\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2024-06-27 09:45:51');
