INSERT INTO `sys_oper_log` VALUES (276, '实验案例库', 1, 'com.ruoyi.web.controller.system.TcmCaseController.add()', 'POST', 1, 'admin', NULL, '/system/case', '127.0.0.1', '内网IP', '{\"caseName\":\"破伤风\",\"caseNo\":\"tcm_case_1\",\"caseRemark\":\"<strong>1.基本信息​</strong><strong>姓名</strong>：张某​<strong>年龄</strong>：32 岁​<strong>职业</strong>：农民​<strong>2.病症表现</strong><strong>受伤经过</strong>：一周前，张某在田间劳作时，右脚不慎被生锈铁钉扎伤。伤口较深，致使铁锈、泥土等污染物被带入伤口深处。受伤后，他仅用清水简单擦拭，既未进行规范的清创处理，也未注射破伤风抗毒素或免疫球蛋白。​<strong>3.症状发展​</strong><strong>初期症状</strong>：三天前，张某开始出现张口不便的症状，咀嚼食物时感到费力，吞咽也出现困难。但这些早期症状未引起他的重视，并未及时就医。​<strong>进展症状</strong>：此后，病情迅速恶化，全身肌肉开始出现阵发性痉挛。起初，痉挛间隔时间较长，随着时间推移，发作愈发频繁，程度也愈发剧烈，严重干扰到日常生活，张某这才前往医院就诊。\",\"id\":1,\"params\":{},\"picture\":\"/profile/upload/2025/03/26/33_20250326151002A001.jpg\",\"results\":\"综合患者受伤病史，以及望闻问切收集的症状和体征，诊断为风毒入络证。受伤后，风毒之邪从伤口乘虚侵入人体，风性善行而数变，毒邪随经络传至全身，导致经络气血痹阻，筋脉失养，从而引发肌肉痉挛等一系列症状\",\"treatmentMethods\":\"<strong>内治法</strong>：以熄风镇痉、解毒通络为核心治疗原则，选用玉真散合五虎追风散加减。​<strong>玉真散</strong>：方中白附子、天南星性辛温，具有祛风化痰、解痉止痛的功效，可驱散经络中的风痰之邪，缓解肌肉痉挛。​<strong>五虎追风散</strong>：全蝎、蜈蚣、僵蚕均为虫类药，善于搜风通络，熄风止痉，能有效缓解抽搐症状。蝉蜕可疏散风热，透疹止痒，且具有一定的熄风作用。朱砂重镇安神，可缓解患者烦躁不安的症状。​<strong>清热解毒药物</strong>：金银花、连翘、蒲公英等清热解毒之品，能够清除伤口部位的毒邪，控制感染的蔓延。​<strong>外治法</strong>：​<strong>清创处理</strong>：对伤口进行彻底清创，在局部麻醉下，清除伤口内的坏死组织、异物和脓性分泌物，使伤口充分暴露。然后用 3％过氧化氢溶液反复冲洗伤口，利用其分解产生的氧气，营造不利于破伤风杆菌生长的厌氧环境。​<strong>外敷药物</strong>：清创后，外敷如意金黄散。该方由大黄、黄柏、姜黄、白芷等药物组成，具有清热解毒、消肿止痛的功效，可促进伤口炎症的消退，减轻红肿疼痛症状。​<strong>其他疗法</strong>：​<strong>中西医结合支持治疗</strong>：对于病情严重的患者，需配合西医的支持治疗。保持呼吸道通畅，必要时行气管切开术，防止因痉挛导致窒息。使用镇静药物控制痉挛发作，减少患者的痛苦。同时，给予营养支持，维持水、电解质平衡，预防并发症的发生。​<strong>针灸治疗</strong>：根据患者的恢复情况，配合针灸治疗。选取风池、合谷、内关、阳陵泉等穴位。风池穴为足少阳胆经与阳维脉的交会穴，可疏散风邪，清利头目；合谷为手阳明大肠经的原穴，能疏风解表，通络止痛；内关为手厥阴心包经的络穴，可宁心安神，理气止痛；阳陵泉为足少阳胆经的合穴，也是八会穴之一的筋会，可舒筋活络，缓解肌肉痉挛。通过针刺这些穴位，疏通经络、调和气血，促进患者康复。\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-03-26 15:11:24');
